import React from 'react';
import { Card, Stack, Text } from '@ggui-ai/design/primitives';

interface Props {
  /** City name */
  city: string;
  /** Current temperature */
  temperature: number;
  /** Weather condition (Sunny, Cloudy, Rainy, etc.) */
  condition: string;
  /** Humidity percentage */
  humidity: number;
  /** Wind speed */
  windSpeed: number;
  /** Temperature unit (C or F) */
  unit?: string;
  /** 5-day forecast array */
  forecast: Array<{ day?: string; icon?: string; high?: number; low?: number }>;
}

export default function GeneratedComponent({
  city = 'City',
  temperature = 0,
  condition = 'Unknown',
  humidity = 0,
  windSpeed = 0,
  unit = 'C',
  forecast = [],
}: Props) {
  return (
    <Card
      padding="var(--ggui-spacing-6, 24px)"
      shadow="md"
      radius="lg"
      border
    >
      <Stack gap="var(--ggui-spacing-6, 24px)">
        <Stack gap="var(--ggui-spacing-2, 8px)">
          <Text
            variant="overline"
            color="var(--ggui-color-onSurfaceVariant, #52525b)"
            as="div"
          >
            {city}
          </Text>

          <Stack direction="horizontal" align="center" justify="between">
            <Text
              size="4xl"
              weight="bold"
              color="var(--ggui-color-onSurface, #18181b)"
              as="div"
              aria-label={`Current temperature ${temperature} degrees ${unit}`}
            >
              {temperature}°{unit}
            </Text>
            <Text
              size="xl"
              weight="medium"
              color="var(--ggui-color-onSurfaceVariant, #52525b)"
              as="div"
              aria-label={`Weather condition ${condition}`}
            >
              {condition}
            </Text>
          </Stack>

          <Stack direction="horizontal" gap="var(--ggui-spacing-4, 16px)" wrap>
            <Text
              variant="label"
              color="var(--ggui-color-onSurfaceVariant, #52525b)"
              as="div"
              aria-label={`Humidity ${humidity} percent`}
            >
              Humidity: {humidity}%
            </Text>
            <Text
              variant="label"
              color="var(--ggui-color-onSurfaceVariant, #52525b)"
              as="div"
              aria-label={`Wind speed ${windSpeed}`}
            >
              Wind: {windSpeed}
            </Text>
          </Stack>
        </Stack>

        <Stack
          direction="horizontal"
          gap="var(--ggui-spacing-2, 8px)"
          wrap
          align="stretch"
          aria-label="5-day forecast"
        >
          {forecast.map((item, index) => (
            <Card
              key={`${item.day ?? 'day'}-${index}`}
              padding="var(--ggui-spacing-2, 8px)"
              shadow="none"
              radius="md"
              border
            >
              <Stack gap="var(--ggui-spacing-1, 4px)" align="center">
                <Text
                  variant="caption"
                  color="var(--ggui-color-onSurfaceVariant, #52525b)"
                  as="div"
                  truncate
                >
                  {item.day ?? '—'}
                </Text>
                <Text
                  size="xl"
                  as="div"
                  aria-label={`Forecast icon ${item.icon ?? ''}`}
                >
                  {item.icon ?? '•'}
                </Text>
                <Text
                  variant="caption"
                  color="var(--ggui-color-onSurface, #18181b)"
                  as="div"
                >
                  {item.high ?? '—'}° / {item.low ?? '—'}°
                </Text>
              </Stack>
            </Card>
          ))}
        </Stack>
      </Stack>
    </Card>
  );
}

import React, { useMemo, useState } from 'react';
import {
  Card,
  Stack,
  Text,
  Button,
  Input,
  RadioGroup,
  Checkbox,
  TextArea,
  Progress,
  Alert,
} from '@ggui-ai/design/primitives';

interface Props {
  /** Available feature options for the checkbox step */
  featureOptions: string[];
  /** Labels for satisfaction rating (e.g., Very Unsatisfied to Very Satisfied) */
  satisfactionLabels: string[];
  /** Action Contract: Submit Survey */
  submit?: (answers: {
    name: string;
    email: string;
    satisfactionRating: string;
    featureInterests: string[];
    comments: string;
  }) => Promise<void> | void;
  /** Optional UI text defaults */
  title?: string;
  description?: string;
  submitLabel?: string;
  submittingLabel?: string;
  successMessage?: string;
  errorMessage?: string;
}

export default function GeneratedComponent({
  featureOptions = ['Feature A', 'Feature B', 'Feature C'],
  satisfactionLabels = [
    'Very Unsatisfied',
    'Unsatisfied',
    'Neutral',
    'Satisfied',
    'Very Satisfied',
  ],
  submit,
  title = 'Customer Survey',
  description = 'Please complete all required steps.',
  submitLabel = 'Submit Survey',
  submittingLabel = 'Submitting...',
  successMessage = 'Survey submitted successfully.',
  errorMessage = 'Something went wrong. Please try again.',
}: Props) {
  const [step, setStep] = useState(1);

  const [name, setName] = useState('');
  const [email, setEmail] = useState('');
  const [satisfactionRating, setSatisfactionRating] = useState('');
  const [featureInterests, setFeatureInterests] = useState<string[]>([]);
  const [comments, setComments] = useState('');

  const [touched, setTouched] = useState({
    name: false,
    email: false,
    satisfactionRating: false,
  });

  const [isSubmitting, setIsSubmitting] = useState(false);
  const [feedback, setFeedback] = useState<{ type: 'success' | 'error'; text: string } | null>(null);

  const totalSteps = 5;
  const emailRegex = /^[^\s@]+@[^\s@]+\.[^\s@]+$/;

  const nameError = touched.name && !name.trim() ? 'Name is required.' : '';
  const emailError =
    touched.email && !email.trim()
      ? 'Email is required.'
      : touched.email && !emailRegex.test(email)
      ? 'Please enter a valid email address.'
      : '';
  const satisfactionError =
    touched.satisfactionRating && !satisfactionRating ? 'Please select a rating.' : '';

  const stepValid = useMemo(() => {
    if (step === 1) return !!name.trim() && emailRegex.test(email);
    if (step === 2) return !!satisfactionRating;
    return true;
  }, [step, name, email, satisfactionRating]);

  const progressValue = Math.round((step / totalSteps) * 100);

  const toggleFeature = (feature: string, checked: boolean) => {
    setFeatureInterests((prev) =>
      checked ? [...prev, feature] : prev.filter((item) => item !== feature)
    );
  };

  const handleNext = () => {
    if (step === 1) {
      setTouched((prev) => ({ ...prev, name: true, email: true }));
      if (!name.trim() || !emailRegex.test(email)) return;
    }
    if (step === 2) {
      setTouched((prev) => ({ ...prev, satisfactionRating: true }));
      if (!satisfactionRating) return;
    }
    setStep((prev) => Math.min(totalSteps, prev + 1));
  };

  const handleBack = () => {
    setStep((prev) => Math.max(1, prev - 1));
  };

  const handleSubmit = async () => {
    setFeedback(null);
    setIsSubmitting(true);
    try {
      await submit?.({
        name: name.trim(),
        email: email.trim(),
        satisfactionRating,
        featureInterests,
        comments: comments.trim(),
      });
      setFeedback({ type: 'success', text: successMessage });
    } catch {
      setFeedback({ type: 'error', text: errorMessage });
    } finally {
      setIsSubmitting(false);
    }
  };

  return (
    <Card
      padding={24}
      shadow="md"
      radius="lg"
      style={{
        background: 'var(--ggui-color-surface, #fafafa)',
        borderColor: 'var(--ggui-color-outline, #d4d4d8)',
        color: 'var(--ggui-color-onSurface, #18181b)',
      }}
    >
      <Stack gap={16}>
        <Stack gap={6}>
          <Text variant="bodyLarge" weight="semibold" color="var(--ggui-color-onSurface, #18181b)">
            {title}
          </Text>
          <Text variant="bodySmall" color="var(--ggui-color-onSurfaceVariant, #52525b)">
            {description}
          </Text>
        </Stack>

        <Stack gap={6}>
          <Text variant="label" color="var(--ggui-color-onSurface, #18181b)">
            Step {step} of {totalSteps}
          </Text>
          <Progress value={progressValue} max={100} size="md" />
        </Stack>

        {feedback && (
          <Alert variant={feedback.type} title={feedback.type === 'success' ? 'Success' : 'Error'}>
            {feedback.text}
          </Alert>
        )}

        {step === 1 && (
          <Stack gap={12}>
            <Input
              label="Name"
              value={name}
              onChange={setName}
              required
              placeholder="Enter your name"
              error={nameError}
              onBlur={() => setTouched((prev) => ({ ...prev, name: true }))}
              aria-label="Name"
            />
            <Input
              label="Email"
              type="email"
              value={email}
              onChange={setEmail}
              required
              placeholder="Enter your email"
              error={emailError}
              onBlur={() => setTouched((prev) => ({ ...prev, email: true }))}
              aria-label="Email"
            />
          </Stack>
        )}

        {step === 2 && (
          <RadioGroup
            label="How satisfied are you?"
            value={satisfactionRating}
            onChange={setSatisfactionRating}
            options={satisfactionLabels.slice(0, 5).map((label, idx) => ({
              value: String(idx + 1),
              label: `${idx + 1} - ${label}`,
            }))}
            error={satisfactionError}
          />
        )}

        {step === 3 && (
          <Stack gap={10}>
            <Text variant="label" color="var(--ggui-color-onSurface, #18181b)">
              Which features are you interested in?
            </Text>
            {featureOptions.map((feature) => (
              <Checkbox
                key={feature}
                label={feature}
                checked={featureInterests.includes(feature)}
                onChange={(checked) => toggleFeature(feature, checked)}
              />
            ))}
          </Stack>
        )}

        {step === 4 && (
          <Stack gap={8}>
            <TextArea
              label="Additional comments (optional)"
              value={comments}
              onChange={setComments}
              rows={6}
              maxLength={500}
              showCount
              placeholder="Share any additional feedback..."
              helperText="Maximum 500 characters."
            />
            <Text variant="caption" color="var(--ggui-color-onSurfaceVariant, #52525b)">
              {comments.length}/500
            </Text>
          </Stack>
        )}

        {step === 5 && (
          <Stack gap={12}>
            <Text variant="label" color="var(--ggui-color-onSurface, #18181b)">
              Review your responses
            </Text>
            <Card
              padding={16}
              border
              shadow="none"
              radius="md"
              style={{
                background: 'var(--ggui-color-surfaceVariant, #f4f4f5)',
                borderColor: 'var(--ggui-color-outline, #d4d4d8)',
              }}
            >
              <Stack gap={8}>
                <Text variant="bodySmall" color="var(--ggui-color-onSurface, #18181b)">
                  <strong>Name:</strong> {name || '—'}
                </Text>
                <Text variant="bodySmall" color="var(--ggui-color-onSurface, #18181b)">
                  <strong>Email:</strong> {email || '—'}
                </Text>
                <Text variant="bodySmall" color="var(--ggui-color-onSurface, #18181b)">
                  <strong>Satisfaction:</strong>{' '}
                  {satisfactionRating
                    ? `${satisfactionRating} - ${
                        satisfactionLabels[Number(satisfactionRating) - 1] ?? ''
                      }`
                    : '—'}
                </Text>
                <Text variant="bodySmall" color="var(--ggui-color-onSurface, #18181b)">
                  <strong>Features:</strong>{' '}
                  {featureInterests.length ? featureInterests.join(', ') : 'None selected'}
                </Text>
                <Text variant="bodySmall" color="var(--ggui-color-onSurface, #18181b)">
                  <strong>Comments:</strong> {comments.trim() || 'No comments'}
                </Text>
              </Stack>
            </Card>
          </Stack>
        )}

        <Stack direction="horizontal" justify="between" gap={12}>
          <Button variant="secondary" onClick={handleBack} disabled={step === 1 || isSubmitting}>
            Back
          </Button>

          {step < totalSteps ? (
            <Button variant="primary" onClick={handleNext} disabled={!stepValid || isSubmitting}>
              Next
            </Button>
          ) : (
            <Button variant="primary" onClick={handleSubmit} loading={isSubmitting} disabled={isSubmitting}>
              {isSubmitting ? submittingLabel : submitLabel}
            </Button>
          )}
        </Stack>
      </Stack>
    </Card>
  );
}

import React, { useEffect, useMemo, useRef, useState } from 'react';
import { Card, Stack, Text, Button, Input, Badge, Box } from '@ggui-ai/design/primitives';

interface Props {
  /** Chat window title */
  title: string;
  /** Current user name (for right-aligning own messages) */
  currentUser: string;
  /** Number of participants */
  participantCount?: number;
  /** Array of messages with sender name, text, and ISO timestamp */
  messages: Array<{ sender?: string; text?: string; timestamp?: string }>;
  /** Action Contract: Send Message */
  sendMessage?: (payload: { text: string; timestamp: string }) => void;
  /** Interaction Contract: outgoing message alias */
  onSubmit?: (payload: { text: string; timestamp: string }) => void;
}

export default function GeneratedComponent({
  title = 'Chat',
  currentUser = '',
  participantCount,
  messages = [],
  sendMessage,
  onSubmit,
}: Props) {
  const [draft, setDraft] = useState<string>('');
  const [streamMessages, setStreamMessages] = useState<Array<{ sender?: string; text?: string; timestamp?: string }>>([]);
  const listRef = useRef<HTMLDivElement | null>(null);

  const allMessages = useMemo(() => [...messages, ...streamMessages], [messages, streamMessages]);

  const groupedMessages = useMemo(() => {
    const groups: Array<{ sender?: string; items: Array<{ sender?: string; text?: string; timestamp?: string }> }> = [];
    allMessages.forEach((msg) => {
      const prev = groups[groups.length - 1];
      if (prev && (prev.sender || '') === (msg.sender || '')) {
        prev.items.push(msg);
      } else {
        groups.push({ sender: msg.sender, items: [msg] });
      }
    });
    return groups;
  }, [allMessages]);

  const formatTime = (iso?: string) => {
    if (!iso) return '';
    const d = new Date(iso);
    if (Number.isNaN(d.getTime())) return iso;
    return d.toLocaleTimeString([], { hour: '2-digit', minute: '2-digit' });
  };

  const scrollToBottom = () => {
    if (listRef.current) {
      listRef.current.scrollTop = listRef.current.scrollHeight;
    }
  };

  useEffect(() => {
    scrollToBottom();
  }, []);

  useEffect(() => {
    scrollToBottom();
  }, [allMessages.length]);

  useEffect(() => {
    const handler = (event: Event) => {
      const custom = event as CustomEvent<{ sender?: string; text?: string; timestamp?: string }>;
      const payload = custom.detail || {};
      if (payload && (payload.text || payload.sender || payload.timestamp)) {
        setStreamMessages((prev) => [...prev, payload]);
      }
    };
    window.addEventListener('ggui:agent-data', handler);
    return () => window.removeEventListener('ggui:agent-data', handler);
  }, []);

  const handleSend = () => {
    const text = draft.trim();
    if (!text) return;
    const payload = { text, timestamp: new Date().toISOString() };
    sendMessage?.(payload);
    onSubmit?.(payload);
    setDraft('');
  };

  const onInputKeyDown = (e: React.KeyboardEvent<HTMLInputElement>) => {
    if (e.key === 'Enter') {
      e.preventDefault();
      handleSend();
    }
  };

  return (
    <Card
      padding={0}
      shadow="sm"
      radius="lg"
      border
      style={{
        background: 'var(--ggui-color-surface, #fafafa)',
        borderColor: 'var(--ggui-color-outline, #d4d4d8)',
        color: 'var(--ggui-color-onSurface, #18181b)',
        height: '100%',
        minHeight: '420px',
      }}
    >
      <Stack gap={0} style={{ height: '100%' }}>
        <Stack
          direction="horizontal"
          justify="between"
          align="center"
          style={{
            padding: 'var(--ggui-spacing-4, 16px)',
            borderBottom: '1px solid var(--ggui-color-outline, #d4d4d8)',
            background: 'var(--ggui-color-surface, #fafafa)',
          }}
        >
          <Text variant="bodyLarge" weight="semibold" color="var(--ggui-color-onSurface, #18181b)">
            {title}
          </Text>
          {typeof participantCount === 'number' && (
            <Badge variant="primary" size="sm" pill>
              {participantCount}
            </Badge>
          )}
        </Stack>

        <Box
          padding={0}
          style={{
            flex: 1,
            overflowY: 'auto',
            padding: 'var(--ggui-spacing-4, 16px)',
            background: 'var(--ggui-color-surface, #fafafa)',
          }}
          aria-label="Message list"
          ref={listRef}
        >
          <Stack gap="var(--ggui-spacing-2, 8px)">
            {groupedMessages.map((group, groupIndex) => {
              const isOwn = (group.sender || '') === currentUser;
              return (
                <Stack
                  key={`${group.sender || 'unknown'}-${groupIndex}`}
                  align={isOwn ? 'end' : 'start'}
                  gap="var(--ggui-spacing-1, 4px)"
                >
                  {group.items.map((msg, msgIndex) => (
                    <Card
                      key={`${msg.sender || 'unknown'}-${msg.timestamp || ''}-${msgIndex}`}
                      padding="var(--ggui-spacing-2, 8px)"
                      shadow="none"
                      border
                      radius="md"
                      style={{
                        maxWidth: '80%',
                        borderColor: 'var(--ggui-color-outline, #d4d4d8)',
                        background: isOwn
                          ? 'var(--ggui-color-primary-600, #0284c7)'
                          : 'var(--ggui-color-surfaceVariant, #f4f4f5)',
                        color: isOwn ? 'var(--ggui-color-surface, #fafafa)' : 'var(--ggui-color-onSurface, #18181b)',
                        transition: 'background-color 200ms ease, box-shadow 200ms ease',
                      }}
                    >
                      <Stack gap={4}>
                        {msgIndex === 0 && (
                          <Text
                            variant="caption"
                            weight="semibold"
                            color={isOwn ? 'var(--ggui-color-surface, #fafafa)' : 'var(--ggui-color-onSurfaceVariant, #52525b)'}
                          >
                            {msg.sender || 'Unknown'}
                          </Text>
                        )}
                        <Text
                          variant="body"
                          color={isOwn ? 'var(--ggui-color-surface, #fafafa)' : 'var(--ggui-color-onSurface, #18181b)'}
                        >
                          {msg.text || ''}
                        </Text>
                        <Text
                          variant="caption"
                          color={isOwn ? 'var(--ggui-color-surface, #fafafa)' : 'var(--ggui-color-onSurfaceVariant, #52525b)'}
                          align="right"
                        >
                          {formatTime(msg.timestamp)}
                        </Text>
                      </Stack>
                    </Card>
                  ))}
                </Stack>
              );
            })}
          </Stack>
        </Box>

        <Stack
          direction="horizontal"
          gap="var(--ggui-spacing-2, 8px)"
          align="end"
          style={{
            padding: 'var(--ggui-spacing-4, 16px)',
            borderTop: '1px solid var(--ggui-color-outline, #d4d4d8)',
            background: 'var(--ggui-color-surface, #fafafa)',
          }}
        >
          <Box style={{ flex: 1 }}>
            <Input
              label="Message"
              placeholder="Type a message..."
              value={draft}
              onChange={setDraft}
              onKeyDown={onInputKeyDown}
              aria-label="Compose message"
              size="md"
            />
          </Box>
          <Button
            variant="primary"
            size="md"
            onClick={handleSend}
            disabled={!draft.trim()}
            aria-label="Send message"
          >
            Send
          </Button>
        </Stack>
      </Stack>
    </Card>
  );
}

import React, { useEffect, useMemo, useState } from 'react';
import { Card, Stack, Text, Spinner, Box } from '@ggui-ai/design/primitives';

interface Props {
  /** Array of stocks with symbol, name, price, change, changePercent */
  stocks: Array<{ symbol?: string; name?: string; price?: number; change?: number; changePercent?: number }>;
  /** ISO timestamp of last price update */
  lastUpdated?: string;
}

export default function GeneratedComponent(props: Props) {
  const [liveStocks, setLiveStocks] = useState<Props['stocks']>(props.stocks ?? []);
  const [liveLastUpdated, setLiveLastUpdated] = useState<string | undefined>(props.lastUpdated);
  const [isConnecting, setIsConnecting] = useState<boolean>(true);
  const [isReceiving, setIsReceiving] = useState<boolean>(false);

  useEffect(() => {
    setLiveStocks(props.stocks ?? []);
  }, [props.stocks]);

  useEffect(() => {
    setLiveLastUpdated(props.lastUpdated);
  }, [props.lastUpdated]);

  useEffect(() => {
    const timeout = window.setTimeout(() => {
      setIsConnecting(false);
    }, 1200);

    const onAgentData = (event: Event) => {
      const customEvent = event as CustomEvent<{
        stocks?: Props['stocks'];
        lastUpdated?: string;
      }>;

      const payload = customEvent.detail;
      if (!payload) return;

      setIsConnecting(false);
      setIsReceiving(true);

      if (Array.isArray(payload.stocks)) {
        setLiveStocks(payload.stocks);
      }
      if (typeof payload.lastUpdated === 'string') {
        setLiveLastUpdated(payload.lastUpdated);
      }

      window.setTimeout(() => setIsReceiving(false), 600);
    };

    window.addEventListener('ggui:agent-data', onAgentData as EventListener);
    return () => {
      window.clearTimeout(timeout);
      window.removeEventListener('ggui:agent-data', onAgentData as EventListener);
    };
  }, []);

  const formattedUpdated = useMemo(() => {
    if (!liveLastUpdated) return '—';
    const date = new Date(liveLastUpdated);
    if (Number.isNaN(date.getTime())) return liveLastUpdated;
    return date.toLocaleString();
  }, [liveLastUpdated]);

  return (
    <Card
      padding="var(--ggui-spacing-6, 24px)"
      shadow="sm"
      border
      radius="lg"
      style={{
        background: 'var(--ggui-color-surface, #fafafa)',
        borderColor: 'var(--ggui-color-outline, #d4d4d8)',
      }}
    >
      <Stack gap="var(--ggui-spacing-6, 24px)">
        <Stack direction="horizontal" justify="between" align="center" wrap>
          <Text
            as="div"
            size="2xl"
            weight="bold"
            color="var(--ggui-color-onSurface, #18181b)"
          >
            Market Watch
          </Text>
          <Stack direction="horizontal" align="center" gap="var(--ggui-spacing-2, 8px)">
            {(isConnecting || isReceiving) && (
              <Spinner
                size={16}
                color="var(--ggui-color-primary-600, #0284c7)"
              />
            )}
            <Text variant="bodySmall" color="var(--ggui-color-onSurfaceVariant, #52525b)">
              {isConnecting ? 'Connecting live feed…' : `Last Updated: ${formattedUpdated}`}
            </Text>
          </Stack>
        </Stack>

        {isConnecting && liveStocks.length === 0 ? (
          <Card
            padding="var(--ggui-spacing-6, 24px)"
            border
            shadow="none"
            radius="md"
            style={{
              background: 'var(--ggui-color-surfaceVariant, #f4f4f5)',
              borderColor: 'var(--ggui-color-outlineVariant, #e4e4e7)',
            }}
          >
            <Stack direction="horizontal" align="center" gap="var(--ggui-spacing-2, 8px)">
              <Spinner size={18} color="var(--ggui-color-primary-600, #0284c7)" />
              <Text variant="bodySmall" color="var(--ggui-color-onSurfaceVariant, #52525b)">
                Waiting for market data…
              </Text>
            </Stack>
          </Card>
        ) : (
          <Box
            style={{
              display: 'grid',
              gridTemplateColumns: 'repeat(auto-fit, minmax(220px, 1fr))',
              gap: 'var(--ggui-spacing-4, 16px)',
            }}
          >
            {liveStocks.map((stock, index) => {
              const change = stock.change ?? 0;
              const changePercent = stock.changePercent ?? 0;
              const positive = change >= 0;
              const accentColor = positive
                ? 'var(--ggui-color-success-600, #16a34a)'
                : 'var(--ggui-color-error-600, #dc2626)';
              const arrow = positive ? '▲' : '▼';

              return (
                <Card
                  key={`${stock.symbol ?? 'stock'}-${index}`}
                  padding="var(--ggui-spacing-4, 16px)"
                  shadow="sm"
                  border
                  radius="md"
                  style={{
                    background: 'var(--ggui-color-surfaceVariant, #f4f4f5)',
                    borderColor: accentColor,
                    transition:
                      'transform var(--ggui-duration-fast, 100ms) ease, box-shadow var(--ggui-duration-fast, 100ms) ease',
                  }}
                >
                  <Stack gap="var(--ggui-spacing-2, 8px)">
                    <Text
                      as="div"
                      size="3xl"
                      weight="bold"
                      color="var(--ggui-color-onSurface, #18181b)"
                    >
                      {stock.symbol ?? '—'}
                    </Text>
                    <Text variant="bodySmall" color="var(--ggui-color-onSurfaceVariant, #52525b)">
                      {stock.name ?? 'Unknown Company'}
                    </Text>
                    <Text
                      as="div"
                      size="xl"
                      weight="semibold"
                      color="var(--ggui-color-onSurface, #18181b)"
                    >
                      ${(stock.price ?? 0).toFixed(2)}
                    </Text>
                    <Stack direction="horizontal" justify="between" align="center">
                      <Text variant="label" color={accentColor}>
                        {change >= 0 ? '+' : ''}
                        {change.toFixed(2)}
                      </Text>
                      <Text variant="label" color={accentColor}>
                        {arrow} {changePercent >= 0 ? '+' : ''}
                        {changePercent.toFixed(2)}%
                      </Text>
                    </Stack>
                  </Stack>
                </Card>
              );
            })}
          </Box>
        )}
      </Stack>
    </Card>
  );
}

import React, { useEffect, useMemo, useRef, useState } from 'react';
import {
  Badge,
  Button,
  Card,
  Container,
  Divider,
  Heading,
  Input,
  MotionKeyframes,
  Progress,
  Select,
  Stack,
  Text,
  Toggle,
  useMotion,
} from '@ggui-ai/design/primitives';

interface Props {
  /** Pre-filled profile data for editing (all fields optional) */
  initialProfile?: {
    name?: string;
    email?: string;
    avatar?: string;
    role?: string;
    emailNotifications?: boolean;
    theme?: string;
  };
  /** Available avatar emojis to choose from */
  avatarOptions: string[];
  /** Available role options for the dropdown */
  roleOptions: string[];
  /** Action Contract: called on final submit */
  onComplete?: (data: {
    name: string;
    email: string;
    avatar: string;
    role: string;
    emailNotifications: boolean;
    theme: string;
  }) => void;
}

export default function GeneratedComponent(props: Props) {
  const {
    initialProfile = {},
    avatarOptions,
    roleOptions,
    onComplete,
  } = props;

  const { motionEnabled } = useMotion();

  const [currentStep, setCurrentStep] = useState<number>(1);
  const [name, setName] = useState<string>(initialProfile.name ?? '');
  const [email, setEmail] = useState<string>(initialProfile.email ?? '');
  const [avatar, setAvatar] = useState<string>(
    initialProfile.avatar ?? avatarOptions[0] ?? ''
  );
  const [role, setRole] = useState<string>(initialProfile.role ?? '');
  const [emailNotifications, setEmailNotifications] = useState<boolean>(
    initialProfile.emailNotifications ?? true
  );
  const [theme, setTheme] = useState<string>(initialProfile.theme ?? 'light');

  const [touchedName, setTouchedName] = useState<boolean>(false);
  const [touchedEmail, setTouchedEmail] = useState<boolean>(false);
  const [touchedAvatar, setTouchedAvatar] = useState<boolean>(false);
  const [touchedRole, setTouchedRole] = useState<boolean>(false);

  const step1FirstRef = useRef<HTMLInputElement | null>(null);
  const step2FirstRef = useRef<HTMLSelectElement | null>(null);
  const step3FocusRef = useRef<HTMLButtonElement | null>(null);

  useEffect(() => {
    setName(initialProfile.name ?? '');
    setEmail(initialProfile.email ?? '');
    setAvatar(initialProfile.avatar ?? avatarOptions[0] ?? '');
    setRole(initialProfile.role ?? '');
    setEmailNotifications(initialProfile.emailNotifications ?? true);
    setTheme(initialProfile.theme ?? 'light');
  }, [initialProfile, avatarOptions]);

  useEffect(() => {
    if (currentStep === 1) step1FirstRef.current?.focus();
    if (currentStep === 2) step2FirstRef.current?.focus();
    if (currentStep === 3) step3FocusRef.current?.focus();
  }, [currentStep]);

  const emailValid = useMemo(
    () => /^[^\s@]+@[^\s@]+\.[^\s@]+$/.test(email.trim()),
    [email]
  );

  const isStep1Valid =
    name.trim().length > 0 && emailValid && avatar.trim().length > 0;
  const isStep2Valid =
    role.trim().length > 0 && (theme === 'light' || theme === 'dark');

  const canGoNext =
    (currentStep === 1 && isStep1Valid) ||
    (currentStep === 2 && isStep2Valid) ||
    (currentStep === 3 && isStep1Valid && isStep2Valid);

  const handleNext = () => {
    if (currentStep === 1) {
      setTouchedName(true);
      setTouchedEmail(true);
      setTouchedAvatar(true);
      if (!isStep1Valid) return;
    }
    if (currentStep === 2) {
      setTouchedRole(true);
      if (!isStep2Valid) return;
    }
    setCurrentStep((prev) => Math.min(3, prev + 1));
  };

  const handleBack = () => setCurrentStep((prev) => Math.max(1, prev - 1));

  const handleComplete = () => {
    if (!isStep1Valid || !isStep2Valid) return;
    onComplete?.({
      name: name.trim(),
      email: email.trim(),
      avatar,
      role,
      emailNotifications,
      theme,
    });
  };

  const animationStyle = motionEnabled
    ? { animation: 'ggui-slideInUp 200ms ease-out' }
    : { animation: 'none' };

  return (
    <Container
      maxWidth="md"
      padding="var(--ggui-spacing-6, 24px)"
    >
      <MotionKeyframes />
      <Card
        padding={24}
        radius="lg"
        shadow="md"
        border
      >
        <Stack gap={24}>
          <Stack gap={8}>
            <Heading level={3} color="var(--ggui-color-onSurface, #18181b)">
              Onboarding Wizard
            </Heading>
            <Stack direction="horizontal" justify="between" align="center">
              <Text
                variant="bodySmall"
                color="var(--ggui-color-onSurfaceVariant, #52525b)"
              >
                Step {currentStep} of 3
              </Text>
              <Badge variant="primary" size="sm">
                Step {currentStep}
              </Badge>
            </Stack>
            <Progress value={(currentStep / 3) * 100} max={100} size="md" variant="default" />
          </Stack>

          <Stack
            gap={16}
            aria-live="polite"
            style={animationStyle}
          >
            {currentStep === 1 && (
              <Stack gap={16}>
                <Input
                  ref={step1FirstRef}
                  label="Name"
                  value={name}
                  onChange={(v) => {
                    setName(v);
                    if (!touchedName) setTouchedName(true);
                  }}
                  required
                  size="md"
                  error={touchedName && name.trim().length === 0 ? 'Name is required.' : undefined}
                />
                <Input
                  label="Email"
                  value={email}
                  onChange={(v) => {
                    setEmail(v);
                    if (!touchedEmail) setTouchedEmail(true);
                  }}
                  required
                  type="email"
                  size="md"
                  error={
                    touchedEmail
                      ? email.trim().length === 0
                        ? 'Email is required.'
                        : !emailValid
                        ? 'Please enter a valid email address.'
                        : undefined
                      : undefined
                  }
                />
                <Stack gap={8}>
                  <Text variant="label" color="var(--ggui-color-onSurface, #18181b)">
                    Avatar
                  </Text>
                  {avatarOptions.length === 0 ? (
                    <Text variant="caption" color="var(--ggui-color-onSurfaceVariant, #52525b)">
                      No avatar options available.
                    </Text>
                  ) : (
                    <Stack direction="horizontal" wrap gap={8}>
                      {avatarOptions.map((emoji) => (
                        <Button
                          key={emoji}
                          variant={avatar === emoji ? 'primary' : 'outline'}
                          size="sm"
                          aria-pressed={avatar === emoji}
                          aria-label={`Select avatar ${emoji}`}
                          onPress={() => {
                            setAvatar(emoji);
                            if (!touchedAvatar) setTouchedAvatar(true);
                          }}
                        >
                          {emoji}
                        </Button>
                      ))}
                    </Stack>
                  )}
                  {touchedAvatar && avatar.trim().length === 0 && (
                    <Text variant="caption" color="var(--ggui-color-error-500, #ef4444)">
                      Please select an avatar.
                    </Text>
                  )}
                </Stack>
              </Stack>
            )}

            {currentStep === 2 && (
              <Stack gap={16}>
                <Select
                  ref={step2FirstRef}
                  label="Role"
                  value={role}
                  onChange={(v) => {
                    setRole(v);
                    if (!touchedRole) setTouchedRole(true);
                  }}
                  options={roleOptions.map((roleItem) => ({
                    value: roleItem,
                    label: roleItem,
                  }))}
                  placeholder="Select your role"
                  size="md"
                  required
                  disabled={roleOptions.length === 0}
                  error={touchedRole && role.trim().length === 0 ? 'Role is required.' : undefined}
                  helperText={roleOptions.length === 0 ? 'No role options available.' : undefined}
                />
                <Toggle
                  label="Email notifications"
                  checked={emailNotifications}
                  onChange={setEmailNotifications}
                  size="md"
                />
                <Text variant="caption" color="var(--ggui-color-onSurfaceVariant, #52525b)">
                  Enable to receive onboarding updates by email.
                </Text>
                <Toggle
                  label={`Theme: ${theme === 'dark' ? 'Dark' : 'Light'}`}
                  checked={theme === 'dark'}
                  onChange={(checked) => setTheme(checked ? 'dark' : 'light')}
                  size="md"
                />
                <Text variant="caption" color="var(--ggui-color-onSurfaceVariant, #52525b)">
                  Toggle between light and dark preference.
                </Text>
              </Stack>
            )}

            {currentStep === 3 && (
              <Stack gap={16}>
                <Heading level={4} color="var(--ggui-color-onSurface, #18181b)">
                  Review & Confirm
                </Heading>
                <Card
                  padding={16}
                  shadow="none"
                  border
                  radius="md"
                >
                  <Stack gap={12}>
                    <Stack direction="horizontal" justify="between">
                      <Text variant="label">Name</Text>
                      <Text variant="bodySmall">{name || '-'}</Text>
                    </Stack>
                    <Stack direction="horizontal" justify="between">
                      <Text variant="label">Email</Text>
                      <Text variant="bodySmall">{email || '-'}</Text>
                    </Stack>
                    <Stack direction="horizontal" justify="between">
                      <Text variant="label">Avatar</Text>
                      <Text variant="bodySmall">{avatar || '-'}</Text>
                    </Stack>
                    <Divider />
                    <Stack direction="horizontal" justify="between">
                      <Text variant="label">Role</Text>
                      <Text variant="bodySmall">{role || '-'}</Text>
                    </Stack>
                    <Stack direction="horizontal" justify="between">
                      <Text variant="label">Email Notifications</Text>
                      <Text variant="bodySmall">{emailNotifications ? 'On' : 'Off'}</Text>
                    </Stack>
                    <Stack direction="horizontal" justify="between">
                      <Text variant="label">Theme</Text>
                      <Text variant="bodySmall">{theme === 'dark' ? 'Dark' : 'Light'}</Text>
                    </Stack>
                  </Stack>
                </Card>
                <Stack direction="horizontal" justify="start" gap={8}>
                  <Button
                    ref={step3FocusRef}
                    variant="ghost"
                    size="md"
                    onPress={() => setCurrentStep(2)}
                  >
                    Go Back
                  </Button>
                  <Button
                    variant="primary"
                    size="md"
                    onPress={handleComplete}
                    disabled={!canGoNext}
                  >
                    Complete Setup
                  </Button>
                </Stack>
              </Stack>
            )}
          </Stack>

          <Divider />

          <Stack direction="horizontal" justify="between" align="center">
            <Button variant="ghost" size="md" onPress={handleBack} disabled={currentStep === 1}>
              Back
            </Button>
            {currentStep < 3 ? (
              <Button variant="primary" size="md" onPress={handleNext} disabled={!canGoNext}>
                Next
              </Button>
            ) : (
              <Button variant="primary" size="md" onPress={handleComplete} disabled={!canGoNext}>
                Complete Setup
              </Button>
            )}
          </Stack>
        </Stack>
      </Card>
    </Container>
  );
}

export const __GGUI_META__ = {
  category: 'forms',
  description:
    'Reusable 3-step onboarding wizard with progress, per-step validation, animated transitions, review step, and completion callback.',
};

import React from 'react';
import { Box, Card, Divider, Heading, Stack, Text } from '@ggui-ai/design/primitives';

interface Props {
  /** City name */
  city: string;
  /** Current temperature */
  temperature: number;
  /** Weather condition (Sunny, Cloudy, Rainy, etc.) */
  condition: string;
  /** Humidity percentage */
  humidity: number;
  /** Wind speed */
  windSpeed: number;
  /** Temperature unit (C or F) */
  unit?: string;
  /** 5-day forecast array */
  forecast: Array<{ day?: string; icon?: string; high?: number; low?: number }>;
}

export default function GeneratedComponent({
  city = '—',
  temperature = 0,
  condition = 'Unknown',
  humidity = 0,
  windSpeed = 0,
  unit = 'C',
  forecast = [],
}: Props) {
  const resolvedUnit = unit || 'C';
  const forecastItems = forecast.slice(0, 5);

  const formatHighLow = (high?: number, low?: number) => {
    const highText = typeof high === 'number' ? `${high}°` : null;
    const lowText = typeof low === 'number' ? `${low}°` : null;

    if (highText && lowText) return `${highText}/${lowText}`;
    if (highText) return highText;
    if (lowText) return lowText;
    return '—';
  };

  return (
    <Card
      shadow="md"
      radius="lg"
      border
      padding="var(--ggui-spacing-6, 24px)"
      role="region"
      aria-label={`Weather for ${city}`}
    >
      <Stack gap="var(--ggui-spacing-4, 16px)">
        <Stack
          direction="horizontal"
          justify="between"
          align="start"
          wrap
          gap="var(--ggui-spacing-4, 16px)"
        >
          <Stack gap="var(--ggui-spacing-2, 8px)">
            <Heading level={4} color="var(--ggui-color-onSurface, #18181b)">
              {city || '—'}
            </Heading>
            <Text
              variant="body"
              size="4xl"
              weight="bold"
              color="var(--ggui-color-primary-700, #0369a1)"
            >
              {`${temperature}°${resolvedUnit}`}
            </Text>
          </Stack>

          <Stack
            gap="var(--ggui-spacing-2, 8px)"
            align="end"
            style={{ minWidth: 'fit-content' }}
          >
            <Text
              as="span"
              variant="body"
              size="4xl"
              color="var(--ggui-color-primary-700, #0369a1)"
              aria-hidden="true"
            >
              {condition?.charAt(0) || '—'}
            </Text>
            <Text
              variant="bodyLarge"
              weight="medium"
              color="var(--ggui-color-onSurface, #18181b)"
              align="right"
            >
              {condition || 'Unknown'}
            </Text>
          </Stack>
        </Stack>

        <Stack
          direction="horizontal"
          justify="between"
          wrap
          gap="var(--ggui-spacing-4, 16px)"
        >
          <Stack gap="var(--ggui-spacing-1, 4px)">
            <Text variant="caption" color="var(--ggui-color-onSurfaceVariant, #52525b)">
              Humidity
            </Text>
            <Text variant="label" color="var(--ggui-color-onSurface, #18181b)">
              {`${humidity}%`}
            </Text>
          </Stack>

          <Stack gap="var(--ggui-spacing-1, 4px)">
            <Text variant="caption" color="var(--ggui-color-onSurfaceVariant, #52525b)">
              Wind
            </Text>
            <Text variant="label" color="var(--ggui-color-onSurface, #18181b)">
              {`${windSpeed} km/h`}
            </Text>
          </Stack>
        </Stack>

        <Divider color="var(--ggui-color-outlineVariant, #e4e4e7)" margin={0} />

        <Box
          background="var(--ggui-color-surface, #fafafa)"
          borderRadius="var(--ggui-shape-radius-md, 8px)"
          padding="var(--ggui-spacing-2, 8px)"
          style={{
            border: '1px solid var(--ggui-color-outlineVariant, #e4e4e7)',
            overflowX: 'auto',
          }}
          role="list"
          aria-label="5-day forecast"
        >
          <Stack
            direction="horizontal"
            gap="var(--ggui-spacing-2, 8px)"
            wrap={false}
            align="stretch"
          >
            {forecastItems.map((item, index) => {
              const fallbackIcon = condition?.charAt(0) || '—';
              const day = item.day || '—';
              const icon = item.icon || fallbackIcon || '—';
              const highLow = formatHighLow(item.high, item.low);

              return (
                <Box
                  key={`${item.day ?? 'day'}-${index}`}
                  padding="var(--ggui-spacing-2, 8px)"
                  borderRadius="var(--ggui-shape-radius-md, 8px)"
                  background="var(--ggui-color-surfaceVariant, #f4f4f5)"
                  role="listitem"
                  style={{
                    minWidth: '84px',
                    border: '1px solid var(--ggui-color-outlineVariant, #e4e4e7)',
                  }}
                >
                  <Stack gap="var(--ggui-spacing-1, 4px)" align="center">
                    <Text
                      variant="caption"
                      weight="medium"
                      color="var(--ggui-color-onSurfaceVariant, #52525b)"
                      align="center"
                    >
                      {day}
                    </Text>
                    <Text
                      as="span"
                      variant="body"
                      size="xl"
                      color="var(--ggui-color-primary-700, #0369a1)"
                      aria-label={`Forecast icon ${icon}`}
                    >
                      {icon}
                    </Text>
                    <Text
                      variant="bodySmall"
                      color="var(--ggui-color-onSurface, #18181b)"
                      align="center"
                    >
                      {highLow}
                    </Text>
                  </Stack>
                </Box>
              );
            })}
          </Stack>
        </Box>
      </Stack>
    </Card>
  );
}

import React, { FormEvent, useMemo, useState } from 'react';
import {
  Alert,
  Button,
  Card,
  Checkbox,
  Container,
  Divider,
  Heading,
  Input,
  Progress,
  RadioGroup,
  Stack,
  Text,
  TextArea,
} from '@ggui-ai/design/primitives';

interface Props {
  /** Available feature options for the checkbox step */
  featureOptions: string[];
  /** Labels for satisfaction rating (e.g., Very Unsatisfied to Very Satisfied) */
  satisfactionLabels: string[];
  /** Action Contract callback: Submit Survey */
  onSubmit?: (payload: {
    respondent: { name: string; email: string };
    satisfaction: { rating: number | null; label: string | null };
    interests: string[];
    comments: string;
    meta: { submittedAt: string };
  }) => Promise<void> | void;
}

export default function GeneratedComponent({
  featureOptions = [],
  satisfactionLabels = ['1', '2', '3', '4', '5'],
  onSubmit = async () => {},
}: Props) {
  const [currentStep, setCurrentStep] = useState<number>(1); // 1..5 (5 = review)
  const [name, setName] = useState<string>('');
  const [email, setEmail] = useState<string>('');
  const [selectedRating, setSelectedRating] = useState<number | null>(null);
  const [selectedFeatures, setSelectedFeatures] = useState<string[]>([]);
  const [comments, setComments] = useState<string>('');

  const [touched, setTouched] = useState<{
    name: boolean;
    email: boolean;
    rating: boolean;
    features: boolean;
    comments: boolean;
  }>({
    name: false,
    email: false,
    rating: false,
    features: false,
    comments: false,
  });

  const [isSubmitting, setIsSubmitting] = useState<boolean>(false);
  const [submitStatus, setSubmitStatus] = useState<{
    type: 'idle' | 'success' | 'error';
    message?: string;
  }>({ type: 'idle' });

  const ratingLabels = useMemo(() => satisfactionLabels.slice(0, 5), [satisfactionLabels]);

  const emailIsValid = useMemo(() => {
    const trimmed = email.trim();
    if (!trimmed) return false;
    return /^[^\s@]+@[^\s@]+\.[^\s@]+$/.test(trimmed);
  }, [email]);

  const stepValidity = useMemo(() => {
    const step1 = name.trim().length > 0 && emailIsValid;
    const step2 = selectedRating !== null;
    const step3 = true;
    const step4 = comments.length <= 500;
    const review = step1 && step2 && step3 && step4;
    return { step1, step2, step3, step4, review };
  }, [name, emailIsValid, selectedRating, comments.length]);

  const canGoNext = useMemo(() => {
    if (currentStep === 1) return stepValidity.step1;
    if (currentStep === 2) return stepValidity.step2;
    if (currentStep === 3) return stepValidity.step3;
    if (currentStep === 4) return stepValidity.step4;
    return stepValidity.review;
  }, [currentStep, stepValidity]);

  const progressValue = currentStep <= 4 ? (currentStep / 4) * 100 : 100;

  const nameError =
    touched.name && name.trim().length === 0 ? 'Name is required.' : undefined;

  const emailError =
    touched.email && email.trim().length === 0
      ? 'Email is required.'
      : touched.email && !emailIsValid
      ? 'Please enter a valid email address.'
      : undefined;

  const ratingError =
    touched.rating && selectedRating === null ? 'Please select a satisfaction rating.' : undefined;

  const toggleFeature = (feature: string, checked: boolean) => {
    if (checked) {
      setSelectedFeatures((prev) => (prev.includes(feature) ? prev : [...prev, feature]));
    } else {
      setSelectedFeatures((prev) => prev.filter((f) => f !== feature));
    }
  };

  const goNext = () => {
    if (isSubmitting) return;

    if (currentStep === 1) setTouched((t) => ({ ...t, name: true, email: true }));
    if (currentStep === 2) setTouched((t) => ({ ...t, rating: true }));
    if (currentStep === 4) setTouched((t) => ({ ...t, comments: true }));

    if (!canGoNext) return;
    setCurrentStep((s) => Math.min(5, s + 1));
  };

  const goBack = () => {
    if (isSubmitting) return;
    setCurrentStep((s) => Math.max(1, s - 1));
  };

  const handleSubmit = async () => {
    if (isSubmitting || !stepValidity.review) return;
    setIsSubmitting(true);
    setSubmitStatus({ type: 'idle' });

    const mappedLabel =
      selectedRating !== null && ratingLabels[selectedRating - 1]
        ? ratingLabels[selectedRating - 1]
        : null;

    const payload = {
      respondent: { name: name.trim(), email: email.trim() },
      satisfaction: { rating: selectedRating, label: mappedLabel },
      interests: selectedFeatures,
      comments,
      meta: { submittedAt: new Date().toISOString() },
    };

    try {
      await onSubmit(payload);
      setSubmitStatus({ type: 'success', message: 'Survey submitted successfully.' });
    } catch (error) {
      setSubmitStatus({
        type: 'error',
        message: 'Submission failed. Please try again.',
      });
    } finally {
      setIsSubmitting(false);
    }
  };

  const onFormSubmit = async (e: FormEvent) => {
    e.preventDefault();
    if (currentStep < 5) {
      goNext();
      return;
    }
    await handleSubmit();
  };

  return (
    <Container maxWidth="md" padding="var(--ggui-spacing-4, 16px)">
      <Card
        padding={24}
        shadow="sm"
        radius="lg"
        border
        style={{
          background: 'var(--ggui-color-surfaceVariant, #f4f4f5)',
          borderColor: 'var(--ggui-color-outline, #d4d4d8)',
        }}
      >
        <form onSubmit={onFormSubmit} aria-label="Multi-step survey form">
          <Stack gap={20}>
            <Stack gap={8}>
              <Heading level={3} color="var(--ggui-color-onSurface, #18181b)">
                Survey Form
              </Heading>
              <Stack gap={4}>
                <Text
                  variant="label"
                  color="var(--ggui-color-onSurfaceVariant, #52525b)"
                  as="div"
                >
                  <span aria-live="polite">
                    {currentStep <= 4 ? `Step ${currentStep} of 4` : 'Review & Submit'}
                  </span>
                </Text>
                <Progress value={progressValue} max={100} size="md" variant="default" />
              </Stack>
            </Stack>

            {currentStep === 1 && (
              <Stack gap={12}>
                <Text variant="bodySmall" color="var(--ggui-color-onSurfaceVariant, #52525b)">
                  Enter your contact details.
                </Text>
                <Input
                  label="Name"
                  value={name}
                  onChange={setName}
                  size="md"
                  required
                  disabled={isSubmitting}
                  error={nameError}
                  onBlur={() => setTouched((t) => ({ ...t, name: true }))}
                />
                <Input
                  label="Email"
                  type="email"
                  value={email}
                  onChange={setEmail}
                  size="md"
                  required
                  disabled={isSubmitting}
                  error={emailError}
                  onBlur={() => setTouched((t) => ({ ...t, email: true }))}
                />
              </Stack>
            )}

            {currentStep === 2 && (
              <Stack gap={12}>
                <Text variant="bodySmall" color="var(--ggui-color-onSurfaceVariant, #52525b)">
                  Rate your overall satisfaction.
                </Text>
                <RadioGroup
                  label="Satisfaction (1-5)"
                  value={selectedRating !== null ? String(selectedRating) : ''}
                  onChange={(value) => {
                    setSelectedRating(Number(value));
                    setTouched((t) => ({ ...t, rating: true }));
                  }}
                  direction="vertical"
                  disabled={isSubmitting}
                  error={ratingError}
                  options={ratingLabels.map((label, index) => ({
                    value: String(index + 1),
                    label,
                  }))}
                />
              </Stack>
            )}

            {currentStep === 3 && (
              <Stack gap={12}>
                <Text variant="label" color="var(--ggui-color-onSurface, #18181b)">
                  Feature interests
                </Text>
                <Text variant="bodySmall" color="var(--ggui-color-onSurfaceVariant, #52525b)">
                  Select any features you are interested in.
                </Text>
                <Stack gap={8}>
                  {featureOptions.map((feature) => (
                    <Checkbox
                      key={feature}
                      label={feature}
                      checked={selectedFeatures.includes(feature)}
                      disabled={isSubmitting}
                      onChange={(checked) => toggleFeature(feature, checked)}
                    />
                  ))}
                  {featureOptions.length === 0 && (
                    <Text variant="caption" color="var(--ggui-color-onSurfaceVariant, #52525b)">
                      No feature options available.
                    </Text>
                  )}
                </Stack>
              </Stack>
            )}

            {currentStep === 4 && (
              <Stack gap={12}>
                <Text variant="bodySmall" color="var(--ggui-color-onSurfaceVariant, #52525b)">
                  Share any additional comments (optional).
                </Text>
                <TextArea
                  label="Comments"
                  value={comments}
                  onChange={(value) => {
                    setComments(value);
                    setTouched((t) => ({ ...t, comments: true }));
                  }}
                  rows={6}
                  maxLength={500}
                  showCount
                  disabled={isSubmitting}
                  helperText="Maximum 500 characters."
                />
                <Text variant="caption" color="var(--ggui-color-onSurfaceVariant, #52525b)">
                  {comments.length}/500 characters
                </Text>
              </Stack>
            )}

            {currentStep === 5 && (
              <Stack gap={12}>
                <Text variant="bodySmall" color="var(--ggui-color-onSurfaceVariant, #52525b)">
                  Review your responses before submitting.
                </Text>
                <Divider color="var(--ggui-color-outlineVariant, #e4e4e7)" margin={4} />
                <Stack gap={8}>
                  <Text variant="label" color="var(--ggui-color-onSurface, #18181b)">
                    Respondent
                  </Text>
                  <Text variant="bodySmall" color="var(--ggui-color-onSurface, #18181b)">
                    Name: {name.trim() || '—'}
                  </Text>
                  <Text variant="bodySmall" color="var(--ggui-color-onSurface, #18181b)">
                    Email: {email.trim() || '—'}
                  </Text>
                </Stack>
                <Divider color="var(--ggui-color-outlineVariant, #e4e4e7)" margin={4} />
                <Stack gap={8}>
                  <Text variant="label" color="var(--ggui-color-onSurface, #18181b)">
                    Satisfaction
                  </Text>
                  <Text variant="bodySmall" color="var(--ggui-color-onSurface, #18181b)">
                    Rating:{' '}
                    {selectedRating !== null
                      ? `${selectedRating} - ${ratingLabels[selectedRating - 1] ?? ''}`
                      : '—'}
                  </Text>
                </Stack>
                <Divider color="var(--ggui-color-outlineVariant, #e4e4e7)" margin={4} />
                <Stack gap={8}>
                  <Text variant="label" color="var(--ggui-color-onSurface, #18181b)">
                    Feature interests
                  </Text>
                  <Text variant="bodySmall" color="var(--ggui-color-onSurface, #18181b)">
                    {selectedFeatures.length > 0 ? selectedFeatures.join(', ') : 'None selected'}
                  </Text>
                </Stack>
                <Divider color="var(--ggui-color-outlineVariant, #e4e4e7)" margin={4} />
                <Stack gap={8}>
                  <Text variant="label" color="var(--ggui-color-onSurface, #18181b)">
                    Comments
                  </Text>
                  <Text variant="bodySmall" color="var(--ggui-color-onSurface, #18181b)">
                    {comments.trim() || 'No comments provided.'}
                  </Text>
                </Stack>
              </Stack>
            )}

            {submitStatus.type !== 'idle' && (
              <>
                <Divider color="var(--ggui-color-outlineVariant, #e4e4e7)" margin={0} />
                <Alert
                  variant={submitStatus.type === 'success' ? 'success' : 'error'}
                  title={submitStatus.type === 'success' ? 'Success' : 'Error'}
                >
                  {submitStatus.message}
                </Alert>
              </>
            )}

            <Stack direction="horizontal" justify="between" align="center" wrap gap={12}>
              <Button
                variant="ghost"
                size="md"
                onClick={goBack}
                disabled={isSubmitting || currentStep === 1}
              >
                Back
              </Button>

              {currentStep < 5 ? (
                <Button
                  variant="primary"
                  size="md"
                  onClick={goNext}
                  disabled={isSubmitting || !canGoNext}
                >
                  {currentStep === 4 ? 'Review' : 'Next'}
                </Button>
              ) : (
                <Button
                  variant="primary"
                  size="md"
                  type="submit"
                  loading={isSubmitting}
                  disabled={isSubmitting || !stepValidity.review}
                >
                  Submit Survey
                </Button>
              )}
            </Stack>
          </Stack>
        </form>
      </Card>
    </Container>
  );
}

import React, { useMemo, useState } from 'react';
import { Card, Stack, Text, Input, Button } from '@ggui-ai/design/primitives';

interface Props {
  /** Full periodic table element data */
  elements: Array<{
    atomicNumber?: number;
    symbol?: string;
    name?: string;
    atomicWeight?: number;
    category?: string;
    row?: number;
    col?: number;
  }>;
}

const defaultElements: Props['elements'] = [
  { atomicNumber: 1, symbol: 'H', name: 'Hydrogen', atomicWeight: 1.008, category: 'nonmetal', row: 1, col: 1 },
  { atomicNumber: 2, symbol: 'He', name: 'Helium', atomicWeight: 4.0026, category: 'noble gas', row: 1, col: 18 },
  { atomicNumber: 3, symbol: 'Li', name: 'Lithium', atomicWeight: 6.94, category: 'alkali metal', row: 2, col: 1 },
  { atomicNumber: 4, symbol: 'Be', name: 'Beryllium', atomicWeight: 9.0122, category: 'alkaline earth metal', row: 2, col: 2 },
  { atomicNumber: 5, symbol: 'B', name: 'Boron', atomicWeight: 10.81, category: 'metalloid', row: 2, col: 13 },
  { atomicNumber: 6, symbol: 'C', name: 'Carbon', atomicWeight: 12.011, category: 'nonmetal', row: 2, col: 14 },
  { atomicNumber: 7, symbol: 'N', name: 'Nitrogen', atomicWeight: 14.007, category: 'nonmetal', row: 2, col: 15 },
  { atomicNumber: 8, symbol: 'O', name: 'Oxygen', atomicWeight: 15.999, category: 'nonmetal', row: 2, col: 16 },
  { atomicNumber: 9, symbol: 'F', name: 'Fluorine', atomicWeight: 18.998, category: 'halogen', row: 2, col: 17 },
  { atomicNumber: 10, symbol: 'Ne', name: 'Neon', atomicWeight: 20.18, category: 'noble gas', row: 2, col: 18 },
];

const categoryColorMap: Record<string, string> = {
  'alkali metal': 'var(--ggui-color-error-500, #ef4444)',
  'alkaline earth metal': 'var(--ggui-color-warning-500, #f59e0b)',
  'transition metal': 'var(--ggui-color-info-500, #06b6d4)',
  'post-transition metal': 'var(--ggui-color-neutral-500, #6b7280)',
  metalloid: 'var(--ggui-color-primary-500, #0ea5e9)',
  nonmetal: 'var(--ggui-color-success-500, #22c55e)',
  halogen: 'var(--ggui-color-warning-600, #d97706)',
  'noble gas': 'var(--ggui-color-primary-600, #0284c7)',
  lanthanide: 'var(--ggui-color-primary-400, #38bdf8)',
  actinide: 'var(--ggui-color-error-600, #dc2626)',
  unknown: 'var(--ggui-color-neutral-400, #9ca3af)',
};

export default function GeneratedComponent(props: Props) {
  const { elements = defaultElements } = props;
  const [search, setSearch] = useState('');
  const [selectedAtomicNumber, setSelectedAtomicNumber] = useState<number | undefined>(undefined);

  const normalizedSearch = search.trim().toLowerCase();

  const filteredElements = useMemo(() => {
    return elements.filter((el) => {
      const name = (el.name ?? '').toLowerCase();
      const symbol = (el.symbol ?? '').toLowerCase();
      if (!normalizedSearch) return true;
      return name.includes(normalizedSearch) || symbol.includes(normalizedSearch);
    });
  }, [elements, normalizedSearch]);

  const selectedElement = useMemo(() => {
    if (selectedAtomicNumber == null) return undefined;
    return elements.find((el) => el.atomicNumber === selectedAtomicNumber);
  }, [elements, selectedAtomicNumber]);

  const categories = useMemo(() => {
    const unique = new Set<string>();
    elements.forEach((el) => {
      unique.add((el.category ?? 'unknown').toLowerCase());
    });
    return Array.from(unique).sort();
  }, [elements]);

  return (
    <Card
      padding={20}
      shadow="sm"
      border
      radius="lg"
    >
      <Stack gap={16}>
        <Text
          variant="bodyLarge"
          weight="semibold"
          color="var(--ggui-color-onSurface, #18181b)"
        >
          Periodic Table of Elements
        </Text>

        <Input
          label="Search elements"
          type="search"
          placeholder="Search by name or symbol"
          value={search}
          onChange={setSearch}
          aria-label="Search elements by name or symbol"
        />

        <Card
          padding={12}
          border
          radius="md"
          shadow="none"
        >
          <div
            role="grid"
            aria-label="Periodic table grid"
            style={{
              display: 'grid',
              gridTemplateColumns: 'repeat(18, minmax(44px, 1fr))',
              gap: 'var(--ggui-spacing-1, 4px)',
              background: 'var(--ggui-color-surface, #fafafa)',
            }}
          >
            {filteredElements.map((element) => {
              const categoryKey = (element.category ?? 'unknown').toLowerCase();
              const color = categoryColorMap[categoryKey] ?? categoryColorMap.unknown;
              const key = `${element.atomicNumber ?? 'x'}-${element.symbol ?? 'unknown'}`;

              return (
                <Button
                  key={key}
                  variant="ghost"
                  size="sm"
                  onPress={() => setSelectedAtomicNumber(element.atomicNumber)}
                  aria-label={`Select ${element.name ?? 'Unknown'} (${element.symbol ?? ''})`}
                  style={{
                    gridColumn: String(element.col ?? 'auto'),
                    gridRow: String(element.row ?? 'auto'),
                    minHeight: 64,
                    padding: 'var(--ggui-spacing-1, 4px)',
                    border: `1px solid var(--ggui-color-outline, #d4d4d8)`,
                    borderRadius: 'var(--ggui-shape-radius-sm, 4px)',
                    background: selectedAtomicNumber === element.atomicNumber
                      ? 'var(--ggui-color-surfaceVariant, #f4f4f5)'
                      : 'var(--ggui-color-surface, #fafafa)',
                    color: 'var(--ggui-color-onSurface, #18181b)',
                    position: 'relative',
                    transition: 'background-color 200ms ease, transform 100ms ease',
                    boxShadow: `inset 0 0 0 2px ${color}`,
                  }}
                >
                  <span
                    style={{
                      position: 'absolute',
                      top: '4px',
                      left: '6px',
                      fontSize: 'var(--ggui-font-size-xs, 12px)',
                      color: 'var(--ggui-color-onSurfaceVariant, #52525b)',
                    }}
                  >
                    {element.atomicNumber ?? '—'}
                  </span>
                  <span
                    style={{
                      fontSize: 'var(--ggui-font-size-xl, 20px)',
                      fontWeight: 'var(--ggui-font-weight-semibold, 600)',
                      lineHeight: 1,
                    }}
                  >
                    {element.symbol ?? '?'}
                  </span>
                </Button>
              );
            })}
          </div>
        </Card>

        <Card padding={12} border radius="md" shadow="none">
          <Stack gap={8}>
            <Text variant="label" color="var(--ggui-color-onSurface, #18181b)">
              Element Details
            </Text>
            {selectedElement ? (
              <Stack gap={4}>
                <Text variant="body"><strong>Name:</strong> {selectedElement.name ?? '—'}</Text>
                <Text variant="body"><strong>Symbol:</strong> {selectedElement.symbol ?? '—'}</Text>
                <Text variant="body"><strong>Atomic Number:</strong> {selectedElement.atomicNumber ?? '—'}</Text>
                <Text variant="body"><strong>Atomic Weight:</strong> {selectedElement.atomicWeight ?? '—'}</Text>
                <Text variant="body"><strong>Category:</strong> {selectedElement.category ?? 'unknown'}</Text>
              </Stack>
            ) : (
              <Text variant="bodySmall" color="var(--ggui-color-onSurfaceVariant, #52525b)">
                Select an element to view details.
              </Text>
            )}
          </Stack>
        </Card>

        <Card padding={12} border radius="md" shadow="none">
          <Stack gap={8}>
            <Text variant="label" color="var(--ggui-color-onSurface, #18181b)">
              Legend
            </Text>
            <Stack direction="horizontal" wrap gap={8}>
              {categories.map((category) => {
                const color = categoryColorMap[category] ?? categoryColorMap.unknown;
                return (
                  <span
                    key={category}
                    style={{
                      display: 'inline-flex',
                      alignItems: 'center',
                      gap: 'var(--ggui-spacing-1, 4px)',
                      padding: '2px 8px',
                      borderRadius: 'var(--ggui-shape-radius-full, 9999px)',
                      border: `1px solid var(--ggui-color-outline, #d4d4d8)`,
                      background: 'var(--ggui-color-surfaceVariant, #f4f4f5)',
                    }}
                  >
                    <span
                      aria-hidden="true"
                      style={{
                        width: 10,
                        height: 10,
                        borderRadius: '50%',
                        background: color,
                      }}
                    />
                    <Text variant="caption" as="span" color="var(--ggui-color-onSurface, #18181b)">
                      {category}
                    </Text>
                  </span>
                );
              })}
            </Stack>
          </Stack>
        </Card>
      </Stack>
    </Card>
  );
}

import React, { useEffect, useMemo, useRef, useState } from 'react';
import { Card, Stack, Text, Button, Input, Badge, Box } from '@ggui-ai/design/primitives';

interface Props {
  /** Chat window title */
  title: string;
  /** Current user name (for right-aligning own messages) */
  currentUser: string;
  /** Number of participants */
  participantCount?: number;
  /** Array of messages with sender name, text, and ISO timestamp */
  messages: Array<{ sender?: string; text?: string; timestamp?: string }>;
  /** Action Contract: send outgoing message payload */
  sendMessage?: (payload: { text: string; timestamp: string }) => void;
}

export default function GeneratedComponent(props: Props) {
  const {
    title = 'Chat',
    currentUser = '',
    participantCount,
    messages = [],
    sendMessage,
  } = props;

  const [draft, setDraft] = useState<string>('');
  const [streamMessages, setStreamMessages] = useState<Array<{ sender?: string; text?: string; timestamp?: string }>>([]);
  const listRef = useRef<HTMLDivElement | null>(null);

  const allMessages = useMemo(() => [...messages, ...streamMessages], [messages, streamMessages]);

  const scrollToBottom = () => {
    if (listRef.current) {
      listRef.current.scrollTop = listRef.current.scrollHeight;
    }
  };

  useEffect(() => {
    scrollToBottom();
  }, []);

  useEffect(() => {
    scrollToBottom();
  }, [allMessages.length]);

  useEffect(() => {
    const handler = (event: Event) => {
      const customEvent = event as CustomEvent<{ sender?: string; text?: string; timestamp?: string }>;
      const incoming = customEvent.detail;
      if (incoming && (incoming.text || incoming.sender || incoming.timestamp)) {
        setStreamMessages((prev) => [...prev, incoming]);
      }
    };

    window.addEventListener('ggui:agent-data', handler as EventListener);
    return () => window.removeEventListener('ggui:agent-data', handler as EventListener);
  }, []);

  const formatTimestamp = (value?: string) => {
    if (!value) return '';
    const parsed = new Date(value);
    if (Number.isNaN(parsed.getTime())) return value;
    return parsed.toLocaleTimeString([], { hour: '2-digit', minute: '2-digit' });
  };

  const handleSend = () => {
    const text = draft.trim();
    if (!text) return;
    const payload = { text, timestamp: new Date().toISOString() };
    sendMessage?.(payload);
    setDraft('');
  };

  return (
    <Card
      padding={0}
      radius="lg"
      shadow="sm"
      border
      style={{
        background: 'var(--ggui-color-surface, #fafafa)',
        color: 'var(--ggui-color-onSurface, #18181b)',
        borderColor: 'var(--ggui-color-outline, #d4d4d8)',
        height: '100%',
        minHeight: '420px',
      }}
    >
      <Stack gap={0} style={{ height: '100%' }}>
        <Stack
          direction="horizontal"
          justify="between"
          align="center"
          style={{
            padding: 'var(--ggui-spacing-4, 16px)',
            borderBottom: '1px solid var(--ggui-color-outline, #d4d4d8)',
            background: 'var(--ggui-color-surfaceVariant, #f4f4f5)',
          }}
        >
          <Text variant="label" color="var(--ggui-color-onSurface, #18181b)">
            {title}
          </Text>
          {typeof participantCount === 'number' && (
            <Badge variant="primary" size="sm">
              {participantCount}
            </Badge>
          )}
        </Stack>

        <Box
          padding={0}
          style={{
            flex: 1,
            minHeight: 0,
            overflowY: 'auto',
            padding: 'var(--ggui-spacing-4, 16px)',
          }}
          ref={listRef as unknown as React.Ref<HTMLDivElement>}
          aria-label="Message list"
        >
          <Stack gap={8}>
            {allMessages.map((message, index) => {
              const sender = message.sender || 'Unknown';
              const isMine = sender === currentUser;
              const previousSender = index > 0 ? allMessages[index - 1]?.sender : undefined;
              const showSenderHeader = sender !== previousSender;

              return (
                <Stack
                  key={`${sender}-${message.timestamp || index}-${index}`}
                  align={isMine ? 'end' : 'start'}
                  gap={4}
                  style={{
                    marginTop: showSenderHeader ? 'var(--ggui-spacing-2, 8px)' : '0',
                  }}
                >
                  {showSenderHeader && (
                    <Text variant="caption" color="var(--ggui-color-onSurfaceVariant, #52525b)">
                      {sender}
                    </Text>
                  )}
                  <Card
                    padding="var(--ggui-spacing-2, 8px) var(--ggui-spacing-4, 16px)"
                    radius="lg"
                    border={false}
                    shadow="none"
                    style={{
                      maxWidth: '75%',
                      background: isMine
                        ? 'var(--ggui-color-primary-600, #0284c7)'
                        : 'var(--ggui-color-surfaceVariant, #f4f4f5)',
                      color: isMine ? 'var(--ggui-color-surface, #fafafa)' : 'var(--ggui-color-onSurface, #18181b)',
                    }}
                  >
                    <Stack gap={4}>
                      <Text
                        variant="bodySmall"
                        color={isMine ? 'var(--ggui-color-surface, #fafafa)' : 'var(--ggui-color-onSurface, #18181b)'}
                      >
                        {message.text || ''}
                      </Text>
                      <Text
                        variant="caption"
                        color={isMine ? 'var(--ggui-color-primary-100, #e0f2fe)' : 'var(--ggui-color-onSurfaceVariant, #52525b)'}
                        align="right"
                      >
                        {formatTimestamp(message.timestamp)}
                      </Text>
                    </Stack>
                  </Card>
                </Stack>
              );
            })}
          </Stack>
        </Box>

        <Stack
          direction="horizontal"
          gap={8}
          align="end"
          style={{
            padding: 'var(--ggui-spacing-4, 16px)',
            borderTop: '1px solid var(--ggui-color-outline, #d4d4d8)',
            background: 'var(--ggui-color-surface, #fafafa)',
          }}
        >
          <Box style={{ flex: 1 }}>
            <Input
              label=""
              placeholder="Type a message..."
              value={draft}
              onChange={setDraft}
              aria-label="Compose message"
              onKeyDown={(e) => {
                if (e.key === 'Enter') {
                  e.preventDefault();
                  handleSend();
                }
              }}
            />
          </Box>
          <Button
            variant="primary"
            size="md"
            onClick={handleSend}
            disabled={!draft.trim()}
            aria-label="Send message"
          >
            Send
          </Button>
        </Stack>
      </Stack>
    </Card>
  );
}

import React, { useEffect, useMemo, useState } from 'react';
import { Card, Stack, Text, Spinner } from '@ggui-ai/design/primitives';
import { CardGrid } from '@ggui-ai/design/compositions';

interface Props {
  /** Array of stocks with symbol, name, price, change, changePercent */
  stocks: Array<{ symbol?: string; name?: string; price?: number; change?: number; changePercent?: number }>;
  /** ISO timestamp of last price update */
  lastUpdated?: string;
}

export default function GeneratedComponent(props: Props) {
  const [liveStocks, setLiveStocks] = useState<Props['stocks']>(props.stocks ?? []);
  const [liveLastUpdated, setLiveLastUpdated] = useState<string | undefined>(props.lastUpdated);
  const [isConnecting, setIsConnecting] = useState(true);

  useEffect(() => {
    setLiveStocks(props.stocks ?? []);
  }, [props.stocks]);

  useEffect(() => {
    setLiveLastUpdated(props.lastUpdated);
  }, [props.lastUpdated]);

  useEffect(() => {
    let connectionTimeout: number | undefined;
    setIsConnecting(true);

    connectionTimeout = window.setTimeout(() => {
      setIsConnecting(false);
    }, 1200);

    const handleAgentData = (event: Event) => {
      const customEvent = event as CustomEvent<Partial<Props>>;
      const payload = customEvent.detail;

      if (payload?.stocks && Array.isArray(payload.stocks)) {
        setLiveStocks(payload.stocks);
      }
      if (typeof payload?.lastUpdated === 'string') {
        setLiveLastUpdated(payload.lastUpdated);
      } else {
        setLiveLastUpdated(new Date().toISOString());
      }

      setIsConnecting(false);
      if (connectionTimeout) {
        window.clearTimeout(connectionTimeout);
      }
    };

    window.addEventListener('ggui:agent-data', handleAgentData as EventListener);

    return () => {
      if (connectionTimeout) {
        window.clearTimeout(connectionTimeout);
      }
      window.removeEventListener('ggui:agent-data', handleAgentData as EventListener);
    };
  }, []);

  const formattedLastUpdated = useMemo(() => {
    if (!liveLastUpdated) return '—';
    const date = new Date(liveLastUpdated);
    if (Number.isNaN(date.getTime())) return liveLastUpdated;
    return date.toLocaleString();
  }, [liveLastUpdated]);

  const hasStocks = liveStocks.length > 0;

  return (
    <Card
      padding="var(--ggui-spacing-6, 24px)"
      shadow="sm"
      border
      radius="lg"
      style={{
        background: 'var(--ggui-color-surface, #fafafa)',
        borderColor: 'var(--ggui-color-outline, #d4d4d8)',
      }}
      aria-label="Stock ticker dashboard"
    >
      <Stack gap="var(--ggui-spacing-6, 24px)">
        <Stack direction="horizontal" justify="between" align="center">
          <Text
            as="div"
            size="2xl"
            weight="bold"
            color="var(--ggui-color-onSurface, #18181b)"
            aria-label="Market Watch"
          >
            Market Watch
          </Text>
          <Stack gap={2} align="end">
            <Text
              variant="caption"
              color="var(--ggui-color-onSurfaceVariant, #52525b)"
              aria-label="Last Updated label"
            >
              Last Updated
            </Text>
            <Text
              variant="label"
              color="var(--ggui-color-onSurface, #18181b)"
              aria-live="polite"
              aria-label={`Last updated at ${formattedLastUpdated}`}
            >
              {formattedLastUpdated}
            </Text>
          </Stack>
        </Stack>

        {isConnecting ? (
          <Card
            border
            shadow="none"
            padding="var(--ggui-spacing-6, 24px)"
            radius="md"
            style={{
              background: 'var(--ggui-color-surfaceVariant, #f4f4f5)',
              borderColor: 'var(--ggui-color-outline, #d4d4d8)',
            }}
            aria-live="polite"
            aria-busy="true"
          >
            <Stack direction="horizontal" align="center" gap="var(--ggui-spacing-2, 8px)">
              <Spinner size={18} color="var(--ggui-color-primary-600, #0284c7)" />
              <Text variant="bodySmall" color="var(--ggui-color-onSurfaceVariant, #52525b)">
                Connecting to live market feed…
              </Text>
            </Stack>
          </Card>
        ) : null}

        {!hasStocks && !isConnecting ? (
          <Card
            border
            shadow="none"
            padding="var(--ggui-spacing-6, 24px)"
            radius="md"
            style={{
              background: 'var(--ggui-color-surfaceVariant, #f4f4f5)',
              borderColor: 'var(--ggui-color-outline, #d4d4d8)',
            }}
            aria-live="polite"
          >
            <Text color="var(--ggui-color-onSurfaceVariant, #52525b)">
              No stock data available.
            </Text>
          </Card>
        ) : null}

        {hasStocks ? (
          <CardGrid columns={{ sm: 1, lg: 3 }} gap={16}>
            {liveStocks.map((stock, index) => {
              const price = typeof stock.price === 'number' ? stock.price : 0;
              const change = typeof stock.change === 'number' ? stock.change : 0;
              const changePercent = typeof stock.changePercent === 'number' ? stock.changePercent : 0;

              const isPositive = change >= 0;
              const trendColor = isPositive
                ? 'var(--ggui-color-success-600, #16a34a)'
                : 'var(--ggui-color-error-600, #dc2626)';
              const trendArrow = isPositive ? '▲' : '▼';

              const symbol = stock.symbol ?? '—';
              const name = stock.name ?? 'Unknown Company';

              return (
                <Card
                  key={`${symbol}-${name}-${index}`}
                  padding="var(--ggui-spacing-4, 16px)"
                  shadow="sm"
                  border
                  radius="md"
                  style={{
                    background: 'var(--ggui-color-surfaceVariant, #f4f4f5)',
                    borderColor: trendColor,
                    transition:
                      'transform 200ms ease, box-shadow 200ms ease, border-color 200ms ease',
                  }}
                  aria-label={`Stock card for ${symbol}`}
                >
                  <Stack gap="var(--ggui-spacing-2, 8px)">
                    <Text
                      as="div"
                      size="3xl"
                      weight="bold"
                      color="var(--ggui-color-onSurface, #18181b)"
                    >
                      {symbol}
                    </Text>

                    <Text
                      variant="bodySmall"
                      color="var(--ggui-color-onSurfaceVariant, #52525b)"
                      truncate
                      aria-label={`Company name ${name}`}
                    >
                      {name}
                    </Text>

                    <Text
                      as="div"
                      size="xl"
                      weight="semibold"
                      color="var(--ggui-color-onSurface, #18181b)"
                      aria-label={`Current price ${price.toFixed(2)}`}
                    >
                      ${price.toFixed(2)}
                    </Text>

                    <Stack direction="horizontal" justify="between" align="center">
                      <Text
                        variant="label"
                        color={trendColor}
                        aria-label={`Change amount ${change >= 0 ? '+' : ''}${change.toFixed(2)}`}
                      >
                        {change >= 0 ? '+' : ''}
                        {change.toFixed(2)}
                      </Text>
                      <Text
                        variant="label"
                        color={trendColor}
                        aria-label={`Change percentage ${changePercent.toFixed(2)} percent`}
                      >
                        <span aria-hidden="true" style={{ marginRight: 'var(--ggui-spacing-1, 4px)' }}>
                          {trendArrow}
                        </span>
                        {changePercent >= 0 ? '+' : ''}
                        {changePercent.toFixed(2)}%
                      </Text>
                    </Stack>
                  </Stack>
                </Card>
              );
            })}
          </CardGrid>
        ) : null}
      </Stack>
    </Card>
  );
}

import React, { useMemo, useState } from 'react';
import {
  Card,
  Stack,
  Text,
  Button,
  Input,
  Select,
  Toggle,
  Progress,
  MotionKeyframes,
} from '@ggui-ai/design/primitives';

interface Props {
  /** Pre-filled profile data for editing (all fields optional) */
  initialProfile?: {
    name?: string;
    email?: string;
    avatar?: string;
    role?: string;
    emailNotifications?: boolean;
    theme?: string;
  };
  /** Available avatar emojis to choose from */
  avatarOptions: string[];
  /** Available role options for the dropdown */
  roleOptions: string[];
  /** Complete Setup callback */
  onComplete?: (data: {
    name: string;
    email: string;
    avatar: string;
    role: string;
    emailNotifications: boolean;
    theme: string;
  }) => void;
}

export default function GeneratedComponent({
  initialProfile = {
    name: '',
    email: '',
    avatar: '',
    role: '',
    emailNotifications: true,
    theme: 'light',
  },
  avatarOptions = ['😀', '🚀', '🎨', '🧠'],
  roleOptions = ['Developer', 'Designer', 'Manager', 'Other'],
  onComplete,
}: Props) {
  const [step, setStep] = useState<number>(1);

  const [name, setName] = useState<string>(initialProfile.name ?? '');
  const [email, setEmail] = useState<string>(initialProfile.email ?? '');
  const [avatar, setAvatar] = useState<string>(
    initialProfile.avatar ?? avatarOptions[0] ?? ''
  );
  const [role, setRole] = useState<string>(initialProfile.role ?? '');
  const [emailNotifications, setEmailNotifications] = useState<boolean>(
    initialProfile.emailNotifications ?? true
  );
  const [theme, setTheme] = useState<string>(initialProfile.theme ?? 'light');

  const emailValid = useMemo(
    () => /^[^\s@]+@[^\s@]+\.[^\s@]+$/.test(email.trim()),
    [email]
  );

  const step1Valid = name.trim().length > 0 && emailValid && avatar.trim().length > 0;
  const step2Valid = role.trim().length > 0;
  const canNext = (step === 1 && step1Valid) || (step === 2 && step2Valid);

  const handleNext = () => {
    if (step < 3 && canNext) setStep(step + 1);
  };

  const handleBack = () => {
    if (step > 1) setStep(step - 1);
  };

  const handleComplete = () => {
    if (!step1Valid || !step2Valid) return;
    onComplete?.({
      name: name.trim(),
      email: email.trim(),
      avatar,
      role,
      emailNotifications,
      theme,
    });
  };

  return (
    <Card
      padding={24}
      shadow="md"
      radius="lg"
      border
      style={{
        background: 'var(--ggui-color-surface, #fafafa)',
        borderColor: 'var(--ggui-color-outline, #d4d4d8)',
      }}
    >
      <MotionKeyframes />
      <Stack gap={20}>
        <Stack gap={8}>
          <Text
            variant="label"
            color="var(--ggui-color-onSurface, #18181b)"
            as="div"
            aria-live="polite"
          >
            Step {step} of 3
          </Text>
          <Progress value={step} max={3} size="md" />
        </Stack>

        <Stack
          gap={16}
          style={{
            animation: 'ggui-fadeIn 200ms ease-out',
            transition: 'all 200ms ease-in-out',
          }}
        >
          {step === 1 && (
            <Stack gap={16}>
              <Text variant="bodyLarge" weight="semibold" color="var(--ggui-color-onSurface, #18181b)">
                Profile Setup
              </Text>

              <Input
                label="Name"
                value={name}
                onChange={setName}
                required
                placeholder="Enter your name"
                error={name.trim().length === 0 ? 'Name is required' : ''}
                aria-label="Name"
              />

              <Input
                label="Email"
                type="email"
                value={email}
                onChange={setEmail}
                required
                placeholder="Enter your email"
                error={
                  email.trim().length === 0
                    ? 'Email is required'
                    : !emailValid
                    ? 'Please enter a valid email'
                    : ''
                }
                aria-label="Email"
              />

              <Stack gap={8}>
                <Text variant="label" color="var(--ggui-color-onSurface, #18181b)">
                  Avatar
                </Text>
                <Stack direction="horizontal" gap={8} wrap>
                  {avatarOptions.map((emoji) => {
                    const selected = avatar === emoji;
                    return (
                      <Button
                        key={emoji}
                        variant={selected ? 'primary' : 'outline'}
                        size="sm"
                        onClick={() => setAvatar(emoji)}
                        aria-label={`Select avatar ${emoji}`}
                      >
                        {emoji}
                      </Button>
                    );
                  })}
                </Stack>
              </Stack>
            </Stack>
          )}

          {step === 2 && (
            <Stack gap={16}>
              <Text variant="bodyLarge" weight="semibold" color="var(--ggui-color-onSurface, #18181b)">
                Preferences
              </Text>

              <Select
                label="Role"
                value={role}
                onChange={setRole}
                options={roleOptions.map((r) => ({ value: r, label: r }))}
                placeholder="Select role"
                error={role.trim().length === 0 ? 'Role is required' : ''}
                aria-label="Role"
              />

              <Toggle
                label="Email notifications"
                checked={emailNotifications}
                onChange={setEmailNotifications}
                size="md"
              />

              <Toggle
                label={`Theme preference (${theme})`}
                checked={theme === 'dark'}
                onChange={(checked) => setTheme(checked ? 'dark' : 'light')}
                size="md"
              />
            </Stack>
          )}

          {step === 3 && (
            <Stack gap={12}>
              <Text variant="bodyLarge" weight="semibold" color="var(--ggui-color-onSurface, #18181b)">
                Review & Confirm
              </Text>

              <Card
                padding={16}
                shadow="none"
                border
                radius="md"
                style={{
                  background: 'var(--ggui-color-surfaceVariant, #f4f4f5)',
                  borderColor: 'var(--ggui-color-outlineVariant, #e4e4e7)',
                }}
              >
                <Stack gap={8}>
                  <Text variant="body"><strong>Name:</strong> {name}</Text>
                  <Text variant="body"><strong>Email:</strong> {email}</Text>
                  <Text variant="body"><strong>Avatar:</strong> {avatar}</Text>
                  <Text variant="body"><strong>Role:</strong> {role}</Text>
                  <Text variant="body">
                    <strong>Email Notifications:</strong> {emailNotifications ? 'On' : 'Off'}
                  </Text>
                  <Text variant="body"><strong>Theme:</strong> {theme}</Text>
                </Stack>
              </Card>
            </Stack>
          )}
        </Stack>

        <Stack direction="horizontal" justify="between" align="center">
          <Button
            variant="ghost"
            onClick={handleBack}
            disabled={step === 1}
            aria-label="Go back"
          >
            Back
          </Button>

          <Stack direction="horizontal" gap={8}>
            {step < 3 ? (
              <Button
                variant="primary"
                onClick={handleNext}
                disabled={!canNext}
                aria-label="Go to next step"
              >
                Next
              </Button>
            ) : (
              <>
                <Button variant="outline" onClick={handleBack} aria-label="Edit previous steps">
                  Go Back
                </Button>
                <Button
                  variant="primary"
                  onClick={handleComplete}
                  aria-label="Complete setup"
                >
                  Complete Setup
                </Button>
              </>
            )}
          </Stack>
        </Stack>
      </Stack>
    </Card>
  );
}

