import React, { useMemo, useState } from 'react';
import {
  Card,
  Stack,
  Text,
  Button,
  Input,
  RadioGroup,
  Checkbox,
  TextArea,
  Progress,
  Alert,
} from '@ggui-ai/design/primitives';

interface Props {
  /** Available feature options for the checkbox step */
  featureOptions: string[];
  /** Labels for satisfaction rating (e.g., Very Unsatisfied to Very Satisfied) */
  satisfactionLabels: string[];
  /** Submit Survey — called with all collected answers as a structured object */
  submit?: (answers: {
    name: string;
    email: string;
    satisfactionRating: number;
    satisfactionLabel: string;
    featureInterests: string[];
    comments: string;
  }) => Promise<void> | void;
}

const defaultProps: Props = {
  featureOptions: ['Feature A', 'Feature B', 'Feature C'],
  satisfactionLabels: ['Very Unsatisfied', 'Unsatisfied', 'Neutral', 'Satisfied', 'Very Satisfied'],
  submit: async () => {},
};

export default function GeneratedComponent(props: Props) {
  const {
    featureOptions = defaultProps.featureOptions,
    satisfactionLabels = defaultProps.satisfactionLabels,
    submit = defaultProps.submit,
  } = props;

  const [step, setStep] = useState<number>(1); // 1..5 (5 = final review)
  const [name, setName] = useState<string>('');
  const [email, setEmail] = useState<string>('');
  const [satisfactionValue, setSatisfactionValue] = useState<string>('');
  const [featureInterests, setFeatureInterests] = useState<string[]>([]);
  const [comments, setComments] = useState<string>('');
  const [touched, setTouched] = useState<Record<string, boolean>>({});
  const [submitting, setSubmitting] = useState<boolean>(false);
  const [feedback, setFeedback] = useState<{ type: 'success' | 'error'; message: string } | null>(null);

  const totalSteps = 5; // includes final review step

  const emailRegex = /^[^\s@]+@[^\s@]+\.[^\s@]+$/;
  const nameError = touched.name && !name.trim() ? 'Name is required.' : '';
  const emailError =
    touched.email && !email.trim()
      ? 'Email is required.'
      : touched.email && !emailRegex.test(email)
      ? 'Enter a valid email address.'
      : '';

  const ratingOptions = useMemo(
    () =>
      satisfactionLabels.map((label, index) => ({
        value: String(index + 1),
        label: `${index + 1} - ${label}`,
      })),
    [satisfactionLabels]
  );

  const isStepValid = useMemo(() => {
    if (step === 1) return !!name.trim() && emailRegex.test(email);
    if (step === 2) return !!satisfactionValue;
    if (step === 3) return true;
    if (step === 4) return comments.length <= 500;
    return true;
  }, [step, name, email, satisfactionValue, comments]);

  const progressValue = Math.round((step / totalSteps) * 100);

  const toggleFeature = (option: string, checked: boolean) => {
    setFeatureInterests((prev) =>
      checked ? Array.from(new Set([...prev, option])) : prev.filter((item) => item !== option)
    );
  };

  const onNext = () => {
    if (step === 1) {
      setTouched((t) => ({ ...t, name: true, email: true }));
      if (!name.trim() || !emailRegex.test(email)) return;
    }
    if (step < totalSteps) setStep((s) => s + 1);
  };

  const onBack = () => {
    if (step > 1) setStep((s) => s - 1);
  };

  const handleSubmit = async () => {
    setFeedback(null);
    setSubmitting(true);
    try {
      const ratingNumber = Number(satisfactionValue || 0);
      const payload = {
        name: name.trim(),
        email: email.trim(),
        satisfactionRating: ratingNumber,
        satisfactionLabel: satisfactionLabels[ratingNumber - 1] || '',
        featureInterests,
        comments: comments.trim(),
      };
      await submit?.(payload);
      setFeedback({ type: 'success', message: 'Survey submitted successfully.' });
    } catch (error) {
      setFeedback({ type: 'error', message: 'Submission failed. Please try again.' });
    } finally {
      setSubmitting(false);
    }
  };

  return (
    <Card
      padding={24}
      shadow="md"
      radius="lg"
      style={{
        background: 'var(--ggui-color-surface, #fafafa)',
        borderColor: 'var(--ggui-color-outline, #d4d4d8)',
        color: 'var(--ggui-color-onSurface, #18181b)',
      }}
    >
      <Stack gap={16}>
        <Stack gap={8}>
          <Text variant="label" color="var(--ggui-color-onSurface, #18181b)">
            Step {step} of {totalSteps}
          </Text>
          <Progress value={progressValue} max={100} size="md" variant="default" />
        </Stack>

        {feedback && (
          <Alert variant={feedback.type === 'success' ? 'success' : 'error'} title={feedback.type === 'success' ? 'Success' : 'Error'}>
            {feedback.message}
          </Alert>
        )}

        {step === 1 && (
          <Stack gap={12}>
            <Text variant="bodyLarge" weight="semibold" color="var(--ggui-color-onSurface, #18181b)">
              Contact Information
            </Text>
            <Input
              label="Name"
              value={name}
              onChange={setName}
              required
              error={nameError || undefined}
              placeholder="Enter your name"
              onBlur={() => setTouched((t) => ({ ...t, name: true }))}
              aria-label="Name"
            />
            <Input
              label="Email"
              type="email"
              value={email}
              onChange={setEmail}
              required
              error={emailError || undefined}
              placeholder="Enter your email"
              onBlur={() => setTouched((t) => ({ ...t, email: true }))}
              aria-label="Email"
            />
          </Stack>
        )}

        {step === 2 && (
          <Stack gap={12}>
            <Text variant="bodyLarge" weight="semibold" color="var(--ggui-color-onSurface, #18181b)">
              Satisfaction Rating
            </Text>
            <RadioGroup
              label="How satisfied are you?"
              value={satisfactionValue}
              onChange={setSatisfactionValue}
              options={ratingOptions}
              direction="vertical"
            />
          </Stack>
        )}

        {step === 3 && (
          <Stack gap={12}>
            <Text variant="bodyLarge" weight="semibold" color="var(--ggui-color-onSurface, #18181b)">
              Feature Interests
            </Text>
            <Text variant="bodySmall" color="var(--ggui-color-onSurfaceVariant, #52525b)">
              Select all that apply
            </Text>
            <Stack gap={8}>
              {featureOptions.map((option) => (
                <Checkbox
                  key={option}
                  label={option}
                  checked={featureInterests.includes(option)}
                  onChange={(checked) => toggleFeature(option, checked)}
                />
              ))}
            </Stack>
          </Stack>
        )}

        {step === 4 && (
          <Stack gap={12}>
            <Text variant="bodyLarge" weight="semibold" color="var(--ggui-color-onSurface, #18181b)">
              Additional Comments
            </Text>
            <TextArea
              label="Comments (optional)"
              value={comments}
              onChange={setComments}
              rows={6}
              maxLength={500}
              showCount
              placeholder="Share anything else..."
              helperText="Maximum 500 characters"
            />
          </Stack>
        )}

        {step === 5 && (
          <Stack gap={12}>
            <Text variant="bodyLarge" weight="semibold" color="var(--ggui-color-onSurface, #18181b)">
              Review Your Answers
            </Text>
            <Card
              padding={16}
              shadow="none"
              radius="md"
              style={{
                background: 'var(--ggui-color-surfaceVariant, #f4f4f5)',
                borderColor: 'var(--ggui-color-outline, #d4d4d8)',
              }}
            >
              <Stack gap={8}>
                <Text variant="body"><strong>Name:</strong> {name || '-'}</Text>
                <Text variant="body"><strong>Email:</strong> {email || '-'}</Text>
                <Text variant="body">
                  <strong>Satisfaction:</strong>{' '}
                  {satisfactionValue
                    ? `${satisfactionValue} - ${satisfactionLabels[Number(satisfactionValue) - 1] || ''}`
                    : '-'}
                </Text>
                <Text variant="body">
                  <strong>Feature Interests:</strong>{' '}
                  {featureInterests.length ? featureInterests.join(', ') : 'None selected'}
                </Text>
                <Text variant="body">
                  <strong>Comments:</strong> {comments.trim() ? comments : 'No comments'}
                </Text>
              </Stack>
            </Card>
          </Stack>
        )}

        <Stack direction="horizontal" justify="between" align="center" gap={12}>
          <Button variant="ghost" onClick={onBack} disabled={step === 1 || submitting}>
            Back
          </Button>

          {step < totalSteps ? (
            <Button variant="primary" onClick={onNext} disabled={!isStepValid || submitting}>
              Next
            </Button>
          ) : (
            <Button variant="primary" onClick={handleSubmit} loading={submitting} disabled={submitting}>
              Submit Survey
            </Button>
          )}
        </Stack>
      </Stack>
    </Card>
  );
}

import React, { useMemo, useState } from 'react';
import { Card, Stack, Text, Input, Button } from '@ggui-ai/design/primitives';

interface Props {
  /** Full periodic table element data */
  elements: Array<{
    atomicNumber?: number;
    symbol?: string;
    name?: string;
    atomicWeight?: number;
    category?: string;
    row?: number;
    col?: number;
  }>;
}

export default function GeneratedComponent(props: Props) {
  const { elements = [] } = props;
  const [query, setQuery] = useState<string>('');
  const [selectedAtomicNumber, setSelectedAtomicNumber] = useState<number | undefined>(undefined);

  const categoryColorMap = useMemo<Record<string, string>>(
    () => ({
      'alkali metal': 'var(--ggui-color-error-500, #ef4444)',
      'alkaline earth metal': 'var(--ggui-color-warning-500, #f59e0b)',
      'transition metal': 'var(--ggui-color-primary-500, #0ea5e9)',
      'post-transition metal': 'var(--ggui-color-info-500, #06b6d4)',
      metalloid: 'var(--ggui-color-success-500, #22c55e)',
      nonmetal: 'var(--ggui-color-success-600, #16a34a)',
      halogen: 'var(--ggui-color-warning-600, #d97706)',
      'noble gas': 'var(--ggui-color-primary-600, #0284c7)',
      lanthanide: 'var(--ggui-color-primary-400, #38bdf8)',
      actinide: 'var(--ggui-color-error-600, #dc2626)',
      unknown: 'var(--ggui-color-neutral-400, #9ca3af)',
    }),
    []
  );

  const normalizedQuery = query.trim().toLowerCase();

  const filteredElements = useMemo(
    () =>
      elements.filter((el) => {
        const name = (el.name ?? '').toLowerCase();
        const symbol = (el.symbol ?? '').toLowerCase();
        return !normalizedQuery || name.includes(normalizedQuery) || symbol.includes(normalizedQuery);
      }),
    [elements, normalizedQuery]
  );

  const selectedElement = useMemo(() => {
    if (selectedAtomicNumber === undefined) return undefined;
    return elements.find((el) => el.atomicNumber === selectedAtomicNumber);
  }, [elements, selectedAtomicNumber]);

  const categories = useMemo(() => {
    const set = new Set<string>();
    elements.forEach((el) => {
      set.add((el.category ?? 'unknown').toLowerCase());
    });
    return Array.from(set).sort((a, b) => a.localeCompare(b));
  }, [elements]);

  return (
    <Card
      padding={16}
      border
      shadow="sm"
      radius="lg"
      style={{
        background: 'var(--ggui-color-surface, #fafafa)',
        borderColor: 'var(--ggui-color-outline, #d4d4d8)',
      }}
    >
      <Stack gap={16}>
        <Text
          variant="bodyLarge"
          weight="semibold"
          color="var(--ggui-color-onSurface, #18181b)"
        >
          Periodic Table of Elements
        </Text>

        <Input
          label="Search elements"
          type="search"
          value={query}
          onChange={setQuery}
          placeholder="Search by name or symbol"
          aria-label="Search elements by name or symbol"
          helperText="Type to filter elements"
        />

        <Card
          padding={12}
          border
          shadow="none"
          radius="md"
          style={{
            background: 'var(--ggui-color-surfaceVariant, #f4f4f5)',
            borderColor: 'var(--ggui-color-outline, #d4d4d8)',
          }}
        >
          <Stack gap={10}>
            <Text
              variant="label"
              color="var(--ggui-color-onSurface, #18181b)"
            >
              Legend
            </Text>
            <Stack direction="horizontal" wrap gap={8}>
              {categories.map((category) => {
                const color = categoryColorMap[category] ?? categoryColorMap.unknown;
                return (
                  <Stack key={category} direction="horizontal" align="center" gap={6}>
                    <span
                      aria-hidden="true"
                      style={{
                        width: 12,
                        height: 12,
                        borderRadius: 'var(--ggui-shape-radius-sm, 4px)',
                        background: color,
                        border: '1px solid var(--ggui-color-outline, #d4d4d8)',
                      }}
                    />
                    <Text variant="caption" color="var(--ggui-color-onSurfaceVariant, #52525b)">
                      {category}
                    </Text>
                  </Stack>
                );
              })}
            </Stack>
          </Stack>
        </Card>

        <Card
          padding={12}
          border
          shadow="none"
          radius="md"
          style={{
            background: 'var(--ggui-color-surface, #fafafa)',
            borderColor: 'var(--ggui-color-outline, #d4d4d8)',
          }}
        >
          <div
            role="grid"
            aria-label="Periodic table grid"
            style={{
              display: 'grid',
              gridTemplateColumns: 'repeat(18, minmax(42px, 1fr))',
              gap: 'var(--ggui-spacing-1, 4px)',
            }}
          >
            {filteredElements.map((el) => {
              const category = (el.category ?? 'unknown').toLowerCase();
              const color = categoryColorMap[category] ?? categoryColorMap.unknown;
              const isSelected = selectedAtomicNumber !== undefined && el.atomicNumber === selectedAtomicNumber;

              return (
                <Button
                  key={`${el.atomicNumber ?? 'x'}-${el.symbol ?? 'unknown'}`}
                  variant={isSelected ? 'primary' : 'ghost'}
                  size="sm"
                  onClick={() => setSelectedAtomicNumber(el.atomicNumber)}
                  aria-label={`Select ${el.name ?? 'Unknown'} (${el.symbol ?? ''})`}
                  style={{
                    gridColumn: `${el.col ?? 1}`,
                    gridRow: `${el.row ?? 1}`,
                    minHeight: 56,
                    padding: 0,
                    border: `1px solid ${isSelected ? 'var(--ggui-color-primary-600, #0284c7)' : 'var(--ggui-color-outline, #d4d4d8)'}`,
                    borderRadius: 'var(--ggui-shape-radius-sm, 4px)',
                    background: isSelected ? 'var(--ggui-color-container, #ede9fe)' : 'var(--ggui-color-surfaceVariant, #f4f4f5)',
                    color: 'var(--ggui-color-onSurface, #18181b)',
                    position: 'relative',
                    overflow: 'hidden',
                    transition: 'transform 200ms ease, box-shadow 200ms ease, border-color 200ms ease',
                    boxShadow: isSelected ? 'var(--ggui-shape-shadow-sm, 0 1px 2px rgba(0,0,0,0.05))' : 'none',
                  }}
                >
                  <span
                    aria-hidden="true"
                    style={{
                      position: 'absolute',
                      left: 0,
                      top: 0,
                      bottom: 0,
                      width: 4,
                      background: color,
                    }}
                  />
                  <span
                    style={{
                      position: 'absolute',
                      top: 4,
                      left: 6,
                      fontSize: 'var(--ggui-font-size-xs, 12px)',
                      color: 'var(--ggui-color-onSurfaceVariant, #52525b)',
                      lineHeight: 1,
                    }}
                  >
                    {el.atomicNumber ?? '-'}
                  </span>
                  <span
                    style={{
                      fontSize: 'var(--ggui-font-size-lg, 18px)',
                      fontWeight: 'var(--ggui-font-weight-semibold, 600)',
                      textAlign: 'center',
                      width: '100%',
                      display: 'block',
                    }}
                  >
                    {el.symbol ?? '?'}
                  </span>
                </Button>
              );
            })}
          </div>
        </Card>

        <Card
          padding={14}
          border
          shadow="sm"
          radius="md"
          style={{
            background: 'var(--ggui-color-surfaceVariant, #f4f4f5)',
            borderColor: 'var(--ggui-color-outline, #d4d4d8)',
          }}
        >
          {selectedElement ? (
            <Stack gap={6}>
              <Text variant="label" color="var(--ggui-color-onSurfaceVariant, #52525b)">
                Element Details
              </Text>
              <Text variant="body" color="var(--ggui-color-onSurface, #18181b)">
                Name: {selectedElement.name ?? '-'}
              </Text>
              <Text variant="body" color="var(--ggui-color-onSurface, #18181b)">
                Symbol: {selectedElement.symbol ?? '-'}
              </Text>
              <Text variant="body" color="var(--ggui-color-onSurface, #18181b)">
                Atomic Number: {selectedElement.atomicNumber ?? '-'}
              </Text>
              <Text variant="body" color="var(--ggui-color-onSurface, #18181b)">
                Atomic Weight: {selectedElement.atomicWeight ?? '-'}
              </Text>
              <Text variant="body" color="var(--ggui-color-onSurface, #18181b)">
                Category: {selectedElement.category ?? 'unknown'}
              </Text>
            </Stack>
          ) : (
            <Text variant="bodySmall" color="var(--ggui-color-onSurfaceVariant, #52525b)">
              Select an element to view details.
            </Text>
          )}
        </Card>
      </Stack>
    </Card>
  );
}

import React, { useEffect, useMemo, useRef, useState } from 'react';
import {
  Badge,
  Box,
  Button,
  Card,
  Divider,
  Heading,
  Input,
  Stack,
  Text,
} from '@ggui-ai/design/primitives';

interface Props {
  /** Chat window title */
  title: string;
  /** Current user name (for right-aligning own messages) */
  currentUser: string;
  /** Number of participants */
  participantCount?: number;
  /** Array of messages with sender name, text, and ISO timestamp */
  messages: Array<{ sender?: string; text?: string; timestamp?: string }>;
  /** Action Contract: Send Message */
  sendMessage?: (payload: { text: string; timestamp: string }) => void;
}

type MessageItem = { sender?: string; text?: string; timestamp?: string };
type MessageGroup = { sender?: string; items: MessageItem[] };

export default function GeneratedComponent({
  title = 'Chat',
  currentUser = 'You',
  participantCount,
  messages = [],
  sendMessage = () => {},
}: Props) {
  const [inputValue, setInputValue] = useState<string>('');
  const messageViewportRef = useRef<HTMLDivElement | null>(null);

  const groupedMessages = useMemo<MessageGroup[]>(() => {
    return messages.reduce<MessageGroup[]>((groups, msg) => {
      const last = groups[groups.length - 1];
      if (last && (last.sender ?? '') === (msg.sender ?? '')) {
        last.items.push(msg);
      } else {
        groups.push({ sender: msg.sender, items: [msg] });
      }
      return groups;
    }, []);
  }, [messages]);

  const scrollToBottom = (behavior: ScrollBehavior = 'auto') => {
    const el = messageViewportRef.current;
    if (!el) return;
    el.scrollTo({ top: el.scrollHeight, behavior });
  };

  useEffect(() => {
    scrollToBottom('auto');
  }, []);

  useEffect(() => {
    scrollToBottom('smooth');
  }, [messages.length]);

  useEffect(() => {
    const handler = () => {
      scrollToBottom('smooth');
    };
    window.addEventListener('ggui:agent-data', handler as EventListener);
    return () => {
      window.removeEventListener('ggui:agent-data', handler as EventListener);
    };
  }, []);

  const formatTimestamp = (timestamp?: string) => {
    if (!timestamp) return '';
    const date = new Date(timestamp);
    if (Number.isNaN(date.getTime())) return '';
    return date.toLocaleTimeString([], { hour: '2-digit', minute: '2-digit' });
  };

  const handleSubmit = () => {
    const trimmed = inputValue.trim();
    if (!trimmed) return;
    const payload = { text: trimmed, timestamp: new Date().toISOString() };
    sendMessage(payload);
    setInputValue('');
  };

  return (
    <Card
      shadow="sm"
      border={true}
      radius="lg"
      padding={0}
      role="region"
      aria-label={title}
    >
      <Box
        style={{
          width: '100%',
          minHeight: 'var(--ggui-spacing-12, 48px)',
          height: 'min(70vh, 640px)',
          background: 'var(--ggui-color-surface, #fafafa)',
          display: 'flex',
          flexDirection: 'column',
        }}
      >
        <Stack direction="vertical" gap={0}>
          <Box
            padding="var(--ggui-spacing-4, 16px)"
            style={{ background: 'var(--ggui-color-surface, #fafafa)' }}
          >
            <Stack direction="horizontal" justify="between" align="center">
              <Heading
                level={5}
                color="var(--ggui-color-onSurface, #18181b)"
                style={{
                  maxWidth: '100%',
                  overflow: 'hidden',
                  textOverflow: 'ellipsis',
                  whiteSpace: 'nowrap',
                }}
              >
                {title}
              </Heading>
              {typeof participantCount === 'number' ? (
                <Badge
                  variant="primary"
                  size="sm"
                  pill={true}
                  aria-label={`${participantCount} participants`}
                >
                  {participantCount}
                </Badge>
              ) : null}
            </Stack>
          </Box>

          <Divider margin={0} color="var(--ggui-color-outlineVariant, #e4e4e7)" />

          <Box
            ref={messageViewportRef}
            role="log"
            aria-live="polite"
            aria-relevant="additions text"
            aria-label={`${title} messages`}
            style={{
              flex: 1,
              overflowY: 'auto',
              padding: 'var(--ggui-spacing-4, 16px)',
              background: 'var(--ggui-color-surface, #fafafa)',
            }}
          >
            {messages.length === 0 ? (
              <Box
                style={{
                  minHeight: '100%',
                  display: 'flex',
                  alignItems: 'center',
                  justifyContent: 'center',
                }}
              >
                <Text
                  variant="bodySmall"
                  color="var(--ggui-color-onSurfaceVariant, #52525b)"
                  align="center"
                >
                  No messages yet.
                </Text>
              </Box>
            ) : (
              <Stack direction="vertical" gap="var(--ggui-spacing-4, 16px)">
                {groupedMessages.map((group, groupIndex) => {
                  const isCurrentUser = (group.sender ?? '') === currentUser;
                  const senderName = group.sender || 'Unknown';

                  return (
                    <Box
                      key={`${senderName}-${groupIndex}`}
                      role="listitem"
                      style={{
                        display: 'flex',
                        justifyContent: isCurrentUser ? 'flex-end' : 'flex-start',
                      }}
                    >
                      <Stack
                        direction="vertical"
                        gap="var(--ggui-spacing-1, 4px)"
                        style={{ width: '100%', maxWidth: '80%' }}
                      >
                        <Text
                          variant="label"
                          color={
                            isCurrentUser
                              ? 'var(--ggui-color-primary-700, #0369a1)'
                              : 'var(--ggui-color-onSurfaceVariant, #52525b)'
                          }
                          align={isCurrentUser ? 'right' : 'left'}
                        >
                          {senderName}
                        </Text>

                        <Stack direction="vertical" gap="var(--ggui-spacing-1, 4px)">
                          {group.items.map((item, itemIndex) => {
                            const formattedTime = formatTimestamp(item.timestamp);
                            return (
                              <Box
                                key={`${senderName}-${itemIndex}-${item.timestamp ?? ''}`}
                                style={{
                                  alignSelf: isCurrentUser ? 'flex-end' : 'flex-start',
                                  background: isCurrentUser
                                    ? 'var(--ggui-color-primary-600, #0284c7)'
                                    : 'var(--ggui-color-surfaceVariant, #f4f4f5)',
                                  borderRadius: 'var(--ggui-shape-radius-lg, 12px)',
                                  padding: '10px 12px',
                                  maxWidth: '100%',
                                }}
                              >
                                <Stack direction="vertical" gap={4}>
                                  <Text
                                    variant="bodySmall"
                                    color={
                                      isCurrentUser
                                        ? 'var(--ggui-color-surface, #fafafa)'
                                        : 'var(--ggui-color-onSurface, #18181b)'
                                    }
                                  >
                                    {item.text ?? ''}
                                  </Text>
                                  {formattedTime ? (
                                    <Text
                                      variant="caption"
                                      color={
                                        isCurrentUser
                                          ? 'var(--ggui-color-primary-100, #e0f2fe)'
                                          : 'var(--ggui-color-onSurfaceVariant, #52525b)'
                                      }
                                    >
                                      {formattedTime}
                                    </Text>
                                  ) : null}
                                </Stack>
                              </Box>
                            );
                          })}
                        </Stack>
                      </Stack>
                    </Box>
                  );
                })}
              </Stack>
            )}
          </Box>

          <Divider margin={0} color="var(--ggui-color-outlineVariant, #e4e4e7)" />

          <Box
            padding="var(--ggui-spacing-4, 16px)"
            style={{ background: 'var(--ggui-color-surface, #fafafa)' }}
          >
            <Stack direction="horizontal" align="end" gap="var(--ggui-spacing-2, 8px)" wrap>
              <Box style={{ flex: 1, minWidth: '220px' }}>
                <Input
                  size="md"
                  placeholder="Type a message"
                  value={inputValue}
                  onChange={setInputValue}
                  aria-label="Type a message"
                  onKeyDown={(e) => {
                    if (e.key === 'Enter') {
                      e.preventDefault();
                      handleSubmit();
                    }
                  }}
                />
              </Box>
              <Button
                variant="primary"
                size="md"
                onClick={handleSubmit}
                disabled={!inputValue.trim()}
                aria-label="Send message"
              >
                Send
              </Button>
            </Stack>
          </Box>
        </Stack>
      </Box>
    </Card>
  );
}

import React, { useEffect, useMemo, useState } from 'react';
import { Card, Stack, Text, Spinner } from '@ggui-ai/design/primitives';

interface Props {
  /** Array of stocks with symbol, name, price, change, changePercent */
  stocks: Array<{ symbol?: string; name?: string; price?: number; change?: number; changePercent?: number }>;
  /** ISO timestamp of last price update */
  lastUpdated?: string;
}

export default function GeneratedComponent({
  stocks = [],
  lastUpdated = '',
}: Props) {
  const [liveStocks, setLiveStocks] = useState<Props['stocks']>(stocks);
  const [liveLastUpdated, setLiveLastUpdated] = useState<string | undefined>(lastUpdated);
  const [connecting, setConnecting] = useState<boolean>(true);

  useEffect(() => {
    setLiveStocks(stocks);
  }, [stocks]);

  useEffect(() => {
    setLiveLastUpdated(lastUpdated);
  }, [lastUpdated]);

  useEffect(() => {
    const timer = window.setTimeout(() => setConnecting(false), 1200);

    const handler = (event: Event) => {
      const customEvent = event as CustomEvent<Partial<Props>>;
      const payload = customEvent.detail;

      if (payload?.stocks) {
        setLiveStocks(payload.stocks);
      }
      if (payload?.lastUpdated) {
        setLiveLastUpdated(payload.lastUpdated);
      }
      setConnecting(false);
    };

    window.addEventListener('ggui:agent-data', handler as EventListener);
    return () => {
      window.clearTimeout(timer);
      window.removeEventListener('ggui:agent-data', handler as EventListener);
    };
  }, []);

  const formattedUpdated = useMemo(() => {
    if (!liveLastUpdated) return '—';
    const date = new Date(liveLastUpdated);
    if (Number.isNaN(date.getTime())) return liveLastUpdated;
    return date.toLocaleString();
  }, [liveLastUpdated]);

  const isLoading = connecting && liveStocks.length === 0;

  return (
    <Card
      padding="var(--ggui-spacing-6, 24px)"
      border
      shadow="sm"
      radius="lg"
    >
      <Stack gap="var(--ggui-spacing-6, 24px)">
        <Stack direction="horizontal" justify="between" align="center">
          <Text
            as="div"
            size="2xl"
            weight="bold"
            color="var(--ggui-color-onSurface, #18181b)"
          >
            Market Watch
          </Text>
          <Stack gap="var(--ggui-spacing-1, 4px)" align="end">
            <Text
              variant="caption"
              color="var(--ggui-color-onSurfaceVariant, #52525b)"
            >
              Last Updated
            </Text>
            <Text
              variant="label"
              color="var(--ggui-color-onSurface, #18181b)"
              aria-live="polite"
            >
              {formattedUpdated}
            </Text>
          </Stack>
        </Stack>

        {connecting && !isLoading && (
          <Text
            variant="caption"
            color="var(--ggui-color-onSurfaceVariant, #52525b)"
            aria-live="polite"
          >
            Connecting to live feed…
          </Text>
        )}

        {isLoading ? (
          <Stack
            direction="horizontal"
            align="center"
            justify="center"
            gap="var(--ggui-spacing-2, 8px)"
          >
            <Spinner size={20} color="var(--ggui-color-primary-600, #0284c7)" />
            <Text variant="bodySmall" color="var(--ggui-color-onSurfaceVariant, #52525b)">
              Loading market data…
            </Text>
          </Stack>
        ) : (
          <div
            aria-live="polite"
            aria-label="Stock ticker grid"
            style={{
              display: 'grid',
              gap: 'var(--ggui-spacing-4, 16px)',
              gridTemplateColumns: 'repeat(auto-fit, minmax(220px, 1fr))',
            }}
          >
            {liveStocks.map((stock, index) => {
              const change = stock.change ?? 0;
              const changePercent = stock.changePercent ?? 0;
              const isPositive = change >= 0;
              const trendColor = isPositive
                ? 'var(--ggui-color-success-600, #16a34a)'
                : 'var(--ggui-color-error-600, #dc2626)';
              const arrow = isPositive ? '▲' : '▼';

              return (
                <Card
                  key={`${stock.symbol ?? 'stock'}-${index}`}
                  padding="var(--ggui-spacing-4, 16px)"
                  radius="md"
                  shadow="sm"
                  border
                >
                  <Stack gap="var(--ggui-spacing-2, 8px)">
                    <Text
                      as="div"
                      size="2xl"
                      weight="bold"
                      color="var(--ggui-color-onSurface, #18181b)"
                    >
                      {stock.symbol ?? '—'}
                    </Text>
                    <Text
                      variant="bodySmall"
                      color="var(--ggui-color-onSurfaceVariant, #52525b)"
                      truncate
                    >
                      {stock.name ?? 'Unknown Company'}
                    </Text>
                    <Text
                      as="div"
                      size="xl"
                      weight="semibold"
                      color="var(--ggui-color-onSurface, #18181b)"
                    >
                      ${(stock.price ?? 0).toFixed(2)}
                    </Text>
                    <Stack direction="horizontal" align="center" justify="between">
                      <Text
                        variant="label"
                        color={trendColor}
                        style={{ borderColor: trendColor }}
                      >
                        {change >= 0 ? '+' : ''}
                        {change.toFixed(2)}
                      </Text>
                      <Text variant="label" color={trendColor}>
                        {arrow} {changePercent >= 0 ? '+' : ''}
                        {changePercent.toFixed(2)}%
                      </Text>
                    </Stack>
                  </Stack>
                </Card>
              );
            })}
          </div>
        )}
      </Stack>
    </Card>
  );
}

import React, { useMemo, useState } from 'react';
import {
  Card,
  Stack,
  Text,
  Button,
  Input,
  Select,
  Toggle,
  Progress,
  MotionKeyframes,
  useMotion,
} from '@ggui-ai/design/primitives';

interface Props {
  /** Pre-filled profile data for editing (all fields optional) */
  initialProfile?: {
    name?: string;
    email?: string;
    avatar?: string;
    role?: string;
    emailNotifications?: boolean;
    theme?: string;
  };
  /** Available avatar emojis to choose from */
  avatarOptions: string[];
  /** Available role options for the dropdown */
  roleOptions: string[];
  /** Called with all profile data when user completes onboarding */
  complete?: (data: {
    name: string;
    email: string;
    avatar: string;
    role: string;
    emailNotifications: boolean;
    theme: string;
  }) => void;
}

export default function GeneratedComponent(props: Props) {
  const { motionEnabled } = useMotion();

  const [step, setStep] = useState<number>(1);

  const [name, setName] = useState<string>(props.initialProfile?.name ?? '');
  const [email, setEmail] = useState<string>(props.initialProfile?.email ?? '');
  const [avatar, setAvatar] = useState<string>(
    props.initialProfile?.avatar ?? props.avatarOptions[0] ?? ''
  );
  const [role, setRole] = useState<string>(props.initialProfile?.role ?? '');
  const [emailNotifications, setEmailNotifications] = useState<boolean>(
    props.initialProfile?.emailNotifications ?? true
  );
  const [theme, setTheme] = useState<string>(props.initialProfile?.theme ?? 'light');

  const emailValid = useMemo(() => /^[^\s@]+@[^\s@]+\.[^\s@]+$/.test(email.trim()), [email]);
  const step1Valid = name.trim().length > 0 && emailValid;
  const step2Valid = role.trim().length > 0;
  const canNext = (step === 1 && step1Valid) || (step === 2 && step2Valid);

  const stepTitle =
    step === 1 ? 'Profile Setup' : step === 2 ? 'Preferences' : 'Review & Confirm';

  const progressValue = (step / 3) * 100;

  const handleNext = () => {
    if (step < 3 && canNext) setStep(step + 1);
  };

  const handleBack = () => {
    if (step > 1) setStep(step - 1);
  };

  const handleComplete = () => {
    if (!step1Valid || !step2Valid) return;
    props.complete?.({
      name: name.trim(),
      email: email.trim(),
      avatar,
      role,
      emailNotifications,
      theme,
    });
  };

  return (
    <Card
      padding={24}
      shadow="md"
      radius="lg"
      border
      style={{
        background: 'var(--ggui-color-surface, #fafafa)',
        color: 'var(--ggui-color-onSurface, #18181b)',
        borderColor: 'var(--ggui-color-outline, #d4d4d8)',
        maxWidth: '640px',
        margin: '0 auto',
      }}
    >
      <MotionKeyframes />
      <Stack gap={20}>
        <Stack gap={8}>
          <Text variant="label" color="var(--ggui-color-onSurfaceVariant, #52525b)">
            Step {step} of 3
          </Text>
          <Text variant="bodyLarge" weight="semibold" color="var(--ggui-color-onSurface, #18181b)">
            {stepTitle}
          </Text>
          <Progress value={progressValue} max={100} size="md" />
        </Stack>

        <Card
          padding={16}
          radius="md"
          border
          shadow="none"
          style={{
            background: 'var(--ggui-color-surfaceVariant, #f4f4f5)',
            borderColor: 'var(--ggui-color-outline, #d4d4d8)',
            animation: motionEnabled ? 'ggui-fadeIn 200ms ease-out' : 'none',
          }}
        >
          {step === 1 && (
            <Stack gap={14}>
              <Input
                label="Name"
                value={name}
                onChange={setName}
                required
                placeholder="Enter your name"
                error={name.trim().length === 0 ? 'Name is required.' : undefined}
              />
              <Input
                label="Email"
                type="email"
                value={email}
                onChange={setEmail}
                required
                placeholder="Enter your email"
                error={
                  email.trim().length === 0
                    ? 'Email is required.'
                    : !emailValid
                    ? 'Enter a valid email address.'
                    : undefined
                }
              />

              <Stack gap={8}>
                <Text variant="label" color="var(--ggui-color-onSurface, #18181b)">
                  Avatar selection
                </Text>
                <Stack direction="horizontal" gap={8} wrap>
                  {props.avatarOptions.map((option) => {
                    const selected = avatar === option;
                    return (
                      <Button
                        key={option}
                        variant={selected ? 'primary' : 'outline'}
                        size="md"
                        aria-label={`Select avatar ${option}`}
                        onClick={() => setAvatar(option)}
                      >
                        <span style={{ fontSize: 'var(--ggui-font-size-xl, 20px)' }}>{option}</span>
                      </Button>
                    );
                  })}
                </Stack>
              </Stack>
            </Stack>
          )}

          {step === 2 && (
            <Stack gap={14}>
              <Select
                label="Role"
                value={role}
                onChange={setRole}
                placeholder="Select your role"
                required
                error={role.trim().length === 0 ? 'Role is required.' : undefined}
                options={props.roleOptions.map((r) => ({ value: r, label: r }))}
              />

              <Toggle
                label="Email notifications"
                checked={emailNotifications}
                onChange={setEmailNotifications}
                size="md"
              />

              <Stack gap={8}>
                <Text variant="label">Theme preference</Text>
                <Stack direction="horizontal" gap={8}>
                  <Button
                    variant={theme === 'light' ? 'primary' : 'outline'}
                    onClick={() => setTheme('light')}
                    aria-label="Set light theme"
                  >
                    Light
                  </Button>
                  <Button
                    variant={theme === 'dark' ? 'primary' : 'outline'}
                    onClick={() => setTheme('dark')}
                    aria-label="Set dark theme"
                  >
                    Dark
                  </Button>
                </Stack>
              </Stack>
            </Stack>
          )}

          {step === 3 && (
            <Stack gap={10}>
              <Text variant="label" color="var(--ggui-color-onSurfaceVariant, #52525b)">
                Review your selections
              </Text>
              <Text>
                <strong>Name:</strong> {name || '-'}
              </Text>
              <Text>
                <strong>Email:</strong> {email || '-'}
              </Text>
              <Text>
                <strong>Avatar:</strong> {avatar || '-'}
              </Text>
              <Text>
                <strong>Role:</strong> {role || '-'}
              </Text>
              <Text>
                <strong>Email notifications:</strong> {emailNotifications ? 'On' : 'Off'}
              </Text>
              <Text>
                <strong>Theme:</strong> {theme || '-'}
              </Text>
            </Stack>
          )}
        </Card>

        <Stack direction="horizontal" justify="between" align="center" gap={8}>
          <Button variant="ghost" onClick={handleBack} disabled={step === 1}>
            Back
          </Button>

          {step < 3 ? (
            <Button variant="primary" onClick={handleNext} disabled={!canNext}>
              Next
            </Button>
          ) : (
            <Stack direction="horizontal" gap={8}>
              <Button variant="secondary" onClick={() => setStep(2)}>
                Go Back
              </Button>
              <Button variant="primary" onClick={handleComplete}>
                Complete Setup
              </Button>
            </Stack>
          )}
        </Stack>
      </Stack>
    </Card>
  );
}

import React, { useMemo, useState } from 'react';
import {
  Card,
  Stack,
  Text,
  Button,
  Input,
  RadioGroup,
  Checkbox,
  TextArea,
  Progress,
  Alert,
} from '@ggui-ai/design/primitives';

interface Props {
  /** Available feature options for the checkbox step */
  featureOptions: string[];
  /** Labels for satisfaction rating (e.g., Very Unsatisfied to Very Satisfied) */
  satisfactionLabels: string[];
  /** Submit Survey — Called with all collected answers as a structured object */
  submit?: (payload: {
    name: string;
    email: string;
    satisfaction: { value: string; label: string };
    featureInterests: string[];
    comments: string;
  }) => Promise<void> | void;
}

export default function GeneratedComponent({
  featureOptions = ['Feature A', 'Feature B', 'Feature C'],
  satisfactionLabels = ['Very Unsatisfied', 'Unsatisfied', 'Neutral', 'Satisfied', 'Very Satisfied'],
  submit,
}: Props) {
  const totalSteps = 5; // includes final review
  const [step, setStep] = useState(1);

  const [name, setName] = useState('');
  const [email, setEmail] = useState('');
  const [satisfaction, setSatisfaction] = useState('');
  const [featureInterests, setFeatureInterests] = useState<string[]>([]);
  const [comments, setComments] = useState('');

  const [touched, setTouched] = useState({ name: false, email: false });
  const [isSubmitting, setIsSubmitting] = useState(false);
  const [feedback, setFeedback] = useState<{ type: 'success' | 'error'; message: string } | null>(null);

  const emailRegex = /^[^\s@]+@[^\s@]+\.[^\s@]+$/;
  const nameError = touched.name && !name.trim() ? 'Name is required.' : '';
  const emailError =
    touched.email && !email.trim()
      ? 'Email is required.'
      : touched.email && !emailRegex.test(email)
      ? 'Please enter a valid email address.'
      : '';

  const step1Valid = !!name.trim() && !!email.trim() && emailRegex.test(email);
  const step2Valid = !!satisfaction;
  const step4Valid = comments.length <= 500;

  const canGoNext =
    (step === 1 && step1Valid) ||
    (step === 2 && step2Valid) ||
    step === 3 ||
    (step === 4 && step4Valid);

  const satisfactionOptions = useMemo(
    () =>
      satisfactionLabels.map((label, index) => ({
        value: String(index + 1),
        label: `${index + 1} - ${label}`,
      })),
    [satisfactionLabels]
  );

  const progressValue = Math.round((step / totalSteps) * 100);

  const toggleFeature = (feature: string, checked: boolean) => {
    setFeatureInterests((prev) =>
      checked ? [...prev, feature] : prev.filter((item) => item !== feature)
    );
  };

  const handleNext = () => {
    if (step === 1) setTouched({ name: true, email: true });
    if (step < totalSteps && canGoNext) setStep((s) => s + 1);
  };

  const handleBack = () => {
    if (step > 1) setStep((s) => s - 1);
  };

  const handleSubmit = async () => {
    setFeedback(null);
    setIsSubmitting(true);
    try {
      const selectedIndex = Number(satisfaction) - 1;
      const payload = {
        name: name.trim(),
        email: email.trim(),
        satisfaction: {
          value: satisfaction,
          label: satisfactionLabels[selectedIndex] ?? '',
        },
        featureInterests,
        comments: comments.trim(),
      };

      if (submit) {
        await submit(payload);
      }

      setFeedback({ type: 'success', message: 'Survey submitted successfully.' });
    } catch (error) {
      setFeedback({ type: 'error', message: 'Submission failed. Please try again.' });
    } finally {
      setIsSubmitting(false);
    }
  };

  return (
    <Card
      padding={24}
      shadow="md"
      border
      radius="lg"
      style={{
        background: 'var(--ggui-color-surface, #fafafa)',
        borderColor: 'var(--ggui-color-outline, #d4d4d8)',
      }}
    >
      <Stack gap={16}>
        <Stack gap={8}>
          <Text
            variant="label"
            color="var(--ggui-color-onSurface, #18181b)"
            aria-live="polite"
          >
            Step {step} of {totalSteps}
          </Text>
          <Progress value={progressValue} max={100} size="md" />
        </Stack>

        {feedback && (
          <Alert variant={feedback.type === 'success' ? 'success' : 'error'} title={feedback.type === 'success' ? 'Success' : 'Error'}>
            {feedback.message}
          </Alert>
        )}

        {step === 1 && (
          <Stack gap={12}>
            <Text variant="bodyLarge" weight="semibold" color="var(--ggui-color-onSurface, #18181b)">
              Basic Information
            </Text>
            <Input
              label="Name"
              value={name}
              onChange={setName}
              required
              error={nameError}
              placeholder="Enter your name"
              onBlur={() => setTouched((t) => ({ ...t, name: true }))}
              aria-label="Name"
            />
            <Input
              label="Email"
              type="email"
              value={email}
              onChange={setEmail}
              required
              error={emailError}
              placeholder="Enter your email"
              onBlur={() => setTouched((t) => ({ ...t, email: true }))}
              aria-label="Email"
            />
          </Stack>
        )}

        {step === 2 && (
          <Stack gap={12}>
            <Text variant="bodyLarge" weight="semibold" color="var(--ggui-color-onSurface, #18181b)">
              Satisfaction Rating
            </Text>
            <RadioGroup
              label="How satisfied are you?"
              value={satisfaction}
              onChange={setSatisfaction}
              options={satisfactionOptions}
              direction="vertical"
              error={!step2Valid ? 'Please select a rating before continuing.' : ''}
            />
          </Stack>
        )}

        {step === 3 && (
          <Stack gap={12}>
            <Text variant="bodyLarge" weight="semibold" color="var(--ggui-color-onSurface, #18181b)">
              Feature Interests
            </Text>
            <Text variant="bodySmall" color="var(--ggui-color-onSurfaceVariant, #52525b)">
              Select all features you are interested in.
            </Text>
            <Stack gap={8}>
              {featureOptions.map((feature) => (
                <Checkbox
                  key={feature}
                  label={feature}
                  checked={featureInterests.includes(feature)}
                  onChange={(checked) => toggleFeature(feature, checked)}
                />
              ))}
            </Stack>
          </Stack>
        )}

        {step === 4 && (
          <Stack gap={12}>
            <Text variant="bodyLarge" weight="semibold" color="var(--ggui-color-onSurface, #18181b)">
              Additional Comments
            </Text>
            <TextArea
              label="Comments (optional)"
              value={comments}
              onChange={setComments}
              rows={6}
              maxLength={500}
              showCount
              placeholder="Share anything else you'd like us to know..."
              aria-label="Comments"
            />
          </Stack>
        )}

        {step === 5 && (
          <Stack gap={12}>
            <Text variant="bodyLarge" weight="semibold" color="var(--ggui-color-onSurface, #18181b)">
              Review Your Answers
            </Text>
            <Card
              padding={16}
              shadow="none"
              border
              radius="md"
              style={{
                background: 'var(--ggui-color-surfaceVariant, #f4f4f5)',
                borderColor: 'var(--ggui-color-outline, #d4d4d8)',
              }}
            >
              <Stack gap={8}>
                <Text variant="body"><strong>Name:</strong> {name || '-'}</Text>
                <Text variant="body"><strong>Email:</strong> {email || '-'}</Text>
                <Text variant="body">
                  <strong>Satisfaction:</strong>{' '}
                  {satisfaction ? `${satisfaction} - ${satisfactionLabels[Number(satisfaction) - 1] ?? ''}` : '-'}
                </Text>
                <Text variant="body">
                  <strong>Feature Interests:</strong>{' '}
                  {featureInterests.length ? featureInterests.join(', ') : 'None selected'}
                </Text>
                <Text variant="body">
                  <strong>Comments:</strong> {comments.trim() || 'No comments'}
                </Text>
              </Stack>
            </Card>
          </Stack>
        )}

        <Stack direction="horizontal" justify="between" align="center" gap={12}>
          <Button variant="ghost" onClick={handleBack} disabled={step === 1 || isSubmitting}>
            Back
          </Button>

          {step < totalSteps ? (
            <Button
              variant="primary"
              onClick={handleNext}
              disabled={!canGoNext || isSubmitting}
              aria-label="Next step"
            >
              Next
            </Button>
          ) : (
            <Button
              variant="primary"
              onClick={handleSubmit}
              loading={isSubmitting}
              disabled={isSubmitting}
              aria-label="Submit survey"
            >
              Submit Survey
            </Button>
          )}
        </Stack>
      </Stack>
    </Card>
  );
}

import React, { useMemo, useState } from 'react';
import { Card, Stack, Text, Input } from '@ggui-ai/design/primitives';

interface Props {
  /** Full periodic table element data */
  elements: Array<{
    atomicNumber?: number;
    symbol?: string;
    name?: string;
    atomicWeight?: number;
    category?: string;
    row?: number;
    col?: number;
  }>;
}

const defaultElements: Props['elements'] = [];

const categoryColorMap: Record<string, string> = {
  'alkali metal': 'var(--ggui-color-error-500, #ef4444)',
  'alkaline earth metal': 'var(--ggui-color-warning-500, #f59e0b)',
  'transition metal': 'var(--ggui-color-primary-500, #0ea5e9)',
  'post-transition metal': 'var(--ggui-color-info-500, #06b6d4)',
  metalloid: 'var(--ggui-color-success-500, #22c55e)',
  nonmetal: 'var(--ggui-color-success-600, #16a34a)',
  halogen: 'var(--ggui-color-warning-600, #d97706)',
  'noble gas': 'var(--ggui-color-primary-600, #0284c7)',
  lanthanide: 'var(--ggui-color-primary-400, #38bdf8)',
  actinide: 'var(--ggui-color-error-600, #dc2626)',
  unknown: 'var(--ggui-color-neutral-400, #9ca3af)',
};

function getCategoryColor(category?: string): string {
  if (!category) return categoryColorMap.unknown;
  return categoryColorMap[category.toLowerCase()] || 'var(--ggui-color-neutral-400, #9ca3af)';
}

export default function GeneratedComponent({ elements = defaultElements }: Props) {
  const [search, setSearch] = useState<string>('');
  const [selectedElement, setSelectedElement] = useState<Props['elements'][number] | null>(null);

  const filteredElements = useMemo(() => {
    const q = search.trim().toLowerCase();
    if (!q) return elements;
    return elements.filter((el) => {
      const name = (el.name || '').toLowerCase();
      const symbol = (el.symbol || '').toLowerCase();
      return name.includes(q) || symbol.includes(q);
    });
  }, [elements, search]);

  const categories = useMemo(() => {
    const map = new Map<string, string>();
    elements.forEach((el) => {
      const key = el.category || 'unknown';
      if (!map.has(key)) {
        map.set(key, getCategoryColor(key));
      }
    });
    return Array.from(map.entries());
  }, [elements]);

  return (
    <Stack gap={16}>
      <Input
        label="Search elements"
        placeholder="Search by name or symbol"
        value={search}
        onChange={setSearch}
        type="search"
      />

      <Card
        padding={12}
        border
        shadow="sm"
        radius="lg"
      >
        <div
          style={{
            display: 'grid',
            gridTemplateColumns: 'repeat(18, minmax(0, 1fr))',
            gap: 'var(--ggui-spacing-1, 4px)',
            background: 'var(--ggui-color-surface, #fafafa)',
          }}
          aria-label="Periodic table grid"
        >
          {filteredElements.map((el, idx) => {
            const bg = getCategoryColor(el.category);
            const isSelected = selectedElement?.atomicNumber === el.atomicNumber;

            return (
              <button
                key={`${el.atomicNumber ?? 'x'}-${el.symbol ?? 'y'}-${idx}`}
                type="button"
                onClick={() => setSelectedElement(el)}
                aria-label={`${el.name || 'Unknown'} (${el.symbol || ''})`}
                style={{
                  gridColumn: el.col || undefined,
                  gridRow: el.row || undefined,
                  minHeight: 64,
                  border: isSelected
                    ? '2px solid var(--ggui-color-primary-600, #0284c7)'
                    : '1px solid var(--ggui-color-outline, #d4d4d8)',
                  borderRadius: 'var(--ggui-shape-radius-md, 8px)',
                  background: bg,
                  color: 'var(--ggui-color-onSurface, #18181b)',
                  position: 'relative',
                  cursor: 'pointer',
                  padding: 'var(--ggui-spacing-1, 4px)',
                  transition: 'transform 150ms ease, box-shadow 150ms ease, border-color 150ms ease',
                  outlineOffset: 2,
                }}
              >
                <Text
                  variant="caption"
                  as="span"
                  color="var(--ggui-color-onSurface, #18181b)"
                  style={{ position: 'absolute', top: 4, left: 6 } as React.CSSProperties}
                >
                  {el.atomicNumber ?? '-'}
                </Text>
                <Text
                  as="span"
                  weight="bold"
                  size="xl"
                  align="center"
                  color="var(--ggui-color-onSurface, #18181b)"
                  style={{
                    display: 'block',
                    lineHeight: '64px',
                  }}
                >
                  {el.symbol || '?'}
                </Text>
              </button>
            );
          })}
        </div>
      </Card>

      <Card padding={16} border shadow="sm" radius="lg">
        <Stack gap={8}>
          <Text variant="label" color="var(--ggui-color-onSurface, #18181b)">
            Element details
          </Text>
          {selectedElement ? (
            <Stack gap={4}>
              <Text color="var(--ggui-color-onSurface, #18181b)">
                Name: {selectedElement.name || '-'}
              </Text>
              <Text color="var(--ggui-color-onSurface, #18181b)">
                Symbol: {selectedElement.symbol || '-'}
              </Text>
              <Text color="var(--ggui-color-onSurface, #18181b)">
                Atomic Number: {selectedElement.atomicNumber ?? '-'}
              </Text>
              <Text color="var(--ggui-color-onSurface, #18181b)">
                Atomic Weight: {selectedElement.atomicWeight ?? '-'}
              </Text>
              <Text color="var(--ggui-color-onSurface, #18181b)">
                Category: {selectedElement.category || 'unknown'}
              </Text>
            </Stack>
          ) : (
            <Text variant="bodySmall" color="var(--ggui-color-onSurfaceVariant, #52525b)">
              Select an element from the table to view details.
            </Text>
          )}
        </Stack>
      </Card>

      <Card padding={16} border shadow="sm" radius="lg">
        <Stack gap={8}>
          <Text variant="label" color="var(--ggui-color-onSurface, #18181b)">
            Legend
          </Text>
          <Stack direction="horizontal" wrap gap={8}>
            {categories.map(([category, color]) => (
              <Stack
                key={category}
                direction="horizontal"
                align="center"
                gap={6}
                style={{
                  padding: '4px 8px',
                  border: '1px solid var(--ggui-color-outline, #d4d4d8)',
                  borderRadius: 'var(--ggui-shape-radius-full, 9999px)',
                  background: 'var(--ggui-color-surfaceVariant, #f4f4f5)',
                }}
              >
                <span
                  aria-hidden="true"
                  style={{
                    width: 10,
                    height: 10,
                    borderRadius: 'var(--ggui-shape-radius-full, 9999px)',
                    background: color,
                    display: 'inline-block',
                  }}
                />
                <Text variant="caption" color="var(--ggui-color-onSurface, #18181b)">
                  {category}
                </Text>
              </Stack>
            ))}
          </Stack>
        </Stack>
      </Card>
    </Stack>
  );
}

