import React, { useEffect, useMemo, useRef, useState } from 'react';
import { Badge, Button, Card, Input, Stack, Text } from '@ggui-ai/design/primitives';

interface Props {
  /** Chat window title */
  title: string;
  /** Current user name (for right-aligning own messages) */
  currentUser: string;
  /** Number of participants */
  participantCount?: number;
  /** Array of messages with sender name, text, and ISO timestamp */
  messages: Array<{ sender?: string; text?: string; timestamp?: string }>;
  /** Action Contract: outgoing message callback */
  sendMessage?: (payload: { text: string; timestamp: string }) => void;
}

export default function GeneratedComponent({
  title = 'Chat',
  currentUser = '',
  participantCount,
  messages = [],
  sendMessage,
}: Props) {
  const [draft, setDraft] = useState<string>('');
  const [streamMessages, setStreamMessages] = useState<Array<{ sender?: string; text?: string; timestamp?: string }>>([]);
  const listRef = useRef<HTMLDivElement | null>(null);

  // Stream Contract
  useEffect(() => {
    const handler = (event: Event) => {
      const customEvent = event as CustomEvent<{ sender?: string; text?: string; timestamp?: string }>;
      const payload = customEvent.detail;
      if (payload && (payload.text || payload.sender || payload.timestamp)) {
        setStreamMessages((prev) => [...prev, payload]);
      }
    };
    window.addEventListener('ggui:agent-data', handler);
    return () => window.removeEventListener('ggui:agent-data', handler);
  }, []);

  const allMessages = useMemo(() => [...messages, ...streamMessages], [messages, streamMessages]);

  const groupedMessages = useMemo(() => {
    const groups: Array<{ sender?: string; items: Array<{ sender?: string; text?: string; timestamp?: string }> }> = [];
    allMessages.forEach((msg) => {
      const last = groups[groups.length - 1];
      if (last && last.sender === msg.sender) {
        last.items.push(msg);
      } else {
        groups.push({ sender: msg.sender, items: [msg] });
      }
    });
    return groups;
  }, [allMessages]);

  const scrollToBottom = () => {
    if (listRef.current) {
      listRef.current.scrollTop = listRef.current.scrollHeight;
    }
  };

  useEffect(() => {
    scrollToBottom();
  }, []);

  useEffect(() => {
    scrollToBottom();
  }, [allMessages]);

  const formatTimestamp = (value?: string) => {
    if (!value) return '';
    const date = new Date(value);
    if (Number.isNaN(date.getTime())) return value;
    return date.toLocaleTimeString([], { hour: '2-digit', minute: '2-digit' });
  };

  const handleSend = () => {
    const text = draft.trim();
    if (!text) return;
    sendMessage?.({ text, timestamp: new Date().toISOString() });
    setDraft('');
  };

  return (
    <Card
      padding="var(--ggui-spacing-4, 16px)"
      shadow="sm"
      border
      radius="lg"
    >
      <Stack gap="var(--ggui-spacing-4, 16px)" style={{ height: '100%' }}>
        <Stack direction="horizontal" justify="between" align="center">
          <Text
            variant="label"
            color="var(--ggui-color-onSurface, #18181b)"
          >
            {title}
          </Text>
          {typeof participantCount === 'number' && (
            <Badge variant="primary" size="sm" aria-label={`Participants: ${participantCount}`}>
              {participantCount}
            </Badge>
          )}
        </Stack>

        <Card
          padding="var(--ggui-spacing-2, 8px)"
          border
          radius="md"
          shadow="none"
        >
          <Stack
            gap="var(--ggui-spacing-2, 8px)"
            style={{
              height: '320px',
              overflowY: 'auto',
              background: 'var(--ggui-color-surface, #fafafa)',
            }}
            ref={listRef}
            aria-label="Message list"
          >
            {groupedMessages.map((group, groupIdx) => {
              const isCurrentUser = (group.sender || '') === currentUser;
              return (
                <Stack
                  key={`${group.sender || 'unknown'}-${groupIdx}`}
                  align={isCurrentUser ? 'end' : 'start'}
                  gap="var(--ggui-spacing-1, 4px)"
                >
                  <Text
                    variant="caption"
                    color="var(--ggui-color-onSurfaceVariant, #52525b)"
                  >
                    {group.sender || 'Unknown'}
                  </Text>

                  {group.items.map((msg, idx) => (
                    <Card
                      key={`${msg.timestamp || 'no-time'}-${idx}-${msg.text || ''}`}
                      padding="var(--ggui-spacing-2, 8px)"
                      radius="md"
                      border
                      shadow="none"
                    >
                      <Stack gap="var(--ggui-spacing-1, 4px)">
                        <Text
                          variant="bodySmall"
                          color={isCurrentUser ? 'var(--ggui-color-onContainer, #4c1d95)' : 'var(--ggui-color-onSurface, #18181b)'}
                        >
                          {msg.text || ''}
                        </Text>
                        <Text
                          variant="caption"
                          color="var(--ggui-color-onSurfaceVariant, #52525b)"
                          align={isCurrentUser ? 'right' : 'left'}
                        >
                          {formatTimestamp(msg.timestamp)}
                        </Text>
                      </Stack>
                      <style>{`
                        [data-own="${isCurrentUser ? 'true' : 'false'}"] {
                          background: ${isCurrentUser
                            ? 'var(--ggui-color-container, #ede9fe)'
                            : 'var(--ggui-color-surfaceVariant, #f4f4f5)'};
                        }
                      `}</style>
                    </Card>
                  ))}
                </Stack>
              );
            })}
          </Stack>
        </Card>

        <Stack direction="horizontal" gap="var(--ggui-spacing-2, 8px)" align="end">
          <Input
            value={draft}
            onChange={setDraft}
            placeholder="Type a message..."
            aria-label="Compose message"
            onKeyDown={(e) => {
              if (e.key === 'Enter') {
                e.preventDefault();
                handleSend();
              }
            }}
          />
          <Button
            variant="primary"
            size="md"
            onClick={handleSend}
            disabled={!draft.trim()}
            aria-label="Send message"
          >
            Send
          </Button>
        </Stack>
      </Stack>
    </Card>
  );
}

import React, { useEffect, useMemo, useState } from 'react';
import { Card, Stack, Text, Spinner } from '@ggui-ai/design/primitives';

interface Props {
  /** Array of stocks with symbol, name, price, change, changePercent */
  stocks: Array<{ symbol?: string; name?: string; price?: number; change?: number; changePercent?: number }>;
  /** ISO timestamp of last price update */
  lastUpdated?: string;
}

export default function GeneratedComponent(props: Props) {
  const [liveStocks, setLiveStocks] = useState<Props['stocks']>(props.stocks ?? []);
  const [liveLastUpdated, setLiveLastUpdated] = useState<string | undefined>(props.lastUpdated);
  const [isConnecting, setIsConnecting] = useState<boolean>(true);
  const [isLoading, setIsLoading] = useState<boolean>((props.stocks ?? []).length === 0);

  useEffect(() => {
    setLiveStocks(props.stocks ?? []);
    setLiveLastUpdated(props.lastUpdated);
    setIsLoading((props.stocks ?? []).length === 0);
  }, [props.stocks, props.lastUpdated]);

  useEffect(() => {
    const handleAgentData = (event: Event) => {
      const customEvent = event as CustomEvent<Partial<Props> | undefined>;
      const payload = customEvent.detail;

      if (payload?.stocks) {
        setLiveStocks(payload.stocks);
        setIsLoading(payload.stocks.length === 0);
      }
      if (payload?.lastUpdated) {
        setLiveLastUpdated(payload.lastUpdated);
      } else {
        setLiveLastUpdated(new Date().toISOString());
      }
      setIsConnecting(false);
    };

    window.addEventListener('ggui:agent-data', handleAgentData as EventListener);
    const timeout = window.setTimeout(() => {
      setIsConnecting(false);
    }, 2500);

    return () => {
      window.removeEventListener('ggui:agent-data', handleAgentData as EventListener);
      window.clearTimeout(timeout);
    };
  }, []);

  const formattedUpdated = useMemo(() => {
    if (!liveLastUpdated) return '—';
    const dt = new Date(liveLastUpdated);
    return Number.isNaN(dt.getTime()) ? liveLastUpdated : dt.toLocaleString();
  }, [liveLastUpdated]);

  return (
    <Stack
      gap="var(--ggui-spacing-6, 24px)"
      style={{
        background: 'var(--ggui-color-surface, #fafafa)',
        color: 'var(--ggui-color-onSurface, #18181b)',
        padding: 'var(--ggui-spacing-6, 24px)',
      }}
    >
      <Stack
        direction="horizontal"
        justify="between"
        align="center"
        style={{
          borderBottom: '1px solid var(--ggui-color-outline, #d4d4d8)',
          paddingBottom: 'var(--ggui-spacing-2, 8px)',
        }}
      >
        <Text as="div" size="2xl" weight="bold" color="var(--ggui-color-onSurface, #18181b)">
          Market Watch
        </Text>
        <Stack direction="horizontal" gap="var(--ggui-spacing-2, 8px)" align="center">
          {isConnecting ? <Spinner size={16} color="var(--ggui-color-primary-600, #0284c7)" /> : null}
          <Text variant="bodySmall" color="var(--ggui-color-onSurfaceVariant, #52525b)">
            Last Updated: {formattedUpdated}
          </Text>
        </Stack>
      </Stack>

      {isLoading ? (
        <Card
          padding={20}
          radius="lg"
          border
          shadow="none"
          style={{
            background: 'var(--ggui-color-surfaceVariant, #f4f4f5)',
            borderColor: 'var(--ggui-color-outline, #d4d4d8)',
          }}
        >
          <Stack direction="horizontal" gap="var(--ggui-spacing-2, 8px)" align="center">
            <Spinner size={18} color="var(--ggui-color-primary-600, #0284c7)" />
            <Text variant="bodySmall" color="var(--ggui-color-onSurfaceVariant, #52525b)">
              Loading live market data...
            </Text>
          </Stack>
        </Card>
      ) : null}

      <div
        aria-live="polite"
        style={{
          display: 'grid',
          gridTemplateColumns: 'repeat(auto-fit, minmax(260px, 1fr))',
          gap: 'var(--ggui-spacing-4, 16px)',
        }}
      >
        {(liveStocks ?? []).map((stock, index) => {
          const change = stock.change ?? 0;
          const changePercent = stock.changePercent ?? 0;
          const isPositive = change >= 0;
          const trendColor = isPositive
            ? 'var(--ggui-color-success-600, #16a34a)'
            : 'var(--ggui-color-error-600, #dc2626)';
          const arrow = isPositive ? '▲' : '▼';

          return (
            <Card
              key={`${stock.symbol ?? 'stock'}-${index}`}
              padding={16}
              radius="lg"
              border
              shadow="sm"
              style={{
                background: 'var(--ggui-color-surfaceVariant, #f4f4f5)',
                borderColor: trendColor,
                transition: 'transform 200ms ease, box-shadow 200ms ease, border-color 200ms ease',
              }}
              aria-label={`${stock.symbol ?? 'Unknown'} stock card`}
            >
              <Stack gap="var(--ggui-spacing-2, 8px)">
                <Text as="div" size="3xl" weight="bold" color="var(--ggui-color-onSurface, #18181b)">
                  {stock.symbol ?? '—'}
                </Text>
                <Text variant="bodySmall" color="var(--ggui-color-onSurfaceVariant, #52525b)">
                  {stock.name ?? 'Unknown Company'}
                </Text>
                <Text as="div" size="xl" weight="semibold" color="var(--ggui-color-onSurface, #18181b)">
                  ${(stock.price ?? 0).toFixed(2)}
                </Text>
                <Text variant="label" color={trendColor}>
                  {change >= 0 ? '+' : ''}
                  {change.toFixed(2)}
                </Text>
                <Text variant="label" color={trendColor}>
                  {arrow} {changePercent >= 0 ? '+' : ''}
                  {changePercent.toFixed(2)}%
                </Text>
              </Stack>
            </Card>
          );
        })}
      </div>
    </Stack>
  );
}

import React, { useMemo, useState } from 'react';
import {
  Card,
  Stack,
  Text,
  Button,
  Input,
  Select,
  Toggle,
  Progress,
  MotionKeyframes,
  useMotion,
} from '@ggui-ai/design/primitives';

interface Props {
  /** Pre-filled profile data for editing (all fields optional) */
  initialProfile?: {
    name?: string;
    email?: string;
    avatar?: string;
    role?: string;
    emailNotifications?: boolean;
    theme?: string;
  };
  /** Available avatar emojis to choose from */
  avatarOptions: string[];
  /** Available role options for the dropdown */
  roleOptions: string[];
  /** Complete Setup callback */
  onComplete?: (data: {
    name: string;
    email: string;
    avatar: string;
    role: string;
    emailNotifications: boolean;
    theme: string;
  }) => void;
}

export default function GeneratedComponent(props: Props) {
  const {
    initialProfile = {},
    avatarOptions = ['😀', '🚀', '🎨', '🧠'],
    roleOptions = ['Developer', 'Designer', 'Manager', 'Other'],
    onComplete,
  } = props;

  const { motionEnabled } = useMotion();

  const [step, setStep] = useState<number>(1);
  const [name, setName] = useState<string>(initialProfile.name ?? '');
  const [email, setEmail] = useState<string>(initialProfile.email ?? '');
  const [avatar, setAvatar] = useState<string>(initialProfile.avatar ?? avatarOptions[0] ?? '');
  const [role, setRole] = useState<string>(initialProfile.role ?? '');
  const [emailNotifications, setEmailNotifications] = useState<boolean>(
    initialProfile.emailNotifications ?? true
  );
  const [theme, setTheme] = useState<string>(initialProfile.theme ?? 'light');

  const emailValid = useMemo(() => /^[^\s@]+@[^\s@]+\.[^\s@]+$/.test(email.trim()), [email]);
  const step1Valid = name.trim().length > 0 && emailValid && avatar.trim().length > 0;
  const step2Valid = role.trim().length > 0 && (theme === 'light' || theme === 'dark');

  const canNext = (step === 1 && step1Valid) || (step === 2 && step2Valid);
  const progressValue = (step / 3) * 100;

  const handleNext = () => {
    if (step < 3 && canNext) setStep((s) => s + 1);
  };

  const handleBack = () => {
    if (step > 1) setStep((s) => s - 1);
  };

  const handleComplete = () => {
    if (!step1Valid || !step2Valid) return;
    onComplete?.({
      name: name.trim(),
      email: email.trim(),
      avatar,
      role,
      emailNotifications,
      theme,
    });
  };

  return (
    <>
      <MotionKeyframes />
      <Card
        padding={24}
        shadow="md"
        radius="lg"
        border
        style={{
          background: 'var(--ggui-color-surface, #fafafa)',
          borderColor: 'var(--ggui-color-outline, #d4d4d8)',
          maxWidth: '680px',
          margin: '0 auto',
        }}
      >
        <Stack gap={20}>
          <Stack gap={8}>
            <Text
              variant="label"
              color="var(--ggui-color-onSurfaceVariant, #52525b)"
              aria-live="polite"
            >
              Step {step} of 3
            </Text>
            <Progress value={progressValue} max={100} size="md" variant="default" />
          </Stack>

          <Stack
            gap={16}
            style={{
              animation: motionEnabled ? 'ggui-fadeIn 200ms ease-out' : 'none',
              transition: motionEnabled ? 'all 200ms ease-in-out' : 'none',
            }}
          >
            {step === 1 && (
              <Stack gap={14}>
                <Text variant="bodyLarge" weight="semibold" color="var(--ggui-color-onSurface, #18181b)">
                  Profile Setup
                </Text>

                <Input
                  label="Name"
                  value={name}
                  onChange={setName}
                  required
                  placeholder="Enter your name"
                  error={name.trim().length === 0 ? 'Name is required' : ''}
                />

                <Input
                  label="Email"
                  type="email"
                  value={email}
                  onChange={setEmail}
                  required
                  placeholder="you@example.com"
                  error={email.trim().length === 0 ? 'Email is required' : !emailValid ? 'Enter a valid email address' : ''}
                />

                <Stack gap={8}>
                  <Text variant="label" color="var(--ggui-color-onSurface, #18181b)">
                    Choose an avatar
                  </Text>
                  <Stack direction="horizontal" gap={8} wrap>
                    {avatarOptions.map((option) => {
                      const selected = avatar === option;
                      return (
                        <Button
                          key={option}
                          variant={selected ? 'primary' : 'outline'}
                          size="md"
                          aria-label={`Select avatar ${option}`}
                          onClick={() => setAvatar(option)}
                        >
                          {option}
                        </Button>
                      );
                    })}
                  </Stack>
                </Stack>
              </Stack>
            )}

            {step === 2 && (
              <Stack gap={14}>
                <Text variant="bodyLarge" weight="semibold" color="var(--ggui-color-onSurface, #18181b)">
                  Preferences
                </Text>

                <Select
                  label="Role"
                  value={role}
                  onChange={setRole}
                  placeholder="Select your role"
                  required
                  options={roleOptions.map((r) => ({ value: r, label: r }))}
                  error={role.trim().length === 0 ? 'Role is required' : ''}
                />

                <Toggle
                  label="Email notifications"
                  checked={emailNotifications}
                  onChange={setEmailNotifications}
                  size="md"
                />

                <Toggle
                  label={`Theme: ${theme === 'dark' ? 'Dark' : 'Light'}`}
                  checked={theme === 'dark'}
                  onChange={(checked) => setTheme(checked ? 'dark' : 'light')}
                  size="md"
                />
              </Stack>
            )}

            {step === 3 && (
              <Stack gap={12}>
                <Text variant="bodyLarge" weight="semibold" color="var(--ggui-color-onSurface, #18181b)">
                  Review & Confirm
                </Text>

                <Card
                  padding={16}
                  shadow="none"
                  radius="md"
                  border
                  style={{
                    background: 'var(--ggui-color-surfaceVariant, #f4f4f5)',
                    borderColor: 'var(--ggui-color-outlineVariant, #e4e4e7)',
                  }}
                >
                  <Stack gap={8}>
                    <Text variant="body"><strong>Name:</strong> {name || '—'}</Text>
                    <Text variant="body"><strong>Email:</strong> {email || '—'}</Text>
                    <Text variant="body"><strong>Avatar:</strong> {avatar || '—'}</Text>
                    <Text variant="body"><strong>Role:</strong> {role || '—'}</Text>
                    <Text variant="body">
                      <strong>Email notifications:</strong> {emailNotifications ? 'On' : 'Off'}
                    </Text>
                    <Text variant="body"><strong>Theme:</strong> {theme}</Text>
                  </Stack>
                </Card>
              </Stack>
            )}
          </Stack>

          <Stack direction="horizontal" justify="between" align="center">
            <Button variant="ghost" onClick={handleBack} disabled={step === 1}>
              Back
            </Button>

            {step < 3 ? (
              <Button variant="primary" onClick={handleNext} disabled={!canNext}>
                Next
              </Button>
            ) : (
              <Stack direction="horizontal" gap={8}>
                <Button variant="outline" onClick={handleBack}>
                  Go Back
                </Button>
                <Button variant="primary" onClick={handleComplete} disabled={!(step1Valid && step2Valid)}>
                  Complete Setup
                </Button>
              </Stack>
            )}
          </Stack>
        </Stack>
      </Card>
    </>
  );
}

import React from 'react';
import { Card, Stack, Text, Divider, Box, Icon } from '@ggui-ai/design/primitives';

/**
 * Weather forecast item contract.
 */
interface ForecastItem {
  /** Day name (e.g., "Mon", "Tue") */
  day?: string;
  /** Emoji icon representing the weather (e.g., "☀️") */
  icon?: string;
  /** High temperature for the day */
  high?: number;
  /** Low temperature for the day */
  low?: number;
}

/**
 * Props for the WeatherCard component.
 */
interface Props {
  /** City name to display */
  city: string;
  /** Current numeric temperature */
  temperature: number;
  /** Weather condition string (e.g., "Sunny", "Partly Cloudy") */
  condition: string;
  /** Humidity percentage (0-100) */
  humidity: number;
  /** Wind speed in numeric value */
  windSpeed: number;
  /** Temperature unit (C or F). Defaults to C. */
  unit?: string;
  /** Array of forecast objects */
  forecast: ForecastItem[];
}

/**
 * WeatherCard Component
 * Displays current weather details and a weekly forecast strip.
 * Utilizes GGUI design tokens for layout, color, and typography.
 */
export default function WeatherCard(props: Props) {
  const {
    city,
    temperature,
    condition,
    humidity,
    windSpeed,
    unit = 'C',
    forecast = [],
  } = props;

  const displayUnit = unit === 'F' ? '°F' : '°C';

  // Helper to resolve condition icon if data is missing an explicit icon
  const getConditionEmoji = (cond: string) => {
    const c = cond.toLowerCase();
    if (c.includes('sun') || c.includes('clear')) return '☀️';
    if (c.includes('rain') || c.includes('drizzle') || c.includes('shower')) return '🌧️';
    if (c.includes('storm') || c.includes('thunder')) return '⛈️';
    if (c.includes('cloud') && c.includes('partly')) return '⛅';
    if (c.includes('cloud')) return '☁️';
    if (c.includes('snow') || c.includes('ice')) return '❄️';
    if (c.includes('mist') || c.includes('fog')) return '🌫️';
    return '⛅'; 
  };

  return (
    <Card 
      padding={0} 
      shadow="md" 
      radius="xl" 
      border={true}
      style={{ 
        maxWidth: '440px',
        overflow: 'hidden',
        backgroundColor: 'var(--ggui-color-surface, #fafafa)'
      }}
    >
      {/* Header / Hero Section: Background uses primary gradient for prominence */}
      <Box 
        padding={24} 
        style={{
          background: 'linear-gradient(135deg, var(--ggui-color-primary-600, #0284c7), var(--ggui-color-primary-800, #075985))'
        }}
      >
        <Stack gap={24}>
          <Stack gap={4}>
            <Text 
              variant="bodyLarge" 
              weight="bold" 
              color="var(--ggui-color-primary-50, #f0f9ff)"
            >
              {city}
            </Text>
            <Text 
              variant="overline" 
              color="var(--ggui-color-primary-200, #bae6fd)"
            >
              Current Conditions
            </Text>
          </Stack>

          <Stack direction="horizontal" align="center" justify="between">
            <Stack gap={4}>
              <Text 
                size="4xl" 
                weight="bold" 
                color="var(--ggui-color-neutral-50, #ffffff)"
              >
                {Math.round(temperature)}{displayUnit}
              </Text>
              <Text 
                variant="bodyLarge" 
                weight="medium" 
                color="var(--ggui-color-primary-100, #e0f2fe)"
              >
                {condition}
              </Text>
            </Stack>

            {/* Main Weather Visual */}
            <Box style={{ fontSize: '64px' }}>
              {getConditionEmoji(condition)}
            </Box>
          </Stack>
        </Stack>
      </Box>

      {/* Detail Stats: Humidity and Wind */}
      <Box paddingX={24} paddingY={20}>
        <Stack direction="horizontal" gap={0} justify="between" align="center">
          <Stack gap={8} align="center" direction="horizontal">
            <Icon name="plus" size={18} color="var(--ggui-color-primary-500, #0ea5e9)" />
            <Stack gap={2}>
              <Text variant="caption" color="var(--ggui-color-neutral-500, #6b7280)">Humidity</Text>
              <Text variant="bodySmall" weight="semibold" color="var(--ggui-color-onSurface, #18181b)">
                {humidity}%
              </Text>
            </Stack>
          </Stack>

          <Divider orientation="vertical" margin={20} color="var(--ggui-color-outlineVariant, #e4e4e7)" />

          <Stack gap={8} align="center" direction="horizontal">
            <Icon name="menu" size={18} color="var(--ggui-color-primary-500, #0ea5e9)" />
            <Stack gap={2}>
              <Text variant="caption" color="var(--ggui-color-neutral-500, #6b7280)">Wind Speed</Text>
              <Text variant="bodySmall" weight="semibold" color="var(--ggui-color-onSurface, #18181b)">
                {windSpeed} km/h
              </Text>
            </Stack>
          </Stack>
        </Stack>
      </Box>

      <Divider margin={0} color="var(--ggui-color-outlineVariant, #e4e4e7)" />

      {/* Forecast Strip: A muted strip at the bottom */}
      <Box 
        padding={20} 
        background="var(--ggui-color-surfaceVariant, #f4f4f5)"
      >
        <Stack direction="horizontal" justify="between" align="stretch" gap={12}>
          {forecast.map((item, index) => (
            <Stack 
              key={`${item.day || index}`} 
              align="center" 
              gap={8} 
              style={{ flex: 1 }}
            >
              <Text 
                variant="caption" 
                weight="semibold" 
                color="var(--ggui-color-onSurfaceVariant, #52525b)"
              >
                {item.day || '---'}
              </Text>

              <Box style={{ fontSize: '24px' }}>
                {item.icon || '☀️'}
              </Box>

              <Stack gap={2} align="center">
                <Text 
                  size="sm" 
                  weight="bold" 
                  color="var(--ggui-color-onSurface, #18181b)"
                >
