                </Text>
                <Text 
                  size="xs" 
                  color="var(--ggui-color-neutral-500, #6b7280)"
                >
                  {Math.round(item.low ?? 0)}°
                </Text>
              </Stack>
            </Stack>
          ))}
        </Stack>
      </Box>
    </Card>
  );
}

// Meta for GGUI platform
export const __GGUI_META__ = {
  category: 'data-display',
  description: 'A comprehensive weather card showing current conditions and a 5-day forecast.',
};

import React, { useState, useMemo } from 'react';
import {
  Stack,
  Card,
  Text,
  Heading,
  Input,
  TextArea,
  Button,
  RadioGroup,
  Checkbox,
  Progress,
  Divider,
  Container,
  Box,
  Alert,
  Icon,
} from '@ggui-ai/design/primitives';

interface Props {
  featureOptions: string[];
  satisfactionLabels: string[];
  /** Wired to "Submit Survey" action */
  onSubmit?: (data: SurveyData) => void;
}

interface SurveyData {
  name: string;
  email: string;
  satisfaction: string;
  features: string[];
  comments: string;
}

export default function MultiStepSurvey({
  featureOptions = ['Speed', 'Design', 'Reliability'],
  satisfactionLabels = ['Bad', 'OK', 'Good'],
  onSubmit,
}: Props) {
  const [step, setStep] = useState(1);
  const [isSubmitted, setIsSubmitted] = useState(false);
  const [formData, setFormData] = useState<SurveyData>({
    name: '',
    email: '',
    satisfaction: '',
    features: [],
    comments: '',
  });

  const [errors, setErrors] = useState({ name: '', email: '' });

  const validateEmail = (email: string) => /^[^\s@]+@[^\s@]+\.[^\s@]+$/.test(email);

  const handleNameChange = (v: string) => {
    setFormData(p => ({ ...p, name: v }));
    setErrors(p => ({ ...p, name: v.trim() === '' ? 'Required' : '' }));
  };

  const handleEmailChange = (v: string) => {
    setFormData(p => ({ ...p, email: v }));
    setErrors(p => ({ ...p, email: !validateEmail(v) ? 'Invalid' : '' }));
  };

  const isStepValid = useMemo(() => {
    if (step === 1) return formData.name.trim() !== '' && validateEmail(formData.email);
    if (step === 2) return formData.satisfaction !== '';
    if (step === 3 || step === 4) return true;
    return true;
  }, [step, formData]);

  const handleSubmit = () => {
    if (onSubmit) onSubmit(formData);
    setIsSubmitted(true);
  };

  if (isSubmitted) {
    return (
      <Container maxWidth="sm" padding="var(--ggui-spacing-12, 48px)">
        <Card shadow="md" padding={40} radius="xl">
          <Stack gap={24} align="center">
            <Box background="var(--ggui-color-success-50, #f0fdf4)" borderRadius="var(--ggui-shape-radius-full, 9999px)" padding={20}><Icon name="check" size={48} color="var(--ggui-color-success-600)" /></Box>
            <Heading level={2}>Submitted</Heading>
            <Text>Thank you for your feedback!</Text>
            <Button variant="outline" onClick={() => { setStep(1); setIsSubmitted(false); setFormData({ name: '', email: '', satisfaction: '', features: [], comments: '' }); }}>Restart</Button>
          </Stack>
        </Card>
      </Container>
    );
  }

  return (
    <Container maxWidth="md" padding="var(--ggui-spacing-6, 24px)">
      <Card shadow="lg" padding={0} radius="xl" border={true}>
        <Box padding={24} background="var(--ggui-color-surfaceVariant, #f4f4f5)">
          <Stack gap={16}>
            <Stack direction="horizontal" justify="between">
              <Heading level={4}>Survey</Heading>
              <Text variant="label" color="var(--ggui-color-primary-600)">Step {Math.min(step, 4)}/4</Text>
            </Stack>
            <Progress value={step === 5 ? 100 : (step / 4) * 100} size="md" />
          </Stack>
        </Box>
        <Divider margin={0} color="var(--ggui-color-outline, #d4d4d8)" />

        <Box padding={32} background="var(--ggui-color-surface, #fafafa)">
          <div style={{ minHeight: '340px' }}>
            {/* Step 1: Info */}
            <div style={{ display: step === 1 ? 'block' : 'none' }}>
              <Stack gap={24}>
                <Heading level={3}>Info</Heading>
                <Input label="Name" value={formData.name} onChange={handleNameChange} error={errors.name} required />
                <Input label="Email" value={formData.email} onChange={handleEmailChange} error={errors.email} required type="email" />
              </Stack>
            </div>

            {/* Step 2: Satisfaction */}
            <div style={{ display: step === 2 ? 'block' : 'none' }}>
              <Stack gap={24}>
                <Heading level={3}>Rating</Heading>
                <RadioGroup label="Satisfied?" value={formData.satisfaction} onChange={v => setFormData(p => ({ ...p, satisfaction: v }))} options={satisfactionLabels.map((l, i) => ({ value: String(i+1), label: l }))} />
              </Stack>
            </div>

            {/* Step 3: Features */}
            <div style={{ display: step === 3 ? 'block' : 'none' }}>
              <Stack gap={24}>
                <Heading level={3}>Features</Heading>
                {featureOptions.map(o => (
                  <Checkbox key={o} label={o} checked={formData.features.includes(o)} onChange={c => setFormData(p => ({ ...p, features: c ? [...p.features, o] : p.features.filter(f => f !== o) }))} />
                ))}
              </Stack>
            </div>

            {/* Step 4: Comments */}
            <div style={{ display: step === 4 ? 'block' : 'none' }}>
              <Stack gap={24}>
                <Heading level={3}>Comments</Heading>
                <TextArea label="Feedback" value={formData.comments} onChange={v => setFormData(p => ({ ...p, comments: v }))} maxLength={500} showCount rows={6} />
              </Stack>
            </div>

            {/* Step 5: Review */}
            <div style={{ display: step === 5 ? 'block' : 'none' }}>
              <Stack gap={24}>
                <Heading level={3}>Review</Heading>
                <Box padding={24} background="var(--ggui-color-surfaceVariant)" borderRadius="8px">
                  <Stack gap={12}>
                    <Text variant="bodySmall">Name: {formData.name}</Text>
                    <Text variant="bodySmall">Email: {formData.email}</Text>
                    <Text variant="bodySmall">Rating: {satisfactionLabels[Number(formData.satisfaction)-1]}</Text>
                    <Text variant="bodySmall">Features: {formData.features.join(', ') || 'None'}</Text>
                  </Stack>
                </Box>
                <Alert variant="info" title="Almost there">Submit your survey below.</Alert>
              </Stack>
            </div>
          </div>
        </Box>

        <Divider margin={0} color="var(--ggui-color-outline, #d4d4d8)" />
        <Box padding={24} background="var(--ggui-color-surfaceVariant, #f4f4f5)">
          <Stack direction="horizontal" justify="between">
            <Button variant="ghost" onClick={() => setStep(s => s - 1)} disabled={step === 1} leftIcon={<Icon name="chevron-left" size={16} />}>Back</Button>
            {step === 5 ? (
              <Button variant="primary" onClick={handleSubmit}>Submit Survey</Button>
            ) : (
              <Button variant="primary" onClick={() => setStep(s => s + 1)} disabled={!isStepValid} rightIcon={<Icon name="chevron-right" size={16} />}>Next</Button>
            )}
          </Stack>
        </Box>
      </Card>
    </Container>
  );
}

import React, { useState, useMemo } from 'react';
import {
  Box,
  Card,
  Stack,
  Text,
  Heading,
  Divider,
  Container,
  Button,
} from '@ggui-ai/design/primitives';
import { SearchField } from '@ggui-ai/design/components';

interface ElementData {
  atomicNumber?: number;
  symbol?: string;
  name?: string;
  atomicWeight?: number;
  category?: string;
  row?: number;
  col?: number;
}

interface Props {
  /** Full periodic table element data */
  elements: ElementData[];
}

/**
 * Maps category strings to theme-aware design tokens.
 * Using semantic color roles where possible.
 */
const getCategoryColor = (category: string = ''): string => {
  const cat = category.toLowerCase();
  if (cat.includes('noble gas')) return 'var(--ggui-color-info-500, #06b6d4)';
  if (cat.includes('alkali metal')) return 'var(--ggui-color-error-600, #dc2626)';
  if (cat.includes('alkaline earth')) return 'var(--ggui-color-warning-500, #f59e0b)';
  if (cat.includes('transition metal')) return 'var(--ggui-color-primary-500, #0ea5e9)';
  if (cat.includes('post-transition')) return 'var(--ggui-color-success-600, #16a34a)';
  if (cat.includes('metalloid')) return 'var(--ggui-color-success-400, #4ade80)';
  if (cat.includes('reactive nonmetal') || cat.includes('polyatomic nonmetal') || cat.includes('diatomic nonmetal')) 
    return 'var(--ggui-color-primary-700, #0369a1)';
  if (cat.includes('lanthanide')) return 'var(--ggui-color-primary-200, #bae6fd)';
  if (cat.includes('actinide')) return 'var(--ggui-color-primary-300, #7dd3fc)';
  return 'var(--ggui-color-neutral-300, #d1d5db)';
};

export default function InteractivePeriodicTable(props: Props) {
  const { elements = [] } = props;
  const [searchTerm, setSearchTerm] = useState('');
  const [selectedSymbol, setSelectedSymbol] = useState<string | null>(null);

  const filteredElements = useMemo(() => {
    if (!searchTerm) return elements;
    const term = searchTerm.toLowerCase();
    return elements.filter(
      (el) =>
        (el.name || '').toLowerCase().includes(term) ||
        (el.symbol || '').toLowerCase().includes(term)
    );
  }, [elements, searchTerm]);

  const selectedElement = useMemo(
    () => elements.find((el) => el.symbol === selectedSymbol),
    [elements, selectedSymbol]
  );

  // Group categories for the legend
  const categories = useMemo(() => {
    const set = new Set<string>();
    elements.forEach((el) => {
      if (el.category) set.add(el.category);
    });
    return Array.from(set).sort();
  }, [elements]);

  return (
    <Container maxWidth="3xl" padding="var(--ggui-spacing-6, 24px)">
      <Stack gap="var(--ggui-spacing-6, 24px)">
        {/* Header and Search */}
        <Stack direction="horizontal" align="center" justify="between" wrap>
          <Stack gap="var(--ggui-spacing-1, 4px)">
            <Heading level={2}>Periodic Table</Heading>
            <Text variant="bodySmall" color="var(--ggui-color-onSurfaceVariant)">
              Click an element for details.
            </Text>
          </Stack>
          <Box style={{ width: '100%', maxWidth: '320px' }}>
            <SearchField
              value={searchTerm}
              onChange={setSearchTerm}
              placeholder="Filter by name or symbol..."
            />
          </Box>
        </Stack>

        {/* Legend */}
        <Box
          padding="var(--ggui-spacing-4, 16px)"
          borderRadius="var(--ggui-shape-radius-md, 8px)"
          background="var(--ggui-color-surfaceVariant, #f4f4f5)"
        >
          <Stack direction="horizontal" gap="var(--ggui-spacing-4, 16px)" wrap justify="center">
            {categories.map((cat) => (
              <Stack key={cat} direction="horizontal" gap="var(--ggui-spacing-2, 8px)" align="center">
                <Box
                  style={{
                    width: '12px',
                    height: '12px',
                    borderRadius: 'var(--ggui-shape-radius-sm, 4px)',
                    backgroundColor: getCategoryColor(cat),
                  }}
                />
                <Text variant="caption" weight="medium">
                  {cat}
                </Text>
              </Stack>
            ))}
          </Stack>
        </Box>

        {/* Periodic Table Grid */}
        <Box
          style={{
            display: 'grid',
            gridTemplateColumns: 'repeat(18, 1fr)',
            gap: 'var(--ggui-spacing-1, 4px)',
            overflowX: 'auto',
            paddingBottom: 'var(--ggui-spacing-4, 16px)',
            minWidth: '900px',
          }}
        >
          {elements.map((el) => {
            const isMatch = filteredElements.some((fe) => fe.symbol === el.symbol);
            const isSelected = selectedSymbol === el.symbol;
            const categoryColor = getCategoryColor(el.category);

            return (
              <Box
                key={el.symbol}
                style={{
                  gridRow: el.row,
                  gridColumn: el.col,
                  aspectRatio: '1/1',
                  transition: 'all 0.2s ease',
                  opacity: isMatch ? 1 : 0.3,
                  transform: isSelected ? 'scale(1.1)' : 'scale(1)',
                  zIndex: isSelected ? 10 : 1,
                }}
              >
                <Button
                  onPress={() => setSelectedSymbol(el.symbol || null)}
                  variant="ghost"
                  fullWidth
                  style={{
                    height: '100%',
                    padding: 0,
                    backgroundColor: isMatch ? categoryColor : 'var(--ggui-color-neutral-100, #f3f4f6)',
                    border: isSelected
                      ? '2px solid var(--ggui-color-onSurface, #18181b)'
                      : '1px solid var(--ggui-color-outline, #d4d4d8)',
                    borderRadius: 'var(--ggui-shape-radius-sm, 4px)',
                    display: 'flex',
                    flexDirection: 'column',
                    alignItems: 'center',
                    justifyContent: 'center',
                    color: 'var(--ggui-color-onSurface, #18181b)',
                    boxShadow: isSelected ? 'var(--ggui-shape-shadow-lg)' : 'none',
                    position: 'relative',
                  }}
                >
                  <Box
                    style={{
                      position: 'absolute',
                      top: 'var(--ggui-spacing-1, 4px)',
                      left: 'var(--ggui-spacing-1, 4px)',
                    }}
                  >
                    <Text size="xs" weight="bold" style={{ lineHeight: 1 }}>
                      {el.atomicNumber}
                    </Text>
                  </Box>
                  <Text size="lg" weight="bold">
                    {el.symbol}
                  </Text>
                </Button>
              </Box>
            );
          })}
        </Box>

        {/* Detail Panel */}
        {selectedElement && (
          <Card padding="var(--ggui-spacing-6, 24px)" shadow="md" radius="lg">
            <Stack direction="horizontal" gap="var(--ggui-spacing-8, 32px)" align="start" wrap>
              {/* Large Element Display */}
              <Box
                padding="var(--ggui-spacing-6, 24px)"
                borderRadius="var(--ggui-shape-radius-lg, 12px)"
                background={getCategoryColor(selectedElement.category)}
                style={{
                  display: 'flex',
                  flexDirection: 'column',
                  alignItems: 'center',
                  justifyContent: 'center',
                  minWidth: '140px',
                  minHeight: '140px',
                  border: '2px solid var(--ggui-color-outline, #d4d4d8)',
                }}
              >
                <Text variant="bodyLarge" weight="bold">
                  {selectedElement.atomicNumber}
                </Text>
                <Text style={{ fontSize: 'var(--ggui-font-size-4xl, 36px)', fontWeight: 'var(--ggui-font-weight-bold, 700)' }}>
                  {selectedElement.symbol}
                </Text>
                <Text variant="caption" weight="medium">
                  {selectedElement.atomicWeight}
                </Text>
              </Box>

              {/* Data List */}
              <Stack gap="var(--ggui-spacing-4, 16px)" style={{ flex: 1, minWidth: '280px' }}>
                <Stack gap="var(--ggui-spacing-1, 4px)">
                  <Heading level={3}>{selectedElement.name}</Heading>
                  <Text variant="label" color="var(--ggui-color-primary-700, #0369a1)">
                    {selectedElement.category}
                  </Text>
                </Stack>

                <Divider margin="var(--ggui-spacing-2, 8px)" />

                <Stack direction="horizontal" gap="var(--ggui-spacing-8, 32px)" wrap>
                  <Stack gap="var(--ggui-spacing-1, 4px)">
                    <Text variant="overline" color="var(--ggui-color-onSurfaceVariant, #52525b)">
                      Atomic Weight
                    </Text>
                    <Text weight="semibold" size="lg">{selectedElement.atomicWeight} u</Text>
                  </Stack>
                  <Stack gap="var(--ggui-spacing-1, 4px)">
                    <Text variant="overline" color="var(--ggui-color-onSurfaceVariant, #52525b)">
                      Position
                    </Text>
                    <Text weight="semibold" size="lg">Period {selectedElement.row}, Group {selectedElement.col}</Text>
                  </Stack>
                </Stack>
              </Stack>
            </Stack>
          </Card>
        )}
      </Stack>
    </Container>
  );
}

import React, { useState, useEffect, useRef } from 'react';
import {
  Card,
  Stack,
  Text,
  Button,
  Input,
  Box,
  Badge,
} from '@ggui-ai/design/primitives';

interface Props {
  title: string;
  currentUser: string;
  participantCount?: number;
  messages: Array<{ sender?: string; text?: string; timestamp?: string }>;
  sendMessage: (payload: { text: string; timestamp: string }) => void;
}

export default function ChatInterface(props: Props) {
  const [inputValue, setInputValue] = useState('');
  const scrollRef = useRef<HTMLDivElement>(null);

  useEffect(() => {
    if (scrollRef.current) {
      scrollRef.current.scrollTop = scrollRef.current.scrollHeight;
    }
  }, [props.messages]);

  const onSend = () => {
    if (!inputValue.trim()) return;
    props.sendMessage({ text: inputValue.trim(), timestamp: new Date().toISOString() });
    setInputValue('');
  };

  return (
    <Card padding={0} shadow="md" radius="lg" border>
      <div style={{ height: '600px', display: 'flex', flexDirection: 'column' }}>
        <Box paddingX="var(--ggui-spacing-4, 16px)" paddingY="var(--ggui-spacing-3, 12px)" background="var(--ggui-color-surface)" style={{ borderBottom: '1px solid var(--ggui-color-outlineVariant)' }}>
          <Stack direction="horizontal" align="center" justify="between">
            <Stack direction="horizontal" gap="var(--ggui-spacing-2, 8px)" align="center">
              <Text weight="bold" size="lg">{props.title}</Text>
              {props.participantCount !== undefined && <Badge variant="secondary" size="sm" pill>{props.participantCount} participants</Badge>}
            </Stack>
          </Stack>
        </Box>

        <div ref={scrollRef} style={{ flex: 1, overflowY: 'auto', background: 'var(--ggui-color-surfaceVariant)', padding: 'var(--ggui-spacing-4, 16px)', display: 'flex', flexDirection: 'column', gap: 'var(--ggui-spacing-3, 12px)', scrollBehavior: 'smooth' }}>
          {props.messages.map((m, i) => {
            const isMe = m.sender === props.currentUser;
            const isF = i === 0 || props.messages[i - 1].sender !== m.sender;
            const t = m.timestamp ? new Date(m.timestamp).toLocaleTimeString([], { hour: '2-digit', minute: '2-digit' }) : '';
            return (
              <div key={i} style={{ alignSelf: isMe ? 'flex-end' : 'flex-start', maxWidth: '85%', display: 'flex', flexDirection: 'column', alignItems: isMe ? 'flex-end' : 'flex-start', gap: 'var(--ggui-spacing-1, 4px)' }}>
                {isF && !isMe && <Text variant="label" size="xs" color="var(--ggui-color-onSurfaceVariant)">{m.sender}</Text>}
                <div style={{ padding: 'var(--ggui-spacing-2, 8px) var(--ggui-spacing-3, 12px)', borderRadius: 'var(--ggui-shape-radius-md)', background: isMe ? 'var(--ggui-color-primary-600)' : 'var(--ggui-color-surface)', border: isMe ? 'none' : '1px solid var(--ggui-color-outlineVariant)', color: isMe ? '#ffffff' : 'var(--ggui-color-onSurface)', boxShadow: 'var(--ggui-shape-shadow-sm)', wordBreak: 'break-word' }}>
                  <Stack gap="var(--ggui-spacing-1, 4px)">
                    <Text color="inherit" size="sm">{m.text}</Text>
                    <div style={{ textAlign: 'right' }}><Text size="xs" color={isMe ? 'rgba(255,255,255,0.7)' : 'var(--ggui-color-onSurfaceVariant)'}>{t}</Text></div>
                  </Stack>
                </div>
              </div>
            );
          })}
        </div>

        <Box padding="var(--ggui-spacing-4, 16px)" background="var(--ggui-color-surface)" style={{ borderTop: '1px solid var(--ggui-color-outlineVariant)' }}>
          <Stack direction="horizontal" gap="var(--ggui-spacing-3, 12px)" align="end">
            <Box style={{ flex: 1 }}>
              <Input label="Message" value={inputValue} onChange={setInputValue} placeholder="Type a message..." onKeyDown={(e: any) => { if (e.key === 'Enter' && !e.shiftKey) { e.preventDefault(); onSend(); } }} />
            </Box>
            <Box style={{ paddingBottom: 'var(--ggui-spacing-1, 4px)' }}>
              <Button variant="primary" disabled={!inputValue.trim()} onClick={onSend}>Send Message</Button>
            </Box>
          </Stack>
        </Box>
      </div>
    </Card>
  );
}

import React, { useState, useEffect } from 'react';
import {
  Container,
  Stack,
  Text,
  Heading,
  Card,
  Box,
  Spinner,
  Icon,
} from '@ggui-ai/design/primitives';
import { CardGrid } from '@ggui-ai/design/compositions';

interface Props {
  /** ISO timestamp of last price update */
  lastUpdated?: string;
  /** Array of stocks with symbol, name, price, change, changePercent */
  stocks: Array<{ symbol?: string; name?: string; price?: number; change?: number; changePercent?: number }>;
}

/**
 * Market Dashboard Component
 * Displays live stock ticker data from properties and broadcast stream.
 */
export default function GeneratedComponent(props: Props) {
  const [data, setData] = useState(props.stocks || []);
  const [stamp, setStamp] = useState(props.lastUpdated);
  const [loading, setLoading] = useState(!props.stocks || props.stocks.length === 0);

  useEffect(() => {
    if (props.stocks) {
      setData(props.stocks);
      setLoading(false);
    }
    setStamp(props.lastUpdated);
  }, [props.stocks, props.lastUpdated]);

  useEffect(() => {
    const handleBroadcast = (event: any) => {
      const detail = event.detail;
      if (detail) {
        if (detail.stocks) {
          setData(detail.stocks);
          setLoading(false);
        }
        if (detail.lastUpdated) {
          setStamp(detail.lastUpdated);
        }
      }
    };

    if (typeof globalThis !== 'undefined') {
      const g = globalThis;
      g.addEventListener('ggui:agent-data', handleBroadcast);
      return () => g.removeEventListener('ggui:agent-data', handleBroadcast);
    }
  }, []);

  const formatPrice = (p?: number) => new Intl.NumberFormat('en-US', { style: 'currency', currency: 'USD' }).format(p ?? 0);

  if (loading && data.length === 0) {
    return (
      <Container padding={64}>
        <Stack align="center" gap={16}>
          <Spinner size={32} color="var(--ggui-color-primary-600)" />
          <Text color="var(--ggui-color-onSurfaceVariant)">Establishing market connection...</Text>
        </Stack>
      </Container>
    );
  }

  return (
    <Container maxWidth="xl" padding="var(--ggui-spacing-6)">
      <Stack gap={24}>
        <Stack direction="horizontal" justify="between" align="center" wrap gap={12}>
          <Stack gap={2}>
            <Heading level={2} color="var(--ggui-color-onSurface)">Market Watch</Heading>
            <Text variant="bodySmall" color="var(--ggui-color-onSurfaceVariant)">Real-time ticker analysis</Text>
          </Stack>
          <Box paddingX={12} paddingY={6} background="var(--ggui-color-surfaceVariant)" borderRadius="var(--ggui-shape-radius-full)">
            <Text variant="caption" weight="medium" color="var(--ggui-color-onSurfaceVariant)">
              Last Sync: {stamp ? new Date(stamp).toLocaleTimeString() : 'N/A'}
            </Text>
          </Box>
        </Stack>

        <CardGrid columns={{ sm: 1, md: 3, lg: 3 }} gap={16}>
          {data.map((s, idx) => {
            const pos = (s.change ?? 0) >= 0;
            const color = pos ? 'var(--ggui-color-success-600)' : 'var(--ggui-color-error-600)';
            const bg = pos ? 'var(--ggui-color-success-50)' : 'var(--ggui-color-error-50)';
            const border = pos ? 'var(--ggui-color-success-200)' : 'var(--ggui-color-error-200)';

            return (
              <Card 
                key={s.symbol || idx} 
                padding={24} 
                radius="lg" 
                border 
                style={{ 
                  borderTop: `4px solid ${color}`,
                  borderColor: border,
                  backgroundColor: 'var(--ggui-color-surface)' 
                }}
              >
                <Stack gap={20}>
                  <Stack direction="horizontal" justify="between" align="start">
                    <Stack gap={0}>
                      <Text size="xl" weight="bold" color="var(--ggui-color-onSurface)">{s.symbol || '---'}</Text>
                      <Text variant="caption" color="var(--ggui-color-onSurfaceVariant)" truncate>{s.name || '---'}</Text>
                    </Stack>
                    <Box paddingX={8} paddingY={4} background={bg} borderRadius="var(--ggui-shape-radius-sm)">
                      <Stack direction="horizontal" gap={4} align="center">
                        <Icon name={pos ? 'chevron-up' : 'chevron-down'} size={12} color={color} />
                        <Text size="xs" weight="bold" color={color}>{(s.changePercent ?? 0).toFixed(2)}%</Text>
                      </Stack>
                    </Box>
                  </Stack>

                  <Stack direction="horizontal" justify="between" align="end">
                    <Text size="2xl" weight="bold" color="var(--ggui-color-onSurface)">{formatPrice(s.price)}</Text>
                    <Text size="sm" weight="semibold" color={color}>{pos ? '+' : ''}{(s.change ?? 0).toFixed(2)}</Text>
                  </Stack>
                </Stack>
              </Card>
            );
          })}
        </CardGrid>
      </Stack>
    </Container>
  );
}

import React, { useState } from 'react';
import {
  Stack,
  Container,
  Card,
  Text,
  Heading,
  Input,
  Select,
  Toggle,
  Button,
  Progress,
  Divider,
  Avatar,
  Box,
  Spacer,
  Icon
} from '@ggui-ai/design/primitives';

interface Props {
  avatarOptions: string[];
  roleOptions: string[];
  initialProfile?: {
    name?: string;
    email?: string;
    avatar?: string;
    role?: string;
    emailNotifications?: boolean;
    theme?: string;
  };
  complete: (data: {
    name: string;
    email: string;
    avatar: string;
    role: string;
    emailNotifications: boolean;
    theme: string;
  }) => void;
}

export default function GeneratedComponent(props: Props) {
  const { avatarOptions, roleOptions, initialProfile, complete } = props;

  const [step, setStep] = useState(1);
  const [formData, setFormData] = useState({
    name: initialProfile?.name || '',
    email: initialProfile?.email || '',
    avatar: initialProfile?.avatar || (avatarOptions && avatarOptions.length > 0 ? avatarOptions[0] : ''),
    role: initialProfile?.role || '',
    emailNotifications: initialProfile?.emailNotifications ?? true,
    theme: initialProfile?.theme || 'light',
  });

  const handleUpdate = (field: string, value: any) => {
    setFormData((prev) => ({ ...prev, [field]: value }));
  };

  const isEmailValid = (email: string) => /^[^\s@]+@[^\s@]+\.[^\s@]+$/.test(email);

  const isStep1Valid = formData.name.trim().length > 0 && isEmailValid(formData.email) && !!formData.avatar;
  const isStep2Valid = !!formData.role;

  const handleNext = () => setStep((s) => Math.min(s + 1, 3));
  const handleBack = () => setStep((s) => Math.max(s - 1, 1));
  const handleComplete = () => complete(formData);

  const progressValue = (step / 3) * 100;

  return (
    <Container maxWidth="md" padding="var(--ggui-spacing-8, 32px) var(--ggui-spacing-4, 16px)">
      <Stack gap={24}>
        <Stack gap={12}>
          <Stack direction="horizontal" justify="between" align="end">
            <Stack gap={4}>
              <Text variant="overline" color="var(--ggui-color-primary-600, #0284c7)">Account Setup</Text>
              <Heading level={2}>
                {step === 1 ? 'Profile Setup' : step === 2 ? 'Preferences' : 'Final Review'}
              </Heading>
            </Stack>
            <Text variant="label" color="var(--ggui-color-neutral-500, #6b7280)">Step {step} of 3</Text>
          </Stack>
          <Progress value={progressValue} size="md" />
        </Stack>

        <Card padding={32} shadow="md" radius="xl" border>
          {step === 1 && (
            <Stack gap={24}>
              <Stack gap={16}>
                <Stack gap={4}>
                  <label htmlFor="name-input" style={{ fontSize: 'var(--ggui-font-size-sm)', fontWeight: 'var(--ggui-font-weight-medium)', color: 'var(--ggui-color-neutral-700)' }}>Full Name</label>
                  <Input id="name-input" label="Full Name" placeholder="Jane Doe" value={formData.name} onChange={(v) => handleUpdate('name', v)} required />
                </Stack>
                <Stack gap={4}>
                  <label htmlFor="email-input" style={{ fontSize: 'var(--ggui-font-size-sm)', fontWeight: 'var(--ggui-font-weight-medium)', color: 'var(--ggui-color-neutral-700)' }}>Email Address</label>
                  <Input id="email-input" label="Email Address" type="email" placeholder="jane@example.com" value={formData.email} onChange={(v) => handleUpdate('email', v)} required />
                </Stack>
                <Stack gap={12}>
                  <Text variant="label">Select Avatar</Text>
                  <Stack direction="horizontal" gap={12} wrap>
                    {avatarOptions && avatarOptions.map((emoji) => (
                      <button
                        key={emoji}
                        type="button"
                        onClick={() => handleUpdate('avatar', emoji)}
                        style={{
                          padding: 'var(--ggui-spacing-2, 8px)',
                          borderRadius: 'var(--ggui-shape-radius-full, 9999px)',
                          backgroundColor: formData.avatar === emoji ? 'var(--ggui-color-primary-100, #e0f2fe)' : 'transparent',
                          border: `2px solid ${formData.avatar === emoji ? 'var(--ggui-color-primary-600, #0284c7)' : 'var(--ggui-color-neutral-200, #e5e7eb)'}`,
                          cursor: 'pointer',
                          display: 'flex',
                          alignItems: 'center',
                          justifyContent: 'center',
                          transition: 'all 0.1s'
                        }}
                        aria-label={`Select ${emoji}`}
                      >
                        <Avatar name={emoji} size="md" />
                      </button>
                    ))}
                  </Stack>
                </Stack>
              </Stack>
            </Stack>
          )}

          {step === 2 && (
            <Stack gap={24}>
              <Stack gap={20}>
                <Select
                  label="Organization Role"
                  placeholder="Select a role..."
                  value={formData.role}
                  onChange={(v) => handleUpdate('role', v)}
                  options={(roleOptions || []).map((r) => ({ value: r, label: r }))}
                  required
                />
                <Divider margin={8} />
                <Toggle
                  label="Receive Email Notifications"
                  checked={formData.emailNotifications}
                  onChange={(v) => handleUpdate('emailNotifications', v)}
                />
                <Stack gap={12}>
                  <Text variant="label">Theme Preference</Text>
                  <Stack direction="horizontal" gap={12}>
                    <Button 
                      variant={formData.theme === 'light' ? 'primary' : 'outline'} 
                      size="sm" 
                      onClick={() => handleUpdate('theme', 'light')} 
                      fullWidth
                    >
                      Light
                    </Button>
                    <Button 
                      variant={formData.theme === 'dark' ? 'primary' : 'outline'} 
                      size="sm" 
                      onClick={() => handleUpdate('theme', 'dark')} 
                      fullWidth
                    >
                      Dark
                    </Button>
                  </Stack>
                </Stack>
              </Stack>
            </Stack>
          )}

          {step === 3 && (
            <Stack gap={24}>
              <Box padding={24} background="var(--ggui-color-surfaceVariant, #f4f4f5)" borderRadius={12}>
                <Stack gap={20}>
                  <Stack direction="horizontal" align="center" gap={16}>
                    <Avatar name={formData.avatar} size="lg" />
                    <Stack gap={2}>
                      <Heading level={4}>{formData.name}</Heading>
                      <Text variant="bodySmall" color="var(--ggui-color-neutral-500, #6b7280)">{formData.email}</Text>
                    </Stack>
                  </Stack>
                  <Divider margin={4} />
                  <Stack gap={8}>
                    <Stack direction="horizontal" justify="between">
                      <Text variant="label" color="var(--ggui-color-neutral-500, #6b7280)">Role</Text>
                      <Text weight="medium">{formData.role}</Text>
                    </Stack>
                    <Stack direction="horizontal" justify="between">
                      <Text variant="label" color="var(--ggui-color-neutral-500, #6b7280)">Notifications</Text>
                      <Text weight="medium">{formData.emailNotifications ? 'Enabled' : 'Disabled'}</Text>
                    </Stack>
                    <Stack direction="horizontal" justify="between">
                      <Text variant="label" color="var(--ggui-color-neutral-500, #6b7280)">Theme</Text>
                      <Text weight="medium" style={{ textTransform: 'capitalize' }}>{formData.theme}</Text>
                    </Stack>
                  </Stack>
                </Stack>
              </Box>
            </Stack>
          )}

          <Spacer size={40} />

          <Stack direction="horizontal" justify="between">
            <Button variant="ghost" onClick={handleBack} disabled={step === 1} leftIcon={<Icon name="chevron-left" size={16} />}>Back</Button>
            {step < 3 ? (
              <Button variant="primary" onClick={handleNext} disabled={(step === 1 && !isStep1Valid) || (step === 2 && !isStep2Valid)} rightIcon={<Icon name="chevron-right" size={16} />}>Next</Button>
            ) : (
              <Button variant="primary" onClick={handleComplete} leftIcon={<Icon name="check" size={16} />}>Complete Setup</Button>
            )}
          </Stack>
        </Card>
      </Stack>
    </Container>
  );
}

import React from 'react';
import { 
  Card, 
  Stack, 
  Text, 
  Heading, 
  Divider, 
  Box 
