interface Props {
  /** City name */
  city: string;
  /** Current temperature */
  temperature: number;
  /** Weather condition (Sunny, Cloudy, Rainy, etc.) */
  condition: string;
  /** Humidity percentage */
  humidity: number;
  /** Wind speed */
  windSpeed: number;
  /** Temperature unit (C or F) */
  unit?: string;
  /** 5-day forecast array */
  forecast: Array<{ day?: string; icon?: string; high?: number; low?: number }>;
}

/**
 * WeatherCard Component
 * A visually rich display for current weather and forecast data.
 * All colors and spacing use design system tokens for theme consistency.
 */
export default function WeatherCard({
  city = 'San Francisco',
  temperature = 22,
  condition = 'Partly Cloudy',
  humidity = 65,
  windSpeed = 12,
  unit = 'C',
  forecast = [
    { day: 'Mon', icon: '☀️', high: 24, low: 16 },
    { day: 'Tue', icon: '⛅', high: 22, low: 15 },
    { day: 'Wed', icon: '☁️', high: 19, low: 14 },
    { day: 'Thu', icon: '🌧️', high: 17, low: 12 },
    { day: 'Fri', icon: '☀️', high: 23, low: 16 },
  ],
}: Props) {
  // Simple helper to provide an emoji icon based on the condition text
  const getConditionEmoji = (cond: string) => {
    const c = cond.toLowerCase();
    if (c.includes('sun') || c.includes('clear')) return '☀️';
    if (c.includes('cloud')) return '☁️';
    if (c.includes('rain') || c.includes('drizzle')) return '🌧️';
    if (c.includes('snow')) return '❄️';
    if (c.includes('thunder') || c.includes('storm')) return '⚡';
    return '⛅';
  };

  return (
    <Card 
      padding={0} 
      radius="xl" 
      shadow="md" 
      border={true}
      style={{
        width: '100%',
        maxWidth: '400px',
        overflow: 'hidden',
        backgroundColor: 'var(--ggui-color-surface, #ffffff)',
      }}
    >
      <Box padding={24}>
        <Stack gap={24}>
          {/* Header Section: City and Date */}
          <Stack gap={4}>
            <Heading level={3} color="var(--ggui-color-onSurface, #111827)">
              {city}
            </Heading>
            <Text variant="bodySmall" color="var(--ggui-color-onSurfaceVariant, #52525b)">
              {new Date().toLocaleDateString('en-US', { weekday: 'long', month: 'long', day: 'numeric' })}
            </Text>
          </Stack>

          {/* Current Weather Display */}
          <Stack direction="horizontal" align="center" justify="between">
            <Stack gap={0}>
              <Text 
                size="4xl" 
                weight="bold" 
                color="var(--ggui-color-onSurface, #111827)"
              >
                {temperature}°{unit}
              </Text>
              <Text variant="bodyLarge" weight="medium" color="var(--ggui-color-onSurfaceVariant, #52525b)">
                {condition}
              </Text>
            </Stack>
            <Box style={{ fontSize: '48px', lineHeight: '1' }} aria-hidden="true">
              {getConditionEmoji(condition)}
            </Box>
          </Stack>

          {/* Secondary Stats Strip */}
          <Box 
            background="var(--ggui-color-surfaceVariant, #f4f4f5)" 
            borderRadius="var(--ggui-shape-radius-md, 8px)"
            padding={16}
          >
            <Stack direction="horizontal" justify="between" align="center">
              <Stack align="center" gap={4}>
                <Text variant="overline" color="var(--ggui-color-onSurfaceVariant, #52525b)">HUMIDITY</Text>
                <Text weight="semibold" color="var(--ggui-color-onSurface, #111827)">{humidity}%</Text>
              </Stack>
              <Divider orientation="vertical" margin={8} />
              <Stack align="center" gap={4}>
                <Text variant="overline" color="var(--ggui-color-onSurfaceVariant, #52525b)">WIND SPEED</Text>
                <Text weight="semibold" color="var(--ggui-color-onSurface, #111827)">{windSpeed} km/h</Text>
              </Stack>
            </Stack>
          </Box>

          <Divider margin={0} color="var(--ggui-color-outlineVariant, #e4e4e7)" />

          {/* 5-Day Forecast Strip */}
          <Stack direction="horizontal" justify="between" gap={8} align="center">
            {forecast.map((item, index) => (
              <Stack 
                key={item.day || index} 
                align="center" 
                gap={4} 
                style={{ flex: 1 }}
              >
                <Text 
                  variant="caption" 
                  weight="medium" 
                  color="var(--ggui-color-onSurfaceVariant, #52525b)"
                >
                  {item.day}
                </Text>
                <Text size="lg" aria-hidden="true">
                  {item.icon || '☀️'}
                </Text>
                <Stack gap={0} align="center">
                  <Text size="xs" weight="bold" color="var(--ggui-color-onSurface, #111827)">
                    {item.high}°
                  </Text>
                  <Text size="xs" color="var(--ggui-color-onSurfaceVariant, #52525b)">
                    {item.low}°
                  </Text>
                </Stack>
              </Stack>
            ))}
          </Stack>
        </Stack>
      </Box>
    </Card>
  );
}

import React, { useState } from 'react';
import {
  Container,
  Card,
  Stack,
  Text,
  Heading,
  Button,
  Input,
  TextArea,
  RadioGroup,
  Checkbox,
  Progress,
  Divider,
  Box,
} from '@ggui-ai/design/primitives';

/**
 * Props Contract
 */
interface Props {
  /** Available feature options for the checkbox step */
  featureOptions: string[];
  /** Labels for satisfaction rating (e.g., Very Unsatisfied to Very Satisfied) */
  satisfactionLabels: string[];
  /** Action: Called with all collected answers as a structured object */
  onSubmit: (data: any) => void;
}

/**
 * Multi-step Survey Form
 */
export default function GeneratedComponent(props: Props) {
  const { featureOptions = [], satisfactionLabels = [], onSubmit } = props;

  const [currentStep, setCurrentStep] = useState(1);
  const [formData, setFormData] = useState({
    name: '',
    email: '',
    satisfaction: '',
    features: [] as string[],
    comments: '',
  });

  const [errors, setErrors] = useState({
    name: '',
    email: '',
  });

  const validateEmail = (email: string) => /^[^\s@]+@[^\s@]+\.[^\s@]+$/.test(email);

  const isStep1Valid = formData.name.trim() !== '' && validateEmail(formData.email);
  const isStep2Valid = formData.satisfaction !== '';

  const toggleFeature = (feature: string) => {
    setFormData(prev => ({
      ...prev,
      features: prev.features.includes(feature)
        ? prev.features.filter(f => f !== feature)
        : [...prev.features, feature]
    }));
  };

  const progressValue = Math.min((currentStep / 4) * 100, 100);

  return (
    <Container maxWidth="md" padding="24px">
      <Card padding="32px" shadow="md" radius="xl" border={true}>
        <Stack gap={24}>
          <Stack gap={12}>
            <Heading level={2} align="center">Customer Feedback Survey</Heading>
            <Stack gap={8}>
              <Progress value={progressValue} variant={currentStep === 5 ? 'success' : 'default'} />
              <Text variant="caption" align="right">Step {currentStep <= 4 ? currentStep : 4} of 4</Text>
            </Stack>
          </Stack>

          <Divider />

          <Box style={{ minHeight: '400px' }}>
            {currentStep === 1 && (
              <Stack gap={24}>
                <Heading level={4}>Personal Details</Heading>
                <Stack gap={4}>
                  <Text as="label" variant="label">Full Name</Text>
                  <Input label="Full Name" placeholder="Enter your full name" value={formData.name} required onChange={(v) => {
                    setFormData({ ...formData, name: v });
                    setErrors({ ...errors, name: v.trim() ? '' : 'Name is required' });
                  }} error={errors.name} />
                </Stack>
                <Stack gap={4}>
                  <Text as="label" variant="label">Email Address</Text>
                  <Input label="Email Address" type="email" placeholder="name@example.com" value={formData.email} required onChange={(v) => {
                    setFormData({ ...formData, email: v });
                    setErrors({ ...errors, email: validateEmail(v) ? '' : 'Valid email required' });
                  }} error={errors.email} />
                </Stack>
              </Stack>
            )}

            {currentStep === 2 && (
              <Stack gap={24}>
                <Heading level={4}>Satisfaction</Heading>
                <RadioGroup
                  label="Rating"
                  value={formData.satisfaction}
                  onChange={(v) => setFormData({ ...formData, satisfaction: v })}
                  options={satisfactionLabels.map((l, i) => ({ label: l, value: (i + 1).toString() }))}
                />
              </Stack>
            )}

            {currentStep === 3 && (
              <Stack gap={24}>
                <Heading level={4}>Features</Heading>
                <Stack gap={12}>
                  {featureOptions.map(o => (
                    <Checkbox key={o} label={o} checked={formData.features.includes(o)} onChange={() => toggleFeature(o)} />
                  ))}
                </Stack>
              </Stack>
            )}

            {currentStep === 4 && (
              <Stack gap={24}>
                <Heading level={4}>Comments</Heading>
                <TextArea label="Comments" placeholder="Your thoughts..." value={formData.comments} onChange={(v) => setFormData({ ...formData, comments: v })} maxLength={500} showCount />
              </Stack>
            )}

            {currentStep === 5 && (
              <Stack gap={24}>
                <Heading level={4}>Review</Heading>
                <Box padding="20px" background="var(--ggui-color-surfaceVariant)" borderRadius="12px">
                  <Stack gap={16}>
                    <Box><Text variant="label">Name</Text><Text>{formData.name}</Text></Box>
                    <Box><Text variant="label">Email</Text><Text>{formData.email}</Text></Box>
                    <Box><Text variant="label">Rating</Text><Text>{satisfactionLabels[Number(formData.satisfaction) - 1]}</Text></Box>
                    <Box><Text variant="label">Features</Text><Text>{formData.features.join(', ') || 'None'}</Text></Box>
                    <Box><Text variant="label">Comments</Text><Text>{formData.comments || 'No comments'}</Text></Box>
                  </Stack>
                </Box>
              </Stack>
            )}
          </Box>

          <Divider />

          <Stack direction="horizontal" justify="between">
            <Button variant="ghost" disabled={currentStep === 1} onClick={() => setCurrentStep(prev => prev - 1)}>Back</Button>
            {currentStep < 5 ? (
              <Button variant="primary" disabled={currentStep === 1 ? !isStep1Valid : (currentStep === 2 ? !isStep2Valid : false)} onClick={() => setCurrentStep(prev => prev + 1)}>Next</Button>
            ) : (
              <Button variant="primary" onClick={() => onSubmit(formData)}>Submit</Button>
            )}
          </Stack>
        </Stack>
      </Card>
    </Container>
  );
}

import React, { useState, useMemo } from 'react';
import { Container, Stack, Box, Card, Text, Heading, Input, Divider, Button } from '@ggui-ai/design/primitives';

interface ElementData {
  atomicNumber?: number;
  symbol?: string;
  name?: string;
  atomicWeight?: number;
  category?: string;
  row?: number;
  col?: number;
}

interface Props {
  /** Full periodic table element data */
  elements: Array<{ atomicNumber?: number; symbol?: string; name?: string; atomicWeight?: number; category?: string; row?: number; col?: number }>;
}

const getCategoryColors = (category: string = '') => {
  const cat = category.toLowerCase();
  const theme = {
    alkali: { bg: 'var(--ggui-color-error-50)', border: 'var(--ggui-color-error-200)', text: 'var(--ggui-color-error-700)' },
    alkaline: { bg: 'var(--ggui-color-warning-50)', border: 'var(--ggui-color-warning-200)', text: 'var(--ggui-color-warning-700)' },
    transition: { bg: 'var(--ggui-color-neutral-100)', border: 'var(--ggui-color-neutral-300)', text: 'var(--ggui-color-neutral-700)' },
    postTransition: { bg: 'var(--ggui-color-success-50)', border: 'var(--ggui-color-success-200)', text: 'var(--ggui-color-success-700)' },
    metalloid: { bg: 'var(--ggui-color-info-50)', border: 'var(--ggui-color-info-200)', text: 'var(--ggui-color-info-700)' },
    nobleGas: { bg: 'var(--ggui-color-primary-50)', border: 'var(--ggui-color-primary-200)', text: 'var(--ggui-color-primary-700)' },
    lanthanide: { bg: 'var(--ggui-color-primary-100)', border: 'var(--ggui-color-primary-300)', text: 'var(--ggui-color-primary-800)' },
    actinide: { bg: 'var(--ggui-color-error-100)', border: 'var(--ggui-color-error-300)', text: 'var(--ggui-color-error-800)' },
    nonmetal: { bg: 'var(--ggui-color-info-100)', border: 'var(--ggui-color-info-300)', text: 'var(--ggui-color-info-800)' },
    default: { bg: 'var(--ggui-color-surfaceVariant)', border: 'var(--ggui-color-outline)', text: 'var(--ggui-color-onSurface)' }
  };
  if (cat.includes('alkali metal')) return theme.alkali;
  if (cat.includes('alkaline earth')) return theme.alkaline;
  if (cat.includes('transition metal')) return theme.transition;
  if (cat.includes('post-transition')) return theme.postTransition;
  if (cat.includes('metalloid')) return theme.metalloid;
  if (cat.includes('noble gas')) return theme.nobleGas;
  if (cat.includes('lanthanide')) return theme.lanthanide;
  if (cat.includes('actinide')) return theme.actinide;
  if (cat.includes('nonmetal') || cat.includes('halogen')) return theme.nonmetal;
  return theme.default;
};

export default function GeneratedComponent(props: Props) {
  const { elements = [] } = props;
  const [searchQuery, setSearchQuery] = useState('');
  const [selectedAtomicNumber, setSelectedAtomicNumber] = useState<number | null>(null);

  const filteredElements = useMemo(() => {
    const query = searchQuery.toLowerCase().trim();
    if (!query) return elements;
    return elements.filter(el => el.name?.toLowerCase().includes(query) || el.symbol?.toLowerCase().includes(query));
  }, [elements, searchQuery]);

  const selectedElement = useMemo(() => elements.find(el => el.atomicNumber === selectedAtomicNumber), [elements, selectedAtomicNumber]);

  const categories = useMemo(() => Array.from(new Set(elements.map(el => el.category).filter(Boolean))).sort(), [elements]);

  return (
    <Container maxWidth="xl" padding="var(--ggui-spacing-6, 24px)">
      <Stack gap="var(--ggui-spacing-8, 32px)">
        <Stack direction="horizontal" justify="between" align="center" wrap gap="var(--ggui-spacing-4, 16px)">
          <Heading level={1}>Periodic Table</Heading>
          <Box style={{ width: '100%', maxWidth: '320px' }}>
            <Input label="Search Elements" placeholder="Filter by name or symbol..." value={searchQuery} onChange={setSearchQuery} size="lg" />
          </Box>
        </Stack>

        <Stack direction="horizontal" gap="var(--ggui-spacing-2, 8px)" wrap>
          {categories.map(cat => {
            const colors = getCategoryColors(cat || '');
            return (
