import React, { useState, useEffect, useRef } from 'react';
import {
  Card,
  Stack,
  Text,
  Button,
  TextArea,
  Badge,
  Box,
  Divider,
} from '@ggui-ai/design/primitives';

interface Props {
  /** Chat window title */
  title: string;
  /** Current user name (for right-aligning own messages) */
  currentUser: string;
  /** Number of participants */
  participantCount?: number;
  /** Array of messages with sender name, text, and ISO timestamp */
  messages: Array<{ sender?: string; text?: string; timestamp?: string }>;
  /** Callback when sending a message */
  sendMessage: (payload: { text: string; timestamp: string }) => void;
}

export default function ChatInterface(props: Props) {
  const { title, currentUser, participantCount, messages, sendMessage } = props;
  const [inputValue, setInputValue] = useState('');
  const [localMessages, setLocalMessages] = useState(messages);
  const scrollRef = useRef<HTMLDivElement>(null);

  // Sync prop messages
  useEffect(() => {
    setLocalMessages(messages);
  }, [messages]);

  // Auto-scroll to bottom on message updates
  useEffect(() => {
    if (scrollRef.current) {
      scrollRef.current.scrollTop = scrollRef.current.scrollHeight;
    }
  }, [localMessages]);

  const handleSend = () => {
    if (!inputValue.trim()) return;
    const timestamp = new Date().toISOString();

    // Add locally for immediate feedback
    const newMessage = {
      sender: currentUser,
      text: inputValue,
      timestamp
    };

    setLocalMessages(prev => [...prev, newMessage]);

    // Action Contract implementation
    sendMessage({ text: inputValue, timestamp });
    setInputValue('');
  };

  const handleKeyDown = (e: React.KeyboardEvent) => {
    if (e.key === 'Enter' && !e.shiftKey) {
      e.preventDefault();
      handleSend();
    }
  };

  const formatTime = (isoString?: string) => {
    if (!isoString) return '';
    try {
      const date = new Date(isoString);
      return date.toLocaleTimeString([], { hour: '2-digit', minute: '2-digit' });
    } catch (e) {
      return '';
    }
  };

  return (
    <Card 
      padding={0} 
      shadow="md" 
      radius="lg" 
      border 
      style={{ 
        display: 'flex', 
        flexDirection: 'column', 
        height: '600px', 
        width: '100%', 
        maxWidth: '800px', 
        margin: '0 auto', 
        backgroundColor: 'var(--ggui-color-surface, #ffffff)', 
        overflow: 'hidden' 
      }}
    >
      {/* Header */}
      <Box padding="var(--ggui-spacing-4, 16px)">
        <Stack direction="horizontal" align="center" justify="between">
          <Stack direction="horizontal" gap="var(--ggui-spacing-2, 8px)" align="center">
            <Text variant="label" size="lg" weight="bold" color="var(--ggui-color-onSurface, #111827)">
              {title}
            </Text>
            {participantCount !== undefined && (
              <Badge variant="primary" size="sm">
                {participantCount} participants
              </Badge>
            )}
          </Stack>
        </Stack>
      </Box>
      <Divider margin={0} />

      {/* Scrollable Message List */}
      <div 
        ref={scrollRef} 
        style={{ 
          flex: 1, 
          overflowY: 'auto', 
          padding: 'var(--ggui-spacing-4, 16px)', 
          display: 'flex', 
          flexDirection: 'column', 
          gap: 'var(--ggui-spacing-3, 12px)', 
          background: 'var(--ggui-color-surface, #ffffff)' 
        }}
      >
        {localMessages.map((msg, index) => {
          const isOwn = msg.sender === currentUser;
          const isConsecutive = index > 0 && localMessages[index - 1].sender === msg.sender;
          return (
            <div key={`${msg.timestamp}-${index}`} style={{ display: 'flex', flexDirection: 'column', alignItems: isOwn ? 'flex-end' : 'flex-start' }}>
              <Stack align={isOwn ? 'end' : 'start'} gap="var(--ggui-spacing-1, 4px)" style={{ maxWidth: '85%' }}>
                {!isConsecutive && <Text variant="caption" color="var(--ggui-color-onSurfaceVariant, #6b7280)" weight="medium">{msg.sender}</Text>}
                <Box 
                  padding="var(--ggui-spacing-2, 8px) var(--ggui-spacing-4, 16px)" 
                  borderRadius="var(--ggui-shape-radius-lg, 12px)" 
                  background={isOwn ? 'var(--ggui-color-primary-600, #0284c7)' : 'var(--ggui-color-surfaceVariant, #f3f4f6)'} 
                  style={{ 
                    color: isOwn ? 'var(--ggui-color-surface, #ffffff)' : 'var(--ggui-color-onSurface, #111827)', 
                    borderBottomRightRadius: isOwn && !isConsecutive ? 'var(--ggui-shape-radius-sm, 4px)' : 'var(--ggui-shape-radius-lg, 12px)', 
                    borderBottomLeftRadius: !isOwn && !isConsecutive ? 'var(--ggui-shape-radius-sm, 4px)' : 'var(--ggui-shape-radius-lg, 12px)', 
                    boxShadow: 'var(--ggui-shape-shadow-sm, 0 1px 2px rgba(0,0,0,0.05))' 
                  }}
                >
                  <Text variant="body" color="inherit">{msg.text}</Text>
                </Box>
                <Text variant="caption" size="xs" color="var(--ggui-color-onSurfaceVariant, #6b7280)">
                  {formatTime(msg.timestamp)}
                </Text>
              </Stack>
            </div>
          );
        })}
      </div>
      <Divider margin={0} />

      {/* Input Area */}
      <Box padding="var(--ggui-spacing-4, 16px)" background="var(--ggui-color-surfaceVariant, #f9fafb)">
        <Stack gap="var(--ggui-spacing-2, 8px)">
          <Text as="label" variant="label" size="sm" color="var(--ggui-color-neutral-700, #374151)">
            Compose Message
          </Text>
          <Stack direction="horizontal" gap="var(--ggui-spacing-3, 12px)" align="end">
            <Box style={{ flex: 1 }}>
              <TextArea 
                label="Message" 
                placeholder="Type a message..." 
                value={inputValue} 
                onChange={(val: string) => setInputValue(val)} 
                onKeyDown={handleKeyDown}
                rows={1}
              />
            </Box>
            <Button 
              variant="primary" 
              onClick={handleSend} 
              disabled={!inputValue.trim()} 
              data-action-id="sendMessage"
            >
              Send Message
            </Button>
          </Stack>
        </Stack>
      </Box>
    </Card>
  );
}

import React, { useState, useEffect } from 'react';
import {
  Container,
  Card,
  Stack,
  Text,
  Heading,
  Box,
  Spinner,
  MotionKeyframes,
} from '@ggui-ai/design/primitives';
import { CardGrid } from '@ggui-ai/design/compositions';

interface Stock {
  symbol?: string;
  name?: string;
  price?: number;
  change?: number;
  changePercent?: number;
}

interface Props {
  /** Array of stocks with symbol, name, price, change, changePercent */
  stocks: Stock[];
  /** ISO timestamp of last price update */
  lastUpdated?: string;
}

/**
 * Stock Ticker Dashboard
 * Displays a live-updating grid of stock market data.
 */
export default function StockTickerDashboard({
  stocks: initialStocks = [],
  lastUpdated: initialLastUpdated,
}: Props) {
  const [stocks, setStocks] = useState<Stock[]>(initialStocks);
  const [lastUpdated, setLastUpdated] = useState<string | undefined>(initialLastUpdated);
  const [isConnecting, setIsConnecting] = useState(!initialStocks || initialStocks.length === 0);

  // Stream Contract: Listen for ggui:agent-data events for live updates
  // We use the global addEventListener to stay within security constraints
  useEffect(() => {
    const handleAgentData = (event: any) => {
      const data = event.detail;
      if (data) {
        if (data.stocks) setStocks(data.stocks);
        if (data.lastUpdated) setLastUpdated(data.lastUpdated);
        setIsConnecting(false);
      }
    };

    // Using global event listener as instructed by Stream Contract rules
    addEventListener('ggui:agent-data', handleAgentData as EventListener);

    // Fallback if data is already present in initial props
    if (initialStocks && initialStocks.length > 0) {
      setIsConnecting(false);
    }

    return () => {
      removeEventListener('ggui:agent-data', handleAgentData as EventListener);
    };
  }, [initialStocks]);

  // Utility to format currency with 2 decimal places
  const formatCurrency = (value: number) => {
    return new Intl.NumberFormat('en-US', {
      style: 'currency',
      currency: 'USD',
      minimumFractionDigits: 2,
    }).format(value);
  };

  // Utility to format timestamp
  const formatTime = (isoString?: string) => {
    if (!isoString) return '--:--:--';
    try {
      const date = new Date(isoString);
      return date.toLocaleTimeString([], {
        hour: '2-digit',
        minute: '2-digit',
        second: '2-digit',
      });
    } catch (e) {
      return '--:--:--';
    }
  };

  // Loading State - shown during initial connection
  if (isConnecting && (!stocks || stocks.length === 0)) {
    return (
      <Container maxWidth="xl" padding="var(--ggui-spacing-12, 48px)">
        <Stack align="center" justify="center" gap={24} style={{ minHeight: '320px' }}>
          <Spinner size={48} color="var(--ggui-color-primary-600)" />
          <Stack align="center" gap={4}>
            <Text variant="bodyLarge" weight="medium">Initialising Market Stream</Text>
            <Text variant="caption" color="var(--ggui-color-onSurfaceVariant)">
              Waiting for data from the trading agent...
            </Text>
          </Stack>
        </Stack>
      </Container>
    );
  }

  return (
    <Container maxWidth="xl" padding="var(--ggui-spacing-6, 24px)">
      <MotionKeyframes />
      <Stack gap={32} style={{ animation: 'ggui-fadeIn 500ms ease-out' }}>

        {/* Header Section with Live Status indicator */}
        <Stack direction="horizontal" justify="between" align="end" wrap gap={16}>
          <Stack gap={4}>
            <Heading level={1}>Market Watch</Heading>
            <Text variant="bodySmall" color="var(--ggui-color-onSurfaceVariant)">
              Real-time securities tracking and analysis
            </Text>
          </Stack>

          <Box 
            paddingX={12} 
            paddingY={6} 
            background="var(--ggui-color-surfaceVariant)" 
            borderRadius="var(--ggui-shape-radius-md)"
          >
            <Stack direction="horizontal" gap={8} align="center">
              <div style={{ 
                width: 8, 
                height: 8, 
                borderRadius: '50%', 
                backgroundColor: 'var(--ggui-color-success-500)',
                boxShadow: '0 0 8px var(--ggui-color-success-500)'
              }} />
              <Text variant="label" size="xs" color="var(--ggui-color-onSurfaceVariant)">
                LIVE UPDATE: {formatTime(lastUpdated)}
              </Text>
            </Stack>
          </Box>
        </Stack>

        {/* Stock Dashboard Grid - Responsive 3-col layout */}
        <CardGrid columns={{ sm: 1, md: 3, lg: 3 }} gap={20}>
          {stocks.map((stock, index) => {
            const isPositive = (stock.change ?? 0) >= 0;
            const colorToken = isPositive 
              ? 'var(--ggui-color-success-600, #16a34a)' 
              : 'var(--ggui-color-error-600, #dc2626)';
            const borderToken = isPositive
              ? 'var(--ggui-color-success-300, #86efac)'
              : 'var(--ggui-color-error-300, #fca5a5)';
            const bgToken = isPositive
              ? 'var(--ggui-color-success-50, #f0fdf4)'
              : 'var(--ggui-color-error-50, #fef2f2)';

            return (
              <Card 
                key={`${stock.symbol}-${index}`}
                padding={24} 
                shadow="sm"
                radius="xl"
                border={true}
                style={{ 
                  borderColor: borderToken,
                  backgroundColor: 'var(--ggui-color-surface)',
                  animation: `ggui-slideInUp 400ms ease-out ${index * 50}ms both`,
                  transition: 'transform 0.2s ease, border-color 0.3s ease',
                  cursor: 'default'
                }}
              >
                <Stack gap={16}>
                  {/* Top: Ticker & Name */}
                  <Stack direction="horizontal" justify="between" align="start">
                    <Stack gap={2}>
                      <Text size="2xl" weight="bold" color="var(--ggui-color-onSurface)">
                        {stock.symbol}
                      </Text>
                      <Text 
                        variant="caption" 
                        color="var(--ggui-color-onSurfaceVariant)" 
                        truncate 
                        style={{ maxWidth: '140px' }}
                      >
                        {stock.name}
                      </Text>
                    </Stack>
                    <Box 
                      paddingX={8} 
                      paddingY={4} 
                      borderRadius="var(--ggui-shape-radius-sm)" 
                      background={bgToken}
                    >
                      <Text weight="bold" size="xs" color={colorToken}>
                        {isPositive ? '▲' : '▼'} {Math.abs(stock.changePercent ?? 0).toFixed(2)}%
                      </Text>
                    </Box>
                  </Stack>

                  {/* Bottom: Price & Detail */}
                  <Stack direction="horizontal" justify="between" align="end">
                    <Text size="2xl" weight="semibold">
                      {formatCurrency(stock.price ?? 0)}
                    </Text>

                    <Stack align="end" gap={0}>
                      <Text 
                        size="sm" 
                        weight="medium"
                        color={colorToken}
                      >
                        {isPositive ? '+' : ''}{(stock.change ?? 0).toFixed(2)}
                      </Text>
                      <Text variant="caption" color="var(--ggui-color-onSurfaceVariant)">
                        Change
                      </Text>
                    </Stack>
                  </Stack>
                </Stack>
              </Card>
            );
          })}
        </CardGrid>

        {/* Empty State when no data is returned */}
        {(!stocks || stocks.length === 0) && !isConnecting && (
          <Card padding={48} shadow="none" border={true} radius="lg">
            <Stack align="center" gap={12}>
              <Text color="var(--ggui-color-onSurfaceVariant)" align="center">
                No active stocks found in your watch list.
              </Text>
            </Stack>
          </Card>
        )}
      </Stack>
    </Container>
  );
}

import React from 'react';
import { Card, Stack, Text, Heading, Divider, Box } from '@ggui-ai/design/primitives';

interface Props {
  /** City name */
  city: string;
  /** Current temperature */
  temperature: number;
  /** Weather condition (Sunny, Cloudy, Rainy, etc.) */
  condition: string;
  /** Humidity percentage */
  humidity: number;
  /** Wind speed */
  windSpeed: number;
  /** Temperature unit (C or F) */
  unit?: string;
  /** 5-day forecast array */
  forecast: Array<{
    day?: string;
    icon?: string;
    high?: number;
    low?: number;
  }>;
}

/**
 * Helper to determine emoji based on condition string.
 * This ensures we have a fallback if the prop doesn't provide an icon.
 */
const getWeatherEmoji = (cond: string = '') => {
  const lower = cond.toLowerCase();
  if (lower.includes('sun') || lower.includes('clear')) return '☀️';
  if (lower.includes('cloud')) return '☁️';
  if (lower.includes('rain') || lower.includes('drizzle')) return '🌧️';
  if (lower.includes('snow')) return '❄️';
  if (lower.includes('storm') || lower.includes('thunder')) return '⛈️';
  if (lower.includes('wind')) return '💨';
  return '🌤️';
};

/**
 * WeatherCard component - A clean, data-driven display of current and forecast weather.
 */
export default function WeatherCard({
  city = 'New York',
  temperature = 22,
  condition = 'Sunny',
  humidity = 45,
  windSpeed = 12,
  unit = 'C',
  forecast = [
    { day: 'Mon', high: 24, low: 18 },
    { day: 'Tue', high: 22, low: 16 },
    { day: 'Wed', high: 25, low: 19 },
    { day: 'Thu', high: 23, low: 17 },
    { day: 'Fri', high: 21, low: 15 },
