          </Heading>
          <Text variant="bodySmall" color="var(--ggui-color-onSurfaceVariant, #52525b)">
            Current Weather
          </Text>
        </Stack>

        {/* Hero Weather Stats */}
        <Stack direction="horizontal" align="center" justify="between">
          <Stack gap={0}>
            <Text size="4xl" weight="bold" color="var(--ggui-color-onSurface, #18181b)">
              {temperature}°{unit}
            </Text>
            <Text variant="bodyLarge" color="var(--ggui-color-onSurfaceVariant, #52525b)">
              {condition}
            </Text>
          </Stack>
          <Text size="4xl" as="span" aria-label={condition} style={{ cursor: 'default', userSelect: 'none' }}>
            {getWeatherEmoji(condition)}
          </Text>
        </Stack>

        {/* Auxiliary Stats (Humidity & Wind) */}
        <Stack direction="horizontal" gap={16}>
          <Box
            paddingX={16}
            paddingY={12}
            background="var(--ggui-color-surfaceVariant, #f4f4f5)"
            borderRadius={12}
            style={{ flex: 1, textAlign: 'center' }}
          >
            <Stack gap={4} align="center">
              <Text variant="caption" color="var(--ggui-color-onSurfaceVariant, #52525b)">
                Humidity
              </Text>
              <Text variant="label" color="var(--ggui-color-onSurface, #18181b)">
                {humidity}%
              </Text>
            </Stack>
          </Box>
          <Box
            paddingX={16}
            paddingY={12}
            background="var(--ggui-color-surfaceVariant, #f4f4f5)"
            borderRadius={12}
            style={{ flex: 1, textAlign: 'center' }}
          >
            <Stack gap={4} align="center">
              <Text variant="caption" color="var(--ggui-color-onSurfaceVariant, #52525b)">
                Wind Speed
              </Text>
              <Text variant="label" color="var(--ggui-color-onSurface, #18181b)">
