              <Text size="2xl" as="span" aria-label={item.day || 'forecast'}>
                {item.icon || getWeatherEmoji('default')}
              </Text>
              <Stack direction="horizontal" gap={4} justify="center">
                <Text variant="label" color="var(--ggui-color-onSurface, #18181b)">
                  {item.high ?? '--'}°
                </Text>
                <Text variant="caption" color="var(--ggui-color-onSurfaceVariant, #52525b)">
                  {item.low ?? '--'}°
                </Text>
              </Stack>
            </Stack>
          ))}
        </Stack>
      </Stack>
    </Card>
  );
