  satisfactionLabels = ['Very Unsatisfied', 'Unsatisfied', 'Neutral', 'Satisfied', 'Very Satisfied'],
  onSubmit
}: Props) {
  const [step, setStep] = useState(1);
  const [isSubmitting, setIsSubmitting] = useState(false);
  const [isSubmitted, setIsSubmitted] = useState(false);
  const [formData, setFormData] = useState({
    name: '',
    email: '',
    satisfaction: '',
    features: [] as string[],
    comments: ''
  });

  const isStepValid = useMemo(() => {
    if (step === 1) return formData.name.trim().length > 0 && formData.email.includes('@');
    if (step === 2) return formData.satisfaction !== '';
    return true;
  }, [step, formData]);

  const handleNext = () => setStep(s => s + 1);
  const handleBack = () => setStep(s => s - 1);

  const handleSubmit = async () => {
    if (!onSubmit) return;
    setIsSubmitting(true);
    try {
      await onSubmit(formData);
      setIsSubmitted(true);
    } catch (e) {
      console.error(e);
    } finally {
      setIsSubmitting(false);
    }
  };

  const update = (key: keyof typeof formData, value: any) => {
    setFormData(prev => ({ ...prev, [key]: value }));
  };

  if (isSubmitted) {
    return (
      <Container maxWidth="md" padding={24}>
        <Card shadow="lg" padding={48} radius="xl">
          <Stack align="center" gap={24}>
            <Box background="var(--ggui-color-success-50, #f0fdf4)" borderRadius="var(--ggui-shape-radius-full, 9999px)" padding={24}>
              <Text color="var(--ggui-color-success-600, #16a34a)" size="4xl" weight="bold">✓</Text>
            </Box>
            <Heading level={2}>Thank You</Heading>
            <Button variant="outline" onPress={() => { setStep(1); setIsSubmitted(false); setFormData({ name: '', email: '', satisfaction: '', features: [], comments: '' }); }}>Reset</Button>
          </Stack>
        </Card>
      </Container>
    );
  }

  const progress = (step / 4) * 100;

  return (
    <Container maxWidth="md" padding={24}>
      <Card shadow="md" padding={32} radius="lg">
        <Stack gap={24}>
          <Stack gap={12}>
            <Progress value={progress} variant="default" size="md" showLabel />
            <Heading level={2}>
              {step === 1 && 'Information'}
              {step === 2 && 'Satisfaction'}
              {step === 3 && 'Interests'}
              {step === 4 && 'Feedback'}
              {step === 5 && 'Summary'}
            </Heading>
          </Stack>

          <Divider color="var(--ggui-color-outlineVariant, #e4e4e7)" />

          <Box paddingY={16}>
            {step === 1 && (
              <Stack gap={16}>
                <Stack gap={4}>
                  <Text as="label" variant="label">Name</Text>
                  <Input label="Name" value={formData.name} onChange={(v: string) => update('name', v)} />
                </Stack>
                <Stack gap={4}>
                  <Text as="label" variant="label">Email</Text>
                  <Input label="Email" type="email" value={formData.email} onChange={(v: string) => update('email', v)} />
                </Stack>
              </Stack>
            )}

            {step === 2 && (
              <RadioGroup
                label="Satisfaction"
                value={formData.satisfaction}
                onChange={(v) => update('satisfaction', v)}
                options={satisfactionLabels.map(l => ({ value: l, label: l }))}
              />
            )}

            {step === 3 && (
              <Stack gap={12}>
                <Text variant="body">Choose Features:</Text>
                {featureOptions.map(f => (
                  <Checkbox 
                    key={f}
                    label={f}
                    checked={formData.features.includes(f)}
                    onChange={(c) => {
                      const features = c ? [...formData.features, f] : formData.features.filter(x => x !== f);
                      update('features', features);
                    }}
                  />
                ))}
              </Stack>
            )}

            {step === 4 && (
              <TextArea 
                label="Comments"
                maxLength={500}
                showCount
                value={formData.comments}
                onChange={(v) => update('comments', v)}
              />
            )}

            {step === 5 && (
              <Stack gap={12}>
                <Text weight="bold">Summary:</Text>
                <Box padding={12} background="var(--ggui-color-surfaceVariant)" borderRadius="var(--ggui-shape-radius-md)">
                  <Stack gap={4}>
                    <Text variant="label">Name: {formData.name}</Text>
                    <Text variant="label">Email: {formData.email}</Text>
                    <Text variant="label">Satisfaction: {formData.satisfaction}</Text>
                    <Text variant="label">Features: {formData.features.join(', ') || 'None'}</Text>
                  </Stack>
                </Box>
              </Stack>
            )}
          </Box>

          <Divider color="var(--ggui-color-outlineVariant, #e4e4e7)" />

          <Stack direction="horizontal" justify="between">
            {step > 1 ? <Button variant="outline" onPress={handleBack}>Back</Button> : <Box />}
            {step < 5 ? (
              <Button variant="primary" onPress={handleNext} disabled={!isStepValid}>{step === 4 ? 'Review' : 'Next'}</Button>
            ) : (
              <Button variant="primary" onPress={handleSubmit} loading={isSubmitting}>Submit</Button>
            )}
          </Stack>
        </Stack>
      </Card>
    </Container>
  );
}

import React, { useState, useMemo } from 'react';
import {
  Container,
  Stack,
  Box,
  Card,
  Input,
  Text,
  Heading,
  Badge,
} from '@ggui-ai/design/primitives';

interface Props {
  /** Full periodic table element data */
  elements: Array<{
    atomicNumber?: number;
    symbol?: string;
    name?: string;
    atomicWeight?: number;
    category?: string;
    row?: number;
    col?: number;
  }>;
}

const CATEGORY_PALETTE = [
  { bg: 'var(--ggui-color-info-100, #e0f2fe)', text: 'var(--ggui-color-info-900, #0c4a6e)' },
  { bg: 'var(--ggui-color-success-100, #dcfce7)', text: 'var(--ggui-color-success-900, #14532d)' },
  { bg: 'var(--ggui-color-warning-100, #fef3c7)', text: 'var(--ggui-color-warning-900, #78350f)' },
  { bg: 'var(--ggui-color-error-100, #fee2e2)', text: 'var(--ggui-color-error-900, #7f1d1d)' },
  { bg: 'var(--ggui-color-primary-100, #e0f2fe)', text: 'var(--ggui-color-primary-900, #0c4a6e)' },
  { bg: 'var(--ggui-color-neutral-200, #e5e7eb)', text: 'var(--ggui-color-onSurface, #18181b)' },
  { bg: 'var(--ggui-color-primary-50, #f0f9ff)', text: 'var(--ggui-color-primary-700, #0369a1)' },
  { bg: 'var(--ggui-color-success-50, #f0fdf4)', text: 'var(--ggui-color-success-800, #166534)' },
  { bg: 'var(--ggui-color-warning-50, #fffbeb)', text: 'var(--ggui-color-warning-800, #92400e)' },
  { bg: 'var(--ggui-color-error-50, #fef2f2)', text: 'var(--ggui-color-error-800, #991b1b)' },
];

const DEFAULT_COLOR = {
  bg: 'var(--ggui-color-surfaceVariant, #f4f4f5)',
  text: 'var(--ggui-color-onSurfaceVariant, #52525b)',
};

export default function PeriodicTable({ elements = [] }: Props) {
  const [searchQuery, setSearchQuery] = useState('');
  const [selectedElement, setSelectedElement] = useState<Props['elements'][0] | null>(null);

  const categoryColors = useMemo(() => {
    const map = new Map<string, { bg: string; text: string }>();
    let colorIndex = 0;
    elements.forEach((el) => {
      if (el.category && !map.has(el.category)) {
        map.set(el.category, CATEGORY_PALETTE[colorIndex % CATEGORY_PALETTE.length]);
        colorIndex++;
      }
    });
    return map;
  }, [elements]);

  const handleSearch = (val: string) => {
    setSearchQuery(val);
    if (selectedElement) setSelectedElement(null);
  };

  const isMatch = (el: Props['elements'][0]) => {
    if (!searchQuery) return true;
    const q = searchQuery.toLowerCase();
    return (
      (el.name?.toLowerCase().includes(q) || false) ||
      (el.symbol?.toLowerCase().includes(q) || false)
    );
  };

  return (
    <Container maxWidth="full" padding={24}>
      <Stack gap={24}>
        <Stack direction="horizontal" justify="between" align="end" wrap gap={24}>
          <Box>
            <Heading level={2}>Periodic Table</Heading>
            <Text variant="bodySmall" color="var(--ggui-color-onSurfaceVariant)">
              Element exploration and analysis
            </Text>
          </Box>
          <Box style={{ minWidth: '320px' }}>
            <Input label="Search elements" type="search" placeholder="Enter name or symbol" value={searchQuery} onChange={handleSearch} id="periodic-table-search" />
          </Box>
        </Stack>

        <Box padding={24} background="var(--ggui-color-surface)" borderRadius="var(--ggui-shape-radius-lg)" style={{ border: '1px solid var(--ggui-color-outlineVariant)', overflowX: 'auto' }}>
          <div style={{ display: 'grid', gridTemplateColumns: 'repeat(18, minmax(64px, 1fr))', gap: 'var(--ggui-spacing-1)', minWidth: '1152px' }} role="grid">
            {elements.map((el, i) => {
              const matches = isMatch(el);
              const color = el.category ? categoryColors.get(el.category) || DEFAULT_COLOR : DEFAULT_COLOR;
              const isSelected = selectedElement?.atomicNumber === el.atomicNumber;
              return (
                <button
                  key={el.atomicNumber || i}
                  onClick={() => matches && setSelectedElement(el)}
                  disabled={!matches}
                  style={{
                    gridRow: el.row || 'auto', gridColumn: el.col || 'auto', aspectRatio: '1', display: 'flex', flexDirection: 'column', alignItems: 'center', justifyContent: 'center', position: 'relative', background: color.bg, color: color.text, borderRadius: '4px', padding: '4px', cursor: matches ? 'pointer' : 'default', opacity: matches ? 1 : 0.1, transition: 'all 200ms', outline: 'none', border: isSelected ? '2px solid var(--ggui-color-primary-600)' : '1px solid transparent', boxShadow: isSelected ? 'var(--ggui-shape-shadow-md)' : 'none'
                  }}
                  aria-label={`${el.name || 'Element'}, ${el.atomicNumber}`}
                  aria-pressed={isSelected}
                >
                  <span style={{ position: 'absolute', top: '4px', left: '6px', fontSize: '10px', fontWeight: 600, opacity: 0.7 }}>{el.atomicNumber}</span>
                  <span style={{ fontSize: '20px', fontWeight: 700 }}>{el.symbol}</span>
                </button>
              );
            })}
          </div>
        </Box>

        {selectedElement && (
          <Card padding={24} shadow="md" border radius="lg">
            <Stack direction="horizontal" gap={32} align="center" wrap>
              <Box padding={24} borderRadius="var(--ggui-shape-radius-md)" background={selectedElement.category ? categoryColors.get(selectedElement.category)?.bg : DEFAULT_COLOR.bg} style={{ color: selectedElement.category ? categoryColors.get(selectedElement.category)?.text : DEFAULT_COLOR.text, minWidth: '120px', textAlign: 'center', border: '1px solid var(--ggui-color-outlineVariant)' }}>
                <Heading level={1}>{selectedElement.symbol}</Heading>
              </Box>
              <Stack gap={16} style={{ flex: 1 }}>
                <Stack direction="horizontal" align="center" gap={12} wrap>
                  <Heading level={2}>{selectedElement.name}</Heading>
                  {selectedElement.category && <Badge variant="primary">{selectedElement.category}</Badge>}
                </Stack>
                <Stack direction="horizontal" gap={48} wrap>
                  <Box>
                    <Text variant="label" color="var(--ggui-color-onSurfaceVariant)">Atomic Number</Text>
                    <Text variant="bodyLarge" weight="bold">{selectedElement.atomicNumber}</Text>
                  </Box>
                  <Box>
                    <Text variant="label" color="var(--ggui-color-onSurfaceVariant)">Atomic Weight</Text>
                    <Text variant="bodyLarge" weight="bold">{selectedElement.atomicWeight}</Text>
                  </Box>
                  <Box>
                    <Text variant="label" color="var(--ggui-color-onSurfaceVariant)">Group / Row</Text>
                    <Text variant="bodyLarge" weight="bold">{selectedElement.col} / {selectedElement.row}</Text>
                  </Box>
                </Stack>
              </Stack>
            </Stack>
          </Card>
        )}

        <Box padding={16} background="var(--ggui-color-surfaceVariant)" borderRadius="var(--ggui-shape-radius-md)">
          <Text variant="label" color="var(--ggui-color-onSurface)" style={{ marginBottom: '12px', display: 'block' }}>Categories</Text>
          <Stack direction="horizontal" wrap gap={16}>
            {Array.from(categoryColors.entries()).map(([category, colors]) => (
              <Stack key={category} direction="horizontal" align="center" gap={8}>
                <div style={{ width: '16px', height: '16px', backgroundColor: colors.bg, borderRadius: '4px', border: `1px solid var(--ggui-color-outline)` }} aria-hidden="true" />
                <Text variant="caption" weight="medium">{category}</Text>
              </Stack>
            ))}
          </Stack>
        </Box>
      </Stack>
    </Container>
  );
}

import React, { useState, useRef, useEffect } from 'react';
import {
  Card,
  Stack,
  Text,
  Heading,
  Badge,
  Box,
  Input,
  Button,
  Divider
} from '@ggui-ai/design/primitives';

interface Message {
  sender?: string;
  text?: string;
  timestamp?: string;
}

interface Props {
  /** Chat window title */
  title: string;
  /** Current user name (for right-aligning own messages) */
  currentUser: string;
  /** Number of participants */
  participantCount?: number;
  /** Array of messages with sender name, text, and ISO timestamp */
  messages: Array<Message>;
  /** Called when user sends a message. */
  onSend: (payload: { text: string; timestamp: string }) => void;
  /** Action Contract: Send Message */
  onSendMessage?: (payload: { text: string; timestamp: string }) => void;
}

export default function ChatInterface(props: Props) {
  const { title, currentUser, messages = [], participantCount, onSend, onSendMessage } = props;
  const [inputText, setInputText] = useState('');
  const scrollRef = useRef<HTMLDivElement>(null);

  // Auto-scroll to bottom
  useEffect(() => {
    if (scrollRef.current) {
      scrollRef.current.scrollTop = scrollRef.current.scrollHeight;
    }
  }, [messages]);

  const handleSubmit = () => {
    const text = inputText.trim();
    if (!text) return;
    const p = { text, timestamp: new Date().toISOString() };
    if (onSend) onSend(p);
    if (onSendMessage) onSendMessage(p);
    setInputText('');
  };

  const onKeyPress = (e: React.KeyboardEvent) => {
    if (e.key === 'Enter' && !e.shiftKey) {
      e.preventDefault();
      handleSubmit();
    }
  };

  return (
    <Card padding={0} border={true} radius="lg" shadow="md" style={{ display: 'flex', flexDirection: 'column', height: '600px', backgroundColor: 'var(--ggui-color-surface, #ffffff)' }}>
      <Box padding="16px" style={{ borderBottom: '1px solid var(--ggui-color-outline, #d1d5db)' }}>
        <Stack direction="horizontal" align="center" justify="between">
          <Stack direction="horizontal" gap={8} align="center">
            <Heading level={3}>{title}</Heading>
            {participantCount !== undefined && <Badge variant="primary" size="sm">{participantCount}</Badge>}
          </Stack>
        </Stack>
      </Box>

      <div ref={scrollRef} style={{ flex: 1, overflowY: 'auto', padding: '16px', backgroundColor: 'var(--ggui-color-surface, #ffffff)', scrollBehavior: 'smooth' }}>
        <Stack gap={12}>
          {messages.map((m, i) => {
            const isMe = m.sender === currentUser;
            const sameAsPrev = i > 0 && messages[i - 1].sender === m.sender;
            return (
              <Box key={`m-${i}`} style={{ display: 'flex', flexDirection: 'column', alignItems: isMe ? 'flex-end' : 'flex-start', marginTop: sameAsPrev ? '-8px' : '0' }}>
                {!isMe && !sameAsPrev && <Text variant="label" style={{ marginBottom: '4px', color: 'var(--ggui-color-onSurfaceVariant, #52525b)' }}>{m.sender}</Text>}
                <Box paddingX={12} paddingY={8} style={{ maxWidth: '80%', borderRadius: '12px', backgroundColor: isMe ? 'var(--ggui-color-primary-600, #0284c7)' : 'var(--ggui-color-surfaceVariant, #f4f4f5)', color: isMe ? '#ffffff' : 'var(--ggui-color-onSurface, #18181b)', borderBottomRightRadius: isMe ? 2 : 12, borderBottomLeftRadius: !isMe ? 2 : 12 }}>
                  <Text variant="bodySmall">{m.text}</Text>
                </Box>
              </Box>
            );
          })}
        </Stack>
      </div>

      <Divider margin={0} />

      <Box padding="16px">
        <Stack direction="horizontal" gap={12} align="end">
          <Input label="Message" value={inputText} onChange={setInputText} onKeyDown={onKeyPress} />
          <Button variant="primary" onClick={handleSubmit} disabled={!inputText.trim()}>Send</Button>
        </Stack>
      </Box>
    </Card>
  );
}

import React, { useState, useEffect } from 'react';
import {
  Container,
  Stack,
  Box,
  Text,
  Heading,
  Icon,
  Spinner,
} from '@ggui-ai/design/primitives';
import { CardGrid } from '@ggui-ai/design/compositions';

interface Stock {
  symbol?: string;
  name?: string;
  price?: number;
  change?: number;
  changePercent?: number;
}

interface Props {
  /** Array of stocks with symbol, name, price, change, changePercent */
  stocks: Array<Stock>;
  /** ISO timestamp of last price update */
  lastUpdated?: string;
}

/**
 * StockTickerDashboard
 * A real-time monitoring dashboard for stock performance.
 * Reactive to props updates from the agent stream.
 */
export default function StockTickerDashboard({ 
  stocks = [], 
  lastUpdated = '' 
}: Props) {
  // We use local state to handle the 'connecting' logic more effectively 
  // until initial data arrives via props.
  const [hasReceivedData, setHasReceivedData] = useState(stocks.length > 0);

  useEffect(() => {
    if (stocks.length > 0) {
      setHasReceivedData(true);
    }
  }, [stocks]);

  const formatPrice = (val: number) => val.toFixed(2);
  const formatTime = (iso: string) => {
    if (!iso) return 'Waiting for update...';
    try {
      const d = new Date(iso);
      return d.toLocaleTimeString([], { hour: '2-digit', minute: '2-digit', second: '2-digit' });
    } catch {
      return iso;
    }
  };

  const isLoading = !hasReceivedData && stocks.length === 0;

  return (
    <Container maxWidth="xl" padding="var(--ggui-spacing-6, 24px)">
      <Stack gap="var(--ggui-spacing-8, 32px)">
        {/* Dashboard Header Slot */}
        <Stack direction="horizontal" justify="between" align="center" wrap>
          <Stack gap={4}>
            <Heading level={1}>Market Watch</Heading>
            <Text color="var(--ggui-color-onSurfaceVariant, #52525b)" variant="bodySmall">
              Real-time ticker stream and performance metrics
            </Text>
          </Stack>

          <Stack direction="horizontal" align="center" gap={12}>
            {!hasReceivedData ? (
              <Stack direction="horizontal" align="center" gap={8}>
                <Spinner size={16} />
                <Text variant="caption" color="var(--ggui-color-onSurfaceVariant)">
                  Establishing connection...
                </Text>
              </Stack>
            ) : (
              <Box 
                paddingX={12} 
                paddingY={6} 
                borderRadius="var(--ggui-shape-radius-full, 9999px)"
                background="var(--ggui-color-surfaceVariant, #f4f4f5)"
                style={{ border: '1px solid var(--ggui-color-outlineVariant, #e4e4e7)' }}
              >
                <Stack direction="horizontal" align="center" gap={8}>
                  <Box 
                    borderRadius="50%" 
                    background="var(--ggui-color-success-500, #22c55e)" 
                    style={{ width: 8, height: 8, boxShadow: '0 0 4px var(--ggui-color-success-500)' }} 
                  />
                  <Text variant="label" size="xs">
                    Live: {formatTime(lastUpdated)}
                  </Text>
                </Stack>
              </Box>
            )}
          </Stack>
        </Stack>

        {/* Dashboard Content */}
        {isLoading ? (
          <Box padding={64} borderRadius={16} style={{ border: '2px dashed var(--ggui-color-outline, #d4d4d8)' }}>
            <Stack align="center" gap={16}>
              <Spinner size={32} />
              <Text weight="medium">Synchronizing with market data streams...</Text>
            </Stack>
          </Box>
        ) : (
          <CardGrid columns={{ sm: 1, md: 2, lg: 3 }} gap={16}>
            {stocks.map((stock, i) => {
              const isPos = (stock.change || 0) >= 0;
              const statusColor = isPos 
                ? 'var(--ggui-color-success-600, #16a34a)' 
                : 'var(--ggui-color-error-600, #dc2626)';
              const statusBg = isPos
                ? 'var(--ggui-color-success-50, #f0fdf4)'
                : 'var(--ggui-color-error-50, #fef2f2)';

              return (
                <Box
                  key={`${stock.symbol}-${i}`}
                  padding={20}
                  borderRadius="var(--ggui-shape-radius-lg, 12px)"
                  background="var(--ggui-color-surface, #ffffff)"
                  style={{
                    border: `1px solid var(--ggui-color-outlineVariant, #e4e4e7)`,
                    boxShadow: 'var(--ggui-shape-shadow-sm, 0 1px 2px rgba(0,0,0,0.05))',
                    transition: 'all 0.2s ease-in-out',
                  }}
                >
                  <Stack gap={16}>
                    {/* Symbol and Pricing Row */}
                    <Stack direction="horizontal" justify="between" align="start">
                      <Stack gap={0}>
                        <Text weight="bold" size="2xl" color="var(--ggui-color-onSurface, #18181b)">
                          {stock.symbol || '---'}
                        </Text>
                        <Text 
                          variant="caption" 
                          color="var(--ggui-color-onSurfaceVariant, #52525b)" 
                          truncate
                          style={{ maxWidth: '140px' }}
                        >
                          {stock.name || 'Unknown Company'}
                        </Text>
                      </Stack>
                      <Text weight="bold" size="xl">
                        ${formatPrice(stock.price || 0)}
                      </Text>
                    </Stack>

                    {/* Change Stats Footer */}
                    <Box 
                      padding={12} 
                      borderRadius="var(--ggui-shape-radius-md, 8px)" 
                      background={statusBg}
                    >
                      <Stack direction="horizontal" justify="between" align="center">
                        <Text size="sm" weight="semibold" color={statusColor}>
                          {isPos ? '+' : ''}{formatPrice(stock.change || 0)}
                        </Text>

                        <Stack direction="horizontal" align="center" gap={4}>
                          <Icon 
                            name={isPos ? 'chevron-up' : 'chevron-down'} 
                            size={20} 
                            color={statusColor} 
                          />
                          <Text size="lg" weight="bold" color={statusColor}>
                            {Math.abs(stock.changePercent || 0).toFixed(2)}%
                          </Text>
                        </Stack>
                      </Stack>
                    </Box>
                  </Stack>
                </Box>
              );
            })}
          </CardGrid>
        )}

        {/* Fallback for empty stream results */}
        {!isLoading && stocks.length === 0 && (
          <Box padding={48} borderRadius={16} background="var(--ggui-color-surfaceVariant)">
            <Stack align="center" gap={8}>
              <Text weight="medium">No stocks in current watchlist</Text>
              <Text variant="bodySmall" color="var(--ggui-color-onSurfaceVariant)">
                The connection is active but no ticker data was provided.
              </Text>
            </Stack>
          </Box>
        )}
      </Stack>
    </Container>
  );
}

import React, { useState } from 'react';
import {
  Container,
  Card,
  Stack,
  Heading,
  Text,
  Progress,
  Input,
  Select,
  Toggle,
  RadioGroup,
  Button,
  Box,
  Divider,
  MotionKeyframes
} from '@ggui-ai/design/primitives';

interface Props {
  avatarOptions: string[];
  roleOptions: string[];
  initialProfile?: {
    name?: string;
    email?: string;
    avatar?: string;
    role?: string;
    emailNotifications?: boolean;
    theme?: string;
  };
  onComplete?: (data: {
    name: string;
    email: string;
    avatar: string;
    role: string;
    emailNotifications: boolean;
    theme: string;
  }) => void;
}

export default function OnboardingWizard({
  avatarOptions,
  roleOptions,
  initialProfile,
  onComplete
}: Props) {
  const [step, setStep] = useState(1);
  const [formData, setFormData] = useState({
    name: initialProfile?.name || '',
    email: initialProfile?.email || '',
    avatar: initialProfile?.avatar || '',
    role: initialProfile?.role || '',
    emailNotifications: initialProfile?.emailNotifications ?? true,
    theme: initialProfile?.theme || 'light'
  });

  const [touched, setTouched] = useState({ name: false, email: false });

  const isValidEmail = (email: string) => /^[^\s@]+@[^\s@]+\.[^\s@]+$/.test(email);

  const isStep1Valid = formData.name.trim().length > 0 && isValidEmail(formData.email) && formData.avatar.length > 0;
  const isStep2Valid = formData.role.length > 0;

  const handleNext = () => setStep((s) => Math.min(s + 1, 3));
  const handleBack = () => setStep((s) => Math.max(s - 1, 1));
  const handleSubmit = () => onComplete?.(formData);

  const updateField = (field: string, value: any) => {
    setFormData((prev) => ({ ...prev, [field]: value }));
  };

  const renderStep1 = () => (
    <div style={{ animation: 'ggui-fadeIn 300ms ease-out' }}>
      <Stack gap={24}>
        <Input label="Full Name" required placeholder="Jane Doe" value={formData.name} onChange={(v) => { updateField('name', v); setTouched(p => ({ ...p, name: true })); }} error={touched.name && !formData.name.trim() ? 'Name is required' : undefined} />
        <Input label="Email Address" required type="email" placeholder="jane@example.com" value={formData.email} onChange={(v) => { updateField('email', v); setTouched(p => ({ ...p, email: true })); }} error={touched.email && !isValidEmail(formData.email) ? 'Valid email is required' : undefined} />
        <Stack gap={12}>
          <Text variant="label">Choose Avatar <span style={{ color: 'var(--ggui-color-error-500, #ef4444)' }}>*</span></Text>
          <Stack direction="horizontal" gap={12} wrap>
            {avatarOptions.map((emoji) => (
              <button
                key={emoji}
                type="button"
                onClick={() => updateField('avatar', emoji)}
                style={{
                  width: '64px', height: '64px', fontSize: '32px', display: 'flex', alignItems: 'center', justifyContent: 'center', cursor: 'pointer',
                  backgroundColor: formData.avatar === emoji ? 'var(--ggui-color-primary-50, #f0f9ff)' : 'var(--ggui-color-surface, #ffffff)',
                  border: formData.avatar === emoji ? '2px solid var(--ggui-color-primary-600, #0284c7)' : '1px solid var(--ggui-color-outline, #d4d4d8)',
                  borderRadius: 'var(--ggui-shape-radius-md, 8px)', transition: 'all 200ms ease-in-out', outline: 'none',
                  boxShadow: formData.avatar === emoji ? '0 0 0 2px var(--ggui-color-primary-100, #e0f2fe)' : 'none'
                }}
                aria-label={`Select avatar ${emoji}`}
                aria-pressed={formData.avatar === emoji}
              >
                {emoji}
              </button>
            ))}
          </Stack>
        </Stack>
      </Stack>
    </div>
  );

  const renderStep2 = () => (
    <div style={{ animation: 'ggui-fadeIn 300ms ease-out' }}>
      <Stack gap={32}>
        <Select label="Primary Role" placeholder="Select a role..." value={formData.role} onChange={(v) => updateField('role', v)} options={roleOptions.map((r) => ({ label: r, value: r }))} required />
        <Box padding={16} background="var(--ggui-color-surfaceVariant, #f4f4f5)" borderRadius="var(--ggui-shape-radius-md, 8px)">
          <Toggle label="Enable Email Notifications" checked={formData.emailNotifications} onChange={(v) => updateField('emailNotifications', v)} />
        </Box>
        <RadioGroup label="Theme Preference" value={formData.theme} onChange={(v) => updateField('theme', v)} options={[{ value: 'light', label: 'Light Mode', description: 'Clean and bright' }, { value: 'dark', label: 'Dark Mode', description: 'Easy on the eyes' }]} />
      </Stack>
    </div>
  );

  const renderStep3 = () => (
    <div style={{ animation: 'ggui-fadeIn 300ms ease-out' }}>
      <Stack gap={24}>
        <Text variant="body">Please review your selections before completing setup.</Text>
        <Card shadow="none" border padding={24} radius="md">
          <Stack gap={16}>
            <Stack direction="horizontal" justify="between" align="center">
              <Text variant="label" color="var(--ggui-color-onSurfaceVariant, #52525b)">Avatar</Text>
              <Text variant="bodyLarge">{formData.avatar}</Text>
            </Stack>
            <Divider margin={0} />
            <Stack direction="horizontal" justify="between" align="center">
              <Text variant="label" color="var(--ggui-color-onSurfaceVariant, #52525b)">Name</Text>
              <Text variant="body">{formData.name}</Text>
            </Stack>
            <Divider margin={0} />
            <Stack direction="horizontal" justify="between" align="center">
              <Text variant="label" color="var(--ggui-color-onSurfaceVariant, #52525b)">Email</Text>
              <Text variant="body">{formData.email}</Text>
            </Stack>
            <Divider margin={0} />
            <Stack direction="horizontal" justify="between" align="center">
              <Text variant="label" color="var(--ggui-color-onSurfaceVariant, #52525b)">Role</Text>
              <Text variant="body">{formData.role}</Text>
            </Stack>
            <Divider margin={0} />
            <Stack direction="horizontal" justify="between" align="center">
              <Text variant="label" color="var(--ggui-color-onSurfaceVariant, #52525b)">Notifications</Text>
              <Text variant="body">{formData.emailNotifications ? 'Enabled' : 'Disabled'}</Text>
            </Stack>
            <Divider margin={0} />
            <Stack direction="horizontal" justify="between" align="center">
              <Text variant="label" color="var(--ggui-color-onSurfaceVariant, #52525b)">Theme</Text>
              <Text variant="body" style={{ textTransform: 'capitalize' }}>{formData.theme}</Text>
            </Stack>
          </Stack>
        </Card>
      </Stack>
    </div>
  );

  return (
    <Container maxWidth="md" padding={24}>
      <MotionKeyframes />
      <Card shadow="lg" padding={32} radius="lg">
        <Stack gap={32}>
          <Stack gap={16}>
            <Stack direction="horizontal" justify="between" align="center">
              <Heading level={3}>{step === 1 ? 'Profile Setup' : step === 2 ? 'Preferences' : 'Review & Confirm'}</Heading>
              <Text variant="bodySmall" color="var(--ggui-color-onSurfaceVariant, #52525b)">Step {step} of 3</Text>
            </Stack>
            <Progress value={(step / 3) * 100} variant="default" size="sm" />
          </Stack>
          <Divider margin={0} />
          <Box paddingY={16}>
            {step === 1 && renderStep1()}
            {step === 2 && renderStep2()}
            {step === 3 && renderStep3()}
          </Box>
          <Divider margin={0} />
          <Stack direction="horizontal" justify="between" align="center">
            {step > 1 ? <Button variant="ghost" onClick={handleBack}>Go Back</Button> : <div style={{ width: 1 }} />}
            <Button variant="primary" onClick={step < 3 ? handleNext : handleSubmit} disabled={step === 1 ? !isStep1Valid : step === 2 ? !isStep2Valid : false}>
              {step < 3 ? 'Next Step' : 'Complete Setup'}
            </Button>
          </Stack>
        </Stack>
      </Card>
    </Container>
  );
}

import React from 'react';
import {
  Card,
  Stack,
  Text,
  Heading,
  Divider,
  Box,
} from '@ggui-ai/design/primitives';

/**
 * Props Contract (MUST use these exact prop names and types)
 */
interface Props {
  /** City name */
  city: string;
  /** Current temperature */
  temperature: number;
  /** Weather condition (Sunny, Cloudy, Rainy, etc.) */
  condition: string;
  /** Humidity percentage */
  humidity: number;
  /** Wind speed */
  windSpeed: number;
  /** Temperature unit (C or F) */
  unit?: string;
  /** 5-day forecast array */
  forecast: Array<{ day?: string; icon?: string; high?: number; low?: number }>;
}

/**
 * Helper to map text conditions to emojis when an explicit icon isn't provided
 */
const getWeatherEmoji = (condition: string): string => {
  const lowerCondition = condition.toLowerCase();
  if (lowerCondition.includes('sun') || lowerCondition.includes('clear')) return '☀️';
  if (lowerCondition.includes('cloud')) return '☁️';
  if (lowerCondition.includes('rain')) return '🌧️';
  if (lowerCondition.includes('storm') || lowerCondition.includes('thunder')) return '⛈️';
  if (lowerCondition.includes('snow')) return '❄️';
  if (lowerCondition.includes('wind')) return '💨';
  if (lowerCondition.includes('fog')) return '🌫️';
  return '⛅'; // default
};

/**
 * WeatherCard component displays current weather information and a 5-day forecast.
 */
export default function WeatherCard({
  city = 'London',
  temperature = 12,
  condition = 'Cloudy',
  humidity = 82,
  windSpeed = 14,
  unit = 'C',
  forecast = [
    { day: 'Mon', icon: '☁️', high: 14, low: 8 },
    { day: 'Tue', icon: '🌧️', high: 11, low: 7 },
    { day: 'Wed', icon: '⛅', high: 13, low: 6 },
    { day: 'Thu', icon: '☀️', high: 16, low: 9 },
    { day: 'Fri', icon: '☀️', high: 18, low: 10 },
  ],
}: Props) {
  return (
    <Card shadow="md" padding={24} radius="lg">
      <Stack gap={24}>
        {/* Header: City and Condition Text */}
        <Stack gap={4}>
          <Heading level={2} color="var(--ggui-color-onSurface, #18181b)">
            {city}
          </Heading>
          <Text variant="body" color="var(--ggui-color-onSurfaceVariant, #52525b)">
            {condition}
          </Text>
        </Stack>

        {/* Main Temperature and Icon Display */}
        <Stack direction="horizontal" justify="between" align="center">
          <Stack direction="horizontal" gap={4} align="start">
            <Text 
              size="4xl" 
              weight="bold" 
              color="var(--ggui-color-onSurface, #18181b)"
            >
              {temperature}
            </Text>
            <Box paddingY={8}>
              <Text size="xl" weight="medium" color="var(--ggui-color-onSurfaceVariant, #52525b)">
                °{unit}
              </Text>
            </Box>
          </Stack>
          <Text 
            size="4xl" 
            align="center" 
          >
            {getWeatherEmoji(condition)}
          </Text>
        </Stack>

        {/* Secondary Stats: Humidity & Wind */}
        <Stack direction="horizontal" gap={16}>
          <Box
            background="var(--ggui-color-surfaceVariant, #f4f4f5)"
            padding={16}
            borderRadius="var(--ggui-shape-radius-md, 8px)"
            style={{ flex: 1 }}
          >
            <Stack gap={4} align="center">
              <Text variant="caption" color="var(--ggui-color-onSurfaceVariant, #52525b)">
                Humidity
              </Text>
              <Text 
                variant="label" 
                color="var(--ggui-color-onSurface, #18181b)"
              >
                {humidity}%
              </Text>
            </Stack>
          </Box>
          <Box
            background="var(--ggui-color-surfaceVariant, #f4f4f5)"
            padding={16}
            borderRadius="var(--ggui-shape-radius-md, 8px)"
            style={{ flex: 1 }}
          >
            <Stack gap={4} align="center">
              <Text variant="caption" color="var(--ggui-color-onSurfaceVariant, #52525b)">
                Wind
              </Text>
              <Text 
                variant="label" 
                color="var(--ggui-color-onSurface, #18181b)"
              >
                {windSpeed} {unit === 'F' ? 'mph' : 'km/h'}
              </Text>
            </Stack>
          </Box>
        </Stack>

        <Divider margin={0} color="var(--ggui-color-outlineVariant, #e4e4e7)" />

        {/* 5-Day Forecast Strip */}
        <Stack 
          direction="horizontal" 
          justify="between" 
          align="center"
        >
          {forecast.map((item, index) => (
            <Stack key={item.day || index} gap={8} align="center">
              <Text variant="caption" color="var(--ggui-color-onSurfaceVariant, #52525b)">
                {item.day || '---'}
              </Text>
              <Text size="lg">
                {item.icon || getWeatherEmoji('Unknown')}
              </Text>
              <Stack direction="horizontal" gap={4}>
                <Text 
                  variant="caption" 
                  weight="semibold" 
                  color="var(--ggui-color-onSurface, #18181b)"
                >
                  {item.high ?? '--'}°
                </Text>
                <Text 
                  variant="caption" 
                  color="var(--ggui-color-onSurfaceVariant, #52525b)"
                >
                  {item.low ?? '--'}°
                </Text>
              </Stack>
            </Stack>
          ))}
        </Stack>
      </Stack>
    </Card>
  );
}

import React, { useState } from 'react';
import {
  Container,
  Card,
  Stack,
  Text,
  Heading,
  Button,
  Input,
  TextArea,
  RadioGroup,
  Checkbox,
  Progress,
  Divider,
  Box,
  Alert
} from '@ggui-ai/design/primitives';

interface Props {
  /** Available feature options for the checkbox step */
  featureOptions: string[];
  /** Labels for satisfaction rating (e.g., Very Unsatisfied to Very Satisfied) */
  satisfactionLabels: string[];
  /** Callback fired when the survey is submitted */
  onSubmit?: (data: {
    name: string;
    email: string;
    satisfaction: string;
    features: string[];
    comments: string;
  }) => void;
}

/**
 * Multi-step survey form component with 4 input steps and a final review.
 */
export default function SurveyForm({
  featureOptions = [
    'Advanced Analytics',
    'Custom Integrations',
    'Automated Reporting',
    'Mobile App Access',
    'Priority Support'
  ],
  satisfactionLabels = [
    'Very Unsatisfied',
    'Unsatisfied',
    'Neutral',
    'Satisfied',
    'Very Satisfied'
  ],
  onSubmit
}: Props) {
  // Navigation State
  const [step, setStep] = useState(1);
  const totalSteps = 5;

  // Form Data State
  const [name, setName] = useState('');
  const [email, setEmail] = useState('');
  const [satisfaction, setSatisfaction] = useState('');
  const [features, setFeatures] = useState<string[]>([]);
  const [comments, setComments] = useState('');

  // Touched state
  const [touchedName, setTouchedName] = useState(false);
  const [touchedEmail, setTouchedEmail] = useState(false);

  // Status
  const [isSubmitting, setIsSubmitting] = useState(false);
  const [submitSuccess, setSubmitSuccess] = useState(false);

  // Validation
  const isNameValid = name.trim().length > 0;
  const isEmailValid = /^[^\s@]+@[^\s@]+\.[^\s@]+$/.test(email);
  const nameError = touchedName && !isNameValid ? 'Name is required' : undefined;
  const emailError = touchedEmail ? (email.trim() === '' ? 'Email is required' : (!isEmailValid ? 'Invalid email' : undefined)) : undefined;

  const handleNext = () => {
    if (step === 1) { setTouchedName(true); setTouchedEmail(true); if (!isNameValid || !isEmailValid) return; }
    if (step === 2 && !satisfaction) return;
    if (step < totalSteps) setStep(s => s + 1);
  };

  const handleSubmit = async () => {
    setIsSubmitting(true);
    try {
      if (onSubmit) {
        await onSubmit({ name, email, satisfaction, features, comments });
      }
      setSubmitSuccess(true);
    } catch (err) {
      console.error(err);
    } finally {
      setIsSubmitting(false);
    }
  };

  const toggleFeature = (f: string, checked: boolean) => {
    setFeatures(prev => checked ? [...prev, f] : prev.filter(item => item !== f));
  };

  const progress = ((step - 1) / (totalSteps - 1)) * 100;

  if (submitSuccess) {
    return (
      <Container maxWidth="md" padding={24}>
        <Alert variant="success" title="Submitted">Thank you for your feedback.</Alert>
      </Container>
    );
  }

  return (
    <Container maxWidth="md" padding={24}>
      <Card shadow="md" padding={32} radius="lg">
        <Stack gap={32}>
          <Stack gap={8}>
            <Heading level={2} align="center">Customer Survey</Heading>
            <Stack gap={4}>
              <Stack direction="horizontal" justify="between"><Text variant="label">{step === 5 ? 'Review' : `Step ${step} of 4`}</Text><Text variant="caption">{Math.round(progress)}%</Text></Stack>
              <Progress value={progress} size="sm" />
            </Stack>
          </Stack>

          <Box>
            <div style={{ minHeight: '340px' }}>
              {step === 1 && (
                <Stack gap={24}>
                  <Heading level={4}>Personal Info</Heading>
                  <Input label="Name" placeholder="Jane Doe" value={name} onChange={setName} error={nameError} required onBlur={() => setTouchedName(true)} />
                  <Input label="Email" type="email" placeholder="jane@example.com" value={email} onChange={setEmail} error={emailError} required onBlur={() => setTouchedEmail(true)} />
                </Stack>
              )}
              {step === 2 && (
                <Stack gap={24}>
                  <Heading level={4}>Satisfaction</Heading>
                  <RadioGroup label="Rating" value={satisfaction} onChange={setSatisfaction} options={satisfactionLabels.map((l, i) => ({ value: String(i + 1), label: `${i + 1} - ${l}` }))} />
                </Stack>
              )}
              {step === 3 && (
                <Stack gap={24}>
                  <Heading level={4}>Features</Heading>
                  <Stack gap={12}>{featureOptions.map(f => <Checkbox key={f} label={f} checked={features.includes(f)} onChange={c => toggleFeature(f, c)} />)}</Stack>
                </Stack>
              )}
              {step === 4 && (
                <Stack gap={24}>
                  <Heading level={4}>Feedback</Heading>
                  <TextArea label="Comments" value={comments} onChange={setComments} maxLength={500} showCount rows={5} />
                </Stack>
              )}
              {step === 5 && (
                <Stack gap={24}>
                  <Heading level={4}>Review</Heading>
                  <Card padding={24} shadow="none" border>
                    <Stack gap={16}>
                      <Box><Text variant="caption">Contact</Text><Text variant="body">{name} ({email})</Text></Box>
                      <Divider margin={4} />
                      <Box><Text variant="caption">Rating</Text><Text variant="body">{satisfactionLabels[Number(satisfaction) - 1]}</Text></Box>
                      <Divider margin={4} />
                      <Box><Text variant="caption">Features</Text><Text variant="body">{features.join(', ') || 'None'}</Text></Box>
                      <Divider margin={4} />
                      <Box><Text variant="caption">Comments</Text><Text variant="body">{comments || 'None'}</Text></Box>
                    </Stack>
                  </Card>
                </Stack>
              )}
            </div>
          </Box>

          <Stack direction="horizontal" justify="between">
            <Button variant="ghost" onClick={() => setStep(s => s - 1)} disabled={step === 1 || isSubmitting}>Back</Button>
            {step < 5 ? (
              <Button variant="primary" onClick={handleNext} disabled={(step === 1 && (!isNameValid || !isEmailValid)) || (step === 2 && !satisfaction)}>Next</Button>
            ) : (
              <Button variant="primary" onClick={handleSubmit} loading={isSubmitting}>Submit</Button>
            )}
          </Stack>
        </Stack>
      </Card>
    </Container>
  );
}

import React, { useState, useMemo } from 'react';
import {
  Card,
  Stack,
  Text,
  Input,
  Box,
  Badge,
  Container,
  Divider,
  Heading,
  Button,
} from '@ggui-ai/design/primitives';

interface Element {
  atomicNumber?: number;
  symbol?: string;
  name?: string;
  atomicWeight?: number;
  category?: string;
  row?: number;
  col?: number;
}

interface Props {
  /** Full periodic table element data */
  elements: Array<{ atomicNumber?: number; symbol?: string; name?: string; atomicWeight?: number; category?: string; row?: number; col?: number }>;
}

const getCategoryColor = (category: string | undefined): string => {
  const cat = category?.toLowerCase() || '';
  if (cat.includes('noble gas')) return 'var(--ggui-color-info-500, #06b6d4)';
  if (cat.includes('alkali metal')) return 'var(--ggui-color-error-500, #ef4444)';
  if (cat.includes('alkaline earth metal')) return 'var(--ggui-color-warning-500, #f59e0b)';
  if (cat.includes('transition metal')) return 'var(--ggui-color-warning-400, #fbbf24)';
  if (cat.includes('lanthanide')) return 'var(--ggui-color-primary-300, #7dd3fc)';
  if (cat.includes('actinide')) return 'var(--ggui-color-primary-500, #0ea5e9)';
  if (cat.includes('metalloid')) return 'var(--ggui-color-success-600, #16a34a)';
  if (cat.includes('post-transition metal')) return 'var(--ggui-color-success-400, #4ade80)';
  if (cat.includes('nonmetal')) return 'var(--ggui-color-info-400, #22d3ee)';
  return 'var(--ggui-color-neutral-300, #d1d5db)';
};

export default function PeriodicTable({
  elements = [],
}: Props) {
  const [searchQuery, setSearchQuery] = useState('');
  const [selectedElement, setSelectedElement] = useState<Element | null>(null);

  const processedElements = useMemo(() => {
    const query = searchQuery.toLowerCase().trim();
    return elements.map((el) => ({
      ...el,
      isMatch: !query || 
        (el.name?.toLowerCase().includes(query) || 
         el.symbol?.toLowerCase().includes(query)),
    }));
  }, [elements, searchQuery]);

  const categories = useMemo(() => {
    const unique = Array.from(new Set(elements.map((el) => el.category).filter(Boolean)));
    return unique.sort() as string[];
  }, [elements]);

  return (
    <Container maxWidth="xl" padding="var(--ggui-spacing-4, 16px)">
      <Stack gap="var(--ggui-spacing-6, 24px)">
        <Stack direction="horizontal" justify="between" align="end" wrap gap="var(--ggui-spacing-4, 16px)">
          <Stack gap="var(--ggui-spacing-1, 4px)">
            <Heading level={2}>Periodic Table</Heading>
            <Text variant="bodySmall" color="var(--ggui-color-onSurfaceVariant, #52525b)">
              Interactive chemical element database
            </Text>
          </Stack>
          <Box style={{ width: '100%', maxWidth: '300px' }}>
            <Input label="Search Elements" placeholder="Search by name or symbol..." value={searchQuery} onChange={setSearchQuery} type="search" />
          </Box>
        </Stack>

        <Box padding="var(--ggui-spacing-4, 16px)" background="var(--ggui-color-surfaceVariant, #f4f4f5)" borderRadius="var(--ggui-shape-radius-lg, 12px)">
          <Stack direction="horizontal" gap="var(--ggui-spacing-4, 16px)" wrap justify="center">
            {categories.map((cat) => (
              <Stack key={cat} direction="horizontal" gap="var(--ggui-spacing-2, 8px)" align="center">
                <Box style={{ width: 'var(--ggui-spacing-4, 16px)', height: 'var(--ggui-spacing-4, 16px)', borderRadius: 'var(--ggui-shape-radius-sm, 4px)', backgroundColor: getCategoryColor(cat) }} />
                <Text variant="caption" weight="medium">{cat}</Text>
              </Stack>
            ))}
          </Stack>
        </Box>

        <Box style={{ display: 'grid', gridTemplateColumns: 'repeat(18, minmax(40px, 1fr))', gap: 'var(--ggui-spacing-1, 4px)', width: '100%', overflowX: 'auto', padding: 'var(--ggui-spacing-1, 4px)', backgroundColor: 'var(--ggui-color-surface, #fafafa)' }}>
          {processedElements.map((el) => {
            const isSelected = selectedElement?.atomicNumber === el.atomicNumber;
            const bgColor = getCategoryColor(el.category);
            return (
              <Box key={el.atomicNumber} style={{ gridRow: el.row, gridColumn: el.col, aspectRatio: '1/1', opacity: el.isMatch ? 1 : 0.2, transition: 'all 200ms cubic-bezier(0.4, 0, 0.2, 1)', zIndex: isSelected ? 10 : 1, transform: isSelected ? 'scale(1.15)' : 'scale(1)' }}>
                <Button variant="ghost" onPress={() => setSelectedElement(el)} style={{ width: '100%', height: '100%', padding: 0, backgroundColor: bgColor, borderRadius: 'var(--ggui-shape-radius-sm, 4px)', display: 'flex', flexDirection: 'column', position: 'relative', border: isSelected ? '2px solid var(--ggui-color-onSurface, #18181b)' : '1px solid var(--ggui-color-outlineVariant, #e4e4e7)', boxShadow: isSelected ? 'var(--ggui-shape-shadow-md, 0 4px 6px -1px rgba(0,0,0,0.1))' : 'none' }}>
                  <Text variant="caption" style={{ position: 'absolute', top: 'var(--ggui-spacing-1, 4px)', left: 'var(--ggui-spacing-1, 4px)', fontSize: 'var(--ggui-font-size-xs, 12px)', fontWeight: 'var(--ggui-font-weight-bold, 700)', opacity: 0.8 }}>{el.atomicNumber}</Text>
                  <Box style={{ flex: 1, display: 'flex', alignItems: 'center', justifyContent: 'center' }}>
                    <Text weight="bold" style={{ fontSize: 'var(--ggui-font-size-base, 16px)', color: 'var(--ggui-color-onSurface, #18181b)' }}>{el.symbol}</Text>
                  </Box>
                </Button>
              </Box>
            );
          })}
        </Box>

        {selectedElement ? (
          <Card padding="var(--ggui-spacing-6, 24px)" shadow="md" radius="xl">
