import React, { useState, useEffect, useRef } from 'react';
import {
  Card,
  Stack,
  Box,
  Heading,
  Badge,
  Divider,
  Input,
  Button,
  Text,
  Avatar,
  Icon,
} from '@ggui-ai/design/primitives';

interface Message {
  sender?: string;
  text?: string;
  timestamp?: string;
}

interface Props {
  /** Chat window title */
  title: string;
  /** Current user name (for right-aligning own messages) */
  currentUser: string;
  /** Number of participants */
  participantCount?: number;
  /** Array of messages with sender name, text, and ISO timestamp */
  messages: Message[];
}

/**
 * ChatInterface Component
 */
export default function ChatInterface(props: Props) {
  const { title, currentUser, messages, participantCount = 0 } = props;
  const [localMessages, setLocalMessages] = useState<Message[]>(messages);
  const [inputValue, setInputValue] = useState('');
  const endRef = useRef<HTMLDivElement>(null);

  useEffect(() => {
    setLocalMessages(messages);
  }, [messages]);

  useEffect(() => {
    endRef.current?.scrollIntoView({ behavior: 'smooth' });
  }, [localMessages]);

  useEffect(() => {
    const handleStream = (e: Event) => {
      const detail = (e as CustomEvent<Message>).detail;
      if (detail) {
        setLocalMessages((prev) => [...prev, detail]);
      }
    };

    // Using global event listeners for Stream Contract
    if (typeof addEventListener !== 'undefined') {
      addEventListener('ggui:agent-data', handleStream);
      return () => removeEventListener('ggui:agent-data', handleStream);
    }
    return undefined;
  }, []);

  const send = () => {
    if (!inputValue.trim()) return;
    const payload = { text: inputValue.trim(), timestamp: new Date().toISOString() };

    // Optimistic Update
    setLocalMessages((prev) => [...prev, { sender: currentUser, ...payload }]);

    // Action Contract
    if (typeof dispatchEvent !== 'undefined') {
      dispatchEvent(new CustomEvent('ggui:action', { detail: { action: 'Send Message', payload } }));
    }

    setInputValue('');
  };

  return (
    <Card shadow="md" radius="lg" padding={0} border>
      <Stack gap={0} direction="vertical" style={{ height: '600px', backgroundColor: 'var(--ggui-color-surface, #fafafa)' }}>
        <Box padding={16} background="var(--ggui-color-surface)">
          <Stack direction="horizontal" justify="between" align="center">
            <Stack direction="horizontal" align="center" gap={8}>
              <Heading level={4}>{title}</Heading>
              {participantCount > 0 && <Badge variant="primary" size="sm" pill>{participantCount}</Badge>}
            </Stack>
            <Icon name="settings" size={20} color="var(--ggui-color-neutral-500)" />
          </Stack>
        </Box>
        <Divider margin={0} color="var(--ggui-color-outlineVariant)" />
        <div style={{ flex: 1, overflowY: 'auto', padding: 'var(--ggui-spacing-4, 16px)' }}>
          <Stack direction="vertical" gap={12}>
            {localMessages.map((m, i) => {
              const me = m.sender === currentUser;
              const g = i > 0 && localMessages[i - 1].sender === m.sender;
              return (
                <Stack key={i} direction="vertical" align={me ? 'end' : 'start'} gap={4}>
                  {!me && !g && (
                    <Stack direction="horizontal" align="center" gap={8}>
                      <Avatar name={m.sender} size="xs" />
                      <Text variant="label" size="xs" color="var(--ggui-color-onSurfaceVariant)">{m.sender}</Text>
                    </Stack>
                  )}
                  <Box paddingX={16} paddingY={10} background={me ? 'var(--ggui-color-primary-600)' : 'var(--ggui-color-surfaceVariant)'} borderRadius={16} style={{ maxWidth: '80%', borderTopRightRadius: me && g ? 4 : 16, borderTopLeftRadius: !me && g ? 4 : 16 }}>
                    <Text variant="bodySmall" color={me ? 'var(--ggui-color-surface, #ffffff)' : 'var(--ggui-color-onSurface)'}>{m.text}</Text>
                  </Box>
                  <Text variant="caption" size="xs" color="var(--ggui-color-neutral-400)">{m.timestamp ? new Date(m.timestamp).toLocaleTimeString() : ''}</Text>
                </Stack>
              );
            })}
            <div ref={endRef} />
          </Stack>
        </div>
        <Divider margin={0} color="var(--ggui-color-outlineVariant)" />
        <Box padding={16} background="var(--ggui-color-surface)">
          <Stack direction="horizontal" align="end" gap={12}>
            <div style={{ flex: 1 }}>
              <Text as="label" variant="label" size="xs" {...({ htmlFor: 'chat-input' } as any)}>Message</Text>
              <Input label="Message" id="chat-input" placeholder="Type here..." value={inputValue} onChange={setInputValue} onKeyDown={(e) => { if (e.key === 'Enter') send(); }} />
            </div>
            <Button variant="primary" disabled={!inputValue.trim()} onClick={send} rightIcon={<Icon name="check" size={16} />}>Send</Button>
          </Stack>
        </Box>
      </Stack>
    </Card>
  );
}

