import React, { useState, useEffect } from 'react';
import { 
  Container, 
  Card, 
  Stack, 
  Text, 
  Heading, 
  Divider, 
  Box, 
  Spinner 
} from '@ggui-ai/design/primitives';
import { Tag } from '@ggui-ai/design/components';
import { CardGrid } from '@ggui-ai/design/compositions';

interface Stock {
  symbol?: string;
  name?: string;
  price?: number;
  change?: number;
  changePercent?: number;
}

interface Props {
  /** Array of stocks with symbol, name, price, change, changePercent */
  stocks: Stock[];
  /** ISO timestamp of last price update */
  lastUpdated?: string;
}

/**
 * StockTickerDashboard: A real-time stock price display component.
 * Layout:
 * - Header with title and timestamp
 * - Grid of stock cards with color-coded status
 */
export default function StockTickerDashboard(props: Props) {
  const [stocks, setStocks] = useState<Stock[]>(props.stocks || []);
  const [lastUpdated, setLastUpdated] = useState<string | undefined>(props.lastUpdated);

  useEffect(() => {
    if (props.stocks) setStocks(props.stocks);
    if (props.lastUpdated) setLastUpdated(props.lastUpdated);
  }, [props.stocks, props.lastUpdated]);

  useEffect(() => {
    const handleBroadcast = (event: Event) => {
      const detail = (event as CustomEvent).detail;
      if (detail) {
        if (Array.isArray(detail.stocks)) setStocks(detail.stocks);
        if (detail.lastUpdated) setLastUpdated(detail.lastUpdated);
      }
    };
    addEventListener('ggui:agent-data', handleBroadcast);
    return () => removeEventListener('ggui:agent-data', handleBroadcast);
  }, []);

  const formatTime = (iso?: string) => {
    if (!iso) return '';
    try {
      return new Date(iso).toLocaleTimeString([], { hour: '2-digit', minute: '2-digit' });
    } catch {
      return iso;
    }
  };

  if (!stocks || stocks.length === 0) {
    return (
      <Container maxWidth="xl" padding={24}>
        <Box paddingY={64}>
          <Stack align="center" justify="center" gap={16}>
            <Spinner size={32} color="var(--ggui-color-primary-600, #0284c7)" />
            <Text color="var(--ggui-color-onSurfaceVariant, #52525b)">Connecting to market data feed...</Text>
          </Stack>
        </Box>
      </Container>
    );
  }

  return (
    <Container maxWidth="xl" padding={24}>
      <Stack gap={24}>

        {/* Header with Title and Timestamp */}
        <Stack direction="horizontal" justify="between" align="center" wrap gap={12}>
          <Heading level={2} color="var(--ggui-color-onSurface, #18181b)">Market Watch</Heading>
          {lastUpdated && (
            <Text variant="caption" color="var(--ggui-color-onSurfaceVariant, #52525b)">
              Last Updated: {formatTime(lastUpdated)}
            </Text>
          )}
        </Stack>

        {/* Dashboard Grid - 3 per row on desktop, 1 on mobile */}
        <CardGrid columns={{ sm: 1, md: 2, lg: 3 }} gap={16}>
          {stocks.map((stock, i) => {
            const price = stock.price ?? 0;
            const change = stock.change ?? 0;
            const pct = stock.changePercent ?? 0;
            const isPos = change >= 0;
            const variant = isPos ? 'success' : 'error';
            const icon = isPos ? '▲' : '▼';

            return (
              <Card 
                key={stock.symbol || `stock-${i}`} 
                padding={24} 
                shadow="sm" 
                radius="lg"
                border
              >
                <Stack gap={16}>
                  <Stack direction="horizontal" justify="between" align="start" gap={8}>
                    <Stack gap={2} style={{ flex: 1, minWidth: 0 }}>
                      <Heading level={3} color="var(--ggui-color-onSurface, #18181b)">{stock.symbol || '---'}</Heading>
                      <Text variant="caption" color="var(--ggui-color-onSurfaceVariant, #52525b)" truncate>
                        {stock.name || 'Unknown'}
                      </Text>
                    </Stack>
                    <Text size="xl" weight="bold" color="var(--ggui-color-onSurface, #18181b)">
                      ${price.toFixed(2)}
                    </Text>
                  </Stack>

                  <Divider margin={4} color="var(--ggui-color-outlineVariant, #e4e4e7)" />

                  <Stack direction="horizontal" justify="between" align="center" gap={8}>
                    <Text variant="label" color="var(--ggui-color-onSurfaceVariant, #52525b)">Daily Change</Text>
                    <Tag variant={variant} size="lg">
                      <Stack direction="horizontal" gap={4} align="center">
                        <Text variant="bodySmall" weight="bold" color="inherit">
                          {icon} {Math.abs(change).toFixed(2)}
                        </Text>
                        <Text variant="caption" weight="medium" color="inherit">
                          ({pct.toFixed(2)}%)
                        </Text>
                      </Stack>
                    </Tag>
                  </Stack>
                </Stack>
              </Card>
            );
          })}
        </CardGrid>

      </Stack>
    </Container>
  );
}

import React, { useState } from 'react';
import { Container, Card, Stack, Box, Text, Heading, Button, Input, Select, Toggle, Progress, Divider } from '@ggui-ai/design/primitives';

interface Props {
  avatarOptions: string[];
  roleOptions: string[];
  initialProfile?: { name?: string; email?: string; avatar?: string; role?: string; emailNotifications?: boolean; theme?: string };
  onComplete: (data: any) => void;
}

export default function GeneratedComponent(props: Props) {
  const [step, setStep] = useState(1);
  const [form, setForm] = useState({
    name: props.initialProfile?.name || '',
    email: props.initialProfile?.email || '',
    avatar: props.initialProfile?.avatar || (props.avatarOptions && props.avatarOptions.length > 0 ? props.avatarOptions[0] : ''),
    role: props.initialProfile?.role || '',
    emailNotifications: props.initialProfile?.emailNotifications ?? true,
    theme: props.initialProfile?.theme || 'light',
  });

  const isEmailValid = (email: string) => /^[^\s@]+@[^\s@]+\.[^\s@]+$/.test(email);
  const isStep1Valid = form.name.trim().length > 0 && isEmailValid(form.email) && form.avatar !== '';
  const isStep2Valid = form.role !== '';

  return (
    <Container maxWidth="md" padding="var(--ggui-spacing-8, 32px)">
      <Stack gap={24}>
        <Progress value={(step / 3) * 100} size="sm" />
        <Card padding="var(--ggui-spacing-6, 24px)" shadow="md" radius="xl" border>
          <div key={step} style={{ animation: 'ggui-fadeIn 300ms ease-out' }}>
            {step === 1 && (
              <Stack gap={20}>
                <Stack gap={4}>
                  <Text as="label" variant="label" color="var(--ggui-color-onSurface, #18181b)">Full Name</Text>
                  <Input label="Full Name" required value={form.name} onChange={(v) => setForm({...form, name: v})} />
                </Stack>
                <Stack gap={4}>
                  <Text as="label" variant="label" color="var(--ggui-color-onSurface, #18181b)">Email Address</Text>
                  <Input label="Email Address" type="email" required value={form.email} onChange={(v) => setForm({...form, email: v})} error={form.email && !isEmailValid(form.email) ? 'Invalid email format' : undefined} />
                </Stack>
                <Stack direction="horizontal" gap={12} wrap>
                  {props.avatarOptions.map(a => (
                    <button key={a} type="button" onClick={() => setForm({...form, avatar: a})} style={{ padding: 'var(--ggui-spacing-4, 16px)', borderRadius: 'var(--ggui-shape-radius-lg, 12px)', border: `2px solid ${form.avatar === a ? 'var(--ggui-color-primary-600, #0284c7)' : 'var(--ggui-color-outline, #d4d4d8)'}`, background: 'var(--ggui-color-surface, #fafafa)', fontSize: '24px', cursor: 'pointer', transition: 'all 200ms ease' }}>{a}</button>
                  ))}
                </Stack>
              </Stack>
            )}
            {step === 2 && (
              <Stack gap={24}>
                <Select label="Role Selection" value={form.role} onChange={(v) => setForm({...form, role: v})} options={props.roleOptions.map(r => ({ label: r, value: r }))} required placeholder="Select a role" />
                <Toggle label="Notifications" checked={form.emailNotifications} onChange={(v) => setForm({...form, emailNotifications: v})} />
                <Toggle label="Dark Appearance" checked={form.theme === 'dark'} onChange={(v) => setForm({...form, theme: v ? 'dark' : 'light'})} />
              </Stack>
            )}
            {step === 3 && (
              <Stack gap={20}>
                <Box padding="var(--ggui-spacing-6, 24px)" background="var(--ggui-color-surfaceVariant, #f4f4f5)" borderRadius="var(--ggui-shape-radius-lg, 12px)" style={{ border: '1px solid var(--ggui-color-outline, #d4d4d8)' }}>
                  <Heading level={4}>Profile Summary</Heading>
                  <Divider margin="var(--ggui-spacing-2, 8px)" />
                  <Stack gap={12}>
                    <Text variant="bodySmall">Name: {form.name}</Text>
                    <Text variant="bodySmall">Email: {form.email}</Text>
                    <Text variant="bodySmall">Role: {form.role}</Text>
                    <Text variant="bodySmall">Avatar: {form.avatar}</Text>
                  </Stack>
                </Box>
              </Stack>
            )}
          </div>
        </Card>
        <Stack direction="horizontal" justify="between">
          <Button variant="ghost" onClick={() => setStep(step - 1)} disabled={step === 1}>Go Back</Button>
          {step < 3 ? (
            <Button variant="primary" onClick={() => setStep(step + 1)} disabled={step === 1 ? !isStep1Valid : !isStep2Valid}>Next Step</Button>
          ) : (
            <Button variant="primary" onClick={() => props.onComplete(form)}>Complete Setup</Button>
          )}
        </Stack>
      </Stack>
    </Container>
  );
}

