import React, { useState } from 'react';
import { Container, Card, Stack, Text, Button, Input, TextArea, RadioGroup, Checkbox, Progress, Divider, Box } from '@ggui-ai/design/primitives';

interface Props {
  featureOptions: string[];
  satisfactionLabels: string[];
  onSubmit?: (answers: SurveyAnswers) => void;
}

interface SurveyAnswers {
  name: string;
  email: string;
  satisfactionRating: string;
  selectedFeatures: string[];
  comments: string;
}

export default function GeneratedComponent(props: Props) {
  const [currentStep, setCurrentStep] = useState(1);
  const [isSubmitting, setIsSubmitting] = useState(false);
  const [submitError, setSubmitError] = useState('');
  const [submitSuccess, setSubmitSuccess] = useState(false);
  const [name, setName] = useState('');
  const [email, setEmail] = useState('');
  const [satisfactionRating, setSatisfactionRating] = useState('');
  const [selectedFeatures, setSelectedFeatures] = useState<string[]>([]);
  const [comments, setComments] = useState('');
  const [nameError, setNameError] = useState('');
  const [emailError, setEmailError] = useState('');

  const validateEmail = (value: string): boolean => {
    const emailRegex = /^[^\s@]+@[^\s@]+\.[^\s@]+$/;
    return emailRegex.test(value);
  };

  const validateStep1 = (): boolean => {
    let isValid = true;
    setNameError('');
    setEmailError('');
    if (!name.trim()) {
      setNameError('Name is required');
      isValid = false;
    }
    if (!email.trim()) {
      setEmailError('Email is required');
      isValid = false;
    } else if (!validateEmail(email)) {
      setEmailError('Please enter a valid email address');
      isValid = false;
    }
    return isValid;
  };

  const handleNext = () => {
    if (currentStep === 1) {
      if (!validateStep1()) return;
    }
    setCurrentStep(currentStep + 1);
  };

  const handleBack = () => {
    setCurrentStep(currentStep - 1);
  };

  const handleFeatureToggle = (feature: string) => {
    setSelectedFeatures((prev) =>
      prev.includes(feature)
        ? prev.filter((f) => f !== feature)
        : [...prev, feature]
    );
  };

  const handleSubmit = async () => {
    setIsSubmitting(true);
    setSubmitError('');
    try {
      const answers: SurveyAnswers = {
        name,
        email,
        satisfactionRating,
        selectedFeatures,
        comments,
      };
      if (props.onSubmit) {
        props.onSubmit(answers);
      }
      setSubmitSuccess(true);
    } catch (error) {
      setSubmitError('Failed to submit survey. Please try again.');
    } finally {
      setIsSubmitting(false);
    }
  };

  const isStep1Valid = name.trim() && email.trim() && validateEmail(email);
  const isStep2Valid = satisfactionRating !== '';

  if (submitSuccess) {
    return (
      <Container maxWidth="md" padding={24}>
        <Card shadow="md" padding={32} radius="lg">
          <Stack gap={16} align="center">
            <Text variant="label" align="center" size="lg" weight="semibold">
              ✓ Survey Submitted Successfully!
            </Text>
            <Text variant="body" align="center" color="var(--ggui-color-onSurfaceVariant, #52525b)">
              Thank you for completing the survey. Your feedback is valuable to us.
            </Text>
          </Stack>
        </Card>
      </Container>
    );
  }

  return (
    <Container maxWidth="md" padding={24}>
      <Card shadow="md" padding={32} radius="lg">
        <form>
          <Stack gap={24}>
            <Stack gap={12}>
              <Stack direction="horizontal" justify="between" align="center">
                <Text variant="label" color="var(--ggui-color-onSurface, #18181b)">
                  Step {currentStep} of 4
                </Text>
                <Text variant="bodySmall" color="var(--ggui-color-onSurfaceVariant, #52525b)">
                  {currentStep === 1 && 'Your Information'}
                  {currentStep === 2 && 'Satisfaction Rating'}
                  {currentStep === 3 && 'Feature Interests'}
                  {currentStep === 4 && 'Comments'}
                  {currentStep === 5 && 'Review'}
                </Text>
              </Stack>
              <Progress value={((currentStep - 1) / 4) * 100} max={100} variant="default" size="md" />
            </Stack>

            <Divider orientation="horizontal" margin={8} />

            {currentStep === 1 && (
              <Stack gap={16}>
                <Input label="Full Name" placeholder="Enter your full name" value={name} onChange={setName} error={nameError} required />
                <Input label="Email Address" type="email" placeholder="you@example.com" value={email} onChange={setEmail} error={emailError} required />
              </Stack>
            )}

            {currentStep === 2 && (
              <Stack gap={16}>
                <RadioGroup
                  label="How satisfied are you with our service?"
                  value={satisfactionRating}
                  onChange={setSatisfactionRating}
                  options={props.satisfactionLabels.map((label, index) => ({
                    value: String(index + 1),
                    label: label,
                  }))}
                  direction="vertical"
                />
              </Stack>
            )}

            {currentStep === 3 && (
              <Stack gap={16}>
                <Text variant="label" color="var(--ggui-color-onSurface, #18181b)">
                  Which features are you interested in? (Select all that apply)
                </Text>
                <Stack gap={12}>
                  {props.featureOptions.map((feature) => (
                    <Checkbox
                      key={feature}
                      label={feature}
                      checked={selectedFeatures.includes(feature)}
                      onChange={() => handleFeatureToggle(feature)}
                    />
                  ))}
                </Stack>
              </Stack>
            )}

            {currentStep === 4 && (
              <Stack gap={16}>
                <TextArea
                  label="Additional Comments"
                  placeholder="Please share any additional feedback or comments (optional)"
                  value={comments}
                  onChange={setComments}
                  rows={6}
                  maxLength={500}
                  showCount
                />
              </Stack>
            )}

            {currentStep === 5 && (
              <Stack gap={16}>
                <Text variant="label" weight="semibold" color="var(--ggui-color-onSurface, #18181b)">
                  Review Your Answers
                </Text>
                <Box background="var(--ggui-color-surfaceVariant, #f4f4f5)" padding={16} borderRadius="var(--ggui-shape-radius-lg, 12px)">
                  <Stack gap={12}>
                    <div>
                      <Text variant="caption" weight="medium" color="var(--ggui-color-onSurfaceVariant, #52525b)">
                        Name
                      </Text>
                      <Text variant="body">{name}</Text>
                    </div>
                    <div>
                      <Text variant="caption" weight="medium" color="var(--ggui-color-onSurfaceVariant, #52525b)">
                        Email
                      </Text>
                      <Text variant="body">{email}</Text>
                    </div>
                    <div>
                      <Text variant="caption" weight="medium" color="var(--ggui-color-onSurfaceVariant, #52525b)">
                        Satisfaction Rating
                      </Text>
                      <Text variant="body">{props.satisfactionLabels[Number(satisfactionRating) - 1]}</Text>
                    </div>
                    <div>
                      <Text variant="caption" weight="medium" color="var(--ggui-color-onSurfaceVariant, #52525b)">
                        Selected Features
                      </Text>
                      <Text variant="body">{selectedFeatures.length > 0 ? selectedFeatures.join(', ') : 'None selected'}</Text>
                    </div>
                    <div>
                      <Text variant="caption" weight="medium" color="var(--ggui-color-onSurfaceVariant, #52525b)">
                        Comments
                      </Text>
                      <Text variant="body">{comments || '(No comments)'}</Text>
                    </div>
                  </Stack>
                </Box>
              </Stack>
            )}

            {submitError && (
              <Box background="var(--ggui-color-error-50, #fef2f2)" padding="var(--ggui-spacing-2, 8px)" borderRadius="var(--ggui-shape-radius-md, 8px)" style={{ borderLeft: '4px solid var(--ggui-color-error-500, #ef4444)' }}>
                <Text variant="bodySmall" color="var(--ggui-color-error-700, #b91c1c)">
                  {submitError}
                </Text>
              </Box>
            )}

            <Stack direction="horizontal" gap="var(--ggui-spacing-2, 8px)" justify="between">
              <Button variant="ghost" onClick={handleBack} disabled={currentStep === 1}>
                Back
              </Button>
              <Stack direction="horizontal" gap="var(--ggui-spacing-2, 8px)">
                {currentStep < 5 && (
                  <Button variant="primary" onClick={handleNext} disabled={(currentStep === 1 && !isStep1Valid) || (currentStep === 2 && !isStep2Valid)}>
                    Next
                  </Button>
                )}
                {currentStep === 4 && (
                  <Button variant="primary" onClick={() => setCurrentStep(5)}>
                    Review
                  </Button>
                )}
                {currentStep === 5 && (
                  <Button variant="primary" onClick={handleSubmit} loading={isSubmitting} disabled={isSubmitting}>
                    Submit Survey
                  </Button>
                )}
              </Stack>
            </Stack>
          </Stack>
        </form>
      </Card>
    </Container>
  );
}

import React, { useState, useMemo } from 'react';
import {
  Container,
  Stack,
  Input,
  Card,
  Badge,
  Divider,
  Box,
  Text,
  Heading,
} from '@ggui-ai/design/primitives';

interface Element {
  atomicNumber?: number;
  symbol?: string;
  name?: string;
  atomicWeight?: number;
  category?: string;
  row?: number;
  col?: number;
}

interface Props {
  elements: Array<{
    atomicNumber?: number;
    symbol?: string;
    name?: string;
    atomicWeight?: number;
    category?: string;
    row?: number;
    col?: number;
  }>;
}

const getCategoryColor = (category?: string): string => {
  const categoryColorMap: Record<string, string> = {
    'Noble Gas': 'var(--ggui-color-primary-300, #7dd3fc)',
    Halogen: 'var(--ggui-color-warning-400, #fbbf24)',
    'Alkali Metal': 'var(--ggui-color-error-300, #fca5a5)',
    'Alkaline Earth': 'var(--ggui-color-warning-200, #fef08a)',
    'Transition Metal': 'var(--ggui-color-neutral-300, #d1d5db)',
    Lanthanide: 'var(--ggui-color-info-300, #a5f3fc)',
    Actinide: 'var(--ggui-color-success-300, #86efac)',
    Metalloid: 'var(--ggui-color-neutral-200, #e5e7eb)',
    Nonmetal: 'var(--ggui-color-primary-100, #e0f2fe)',
  };
  return categoryColorMap[category || ''] || 'var(--ggui-color-surface, #fafafa)';
};

export default function GeneratedComponent({ elements = [] }: Props) {
  const [searchQuery, setSearchQuery] = useState('');
  const [selectedElement, setSelectedElement] = useState<Element | null>(null);
  const [hoveredAtomicNumber, setHoveredAtomicNumber] = useState<number | null>(
    null
  );

  const filteredElements = useMemo(() => {
    if (!searchQuery.trim()) return elements;
    const query = searchQuery.toLowerCase();
    return elements.filter(
      (el) =>
        (el.symbol?.toLowerCase().includes(query)) ||
        (el.name?.toLowerCase().includes(query))
    );
  }, [searchQuery, elements]);

  const categories = useMemo(() => {
    const cats = new Set<string>();
    elements.forEach((el) => {
      if (el.category) cats.add(el.category);
    });
    return Array.from(cats).sort();
  }, [elements]);

  return (
    <Container maxWidth="3xl" padding={24}>
      <Stack direction="vertical" gap={16}>
        <Input
          label="Search Elements"
          placeholder="Search by name or symbol..."
          value={searchQuery}
          onChange={setSearchQuery}
        />

        {categories.length > 0 && (
          <>
            <Stack direction="horizontal" gap={8} wrap={true} align="start">
              {categories.map((cat) => (
                <Badge
                  key={cat}
                  variant="primary"
                  size="sm"
                  pill
                  style={{
                    backgroundColor: getCategoryColor(cat),
                    color: 'var(--ggui-color-onSurface, #18181b)',
                  }}
                >
                  {cat}
                </Badge>
              ))}
            </Stack>

            <Divider margin={16} />
          </>
        )}

        {filteredElements.length > 0 ? (
          <Box
            background="var(--ggui-color-surface, #fafafa)"
            padding={16}
            borderRadius={12}
            style={{
              display: 'grid',
              gridTemplateColumns: 'repeat(18, 1fr)',
              gap: 'var(--ggui-spacing-1, 4px)',
              border: '1px solid var(--ggui-color-outline, #d4d4d8)',
              overflowX: 'auto',
            }}
          >
            {filteredElements.map((el) => (
              <button
                key={el.atomicNumber}
                onClick={() => setSelectedElement(el)}
                onMouseEnter={() =>
                  setHoveredAtomicNumber(el.atomicNumber ?? null)
                }
                onMouseLeave={() => setHoveredAtomicNumber(null)}
                style={{
                  gridRow: el.row,
                  gridColumn: el.col,
                  backgroundColor: getCategoryColor(el.category),
                  cursor: 'pointer',
                  position: 'relative',
                  transition: 'box-shadow 200ms ease-in-out',
                  minHeight: '60px',
                  display: 'flex',
                  flexDirection: 'column',
                  justifyContent: 'center',
                  alignItems: 'center',
                  padding: 'var(--ggui-spacing-1, 4px)',
                  borderRadius: 'var(--ggui-shape-radius-sm, 4px)',
                  border: '1px solid var(--ggui-color-outline, #d4d4d8)',
                  boxShadow:
                    hoveredAtomicNumber === el.atomicNumber
                      ? 'var(--ggui-shape-shadow-sm, 0 1px 2px rgba(0,0,0,0.05))'
                      : 'none',
                }}
                aria-label={`Element ${el.name} (${el.symbol})`}
              >
                <Text
                  as="span"
                  size="xs"
                  weight="semibold"
                  style={{
                    position: 'absolute',
                    top: 'var(--ggui-spacing-1, 4px)',
                    left: 'var(--ggui-spacing-1, 4px)',
                    color: 'var(--ggui-color-onSurfaceVariant, #52525b)',
                  }}
                >
                  {el.atomicNumber}
                </Text>
                <Text
                  as="span"
                  weight="bold"
                  size="xl"
                  align="center"
                  style={{ color: 'var(--ggui-color-onSurface, #18181b)' }}
                >
                  {el.symbol}
                </Text>
              </button>
            ))}
          </Box>
        ) : (
          <Card padding={16} shadow="sm">
            <Text
              align="center"
              color="var(--ggui-color-onSurfaceVariant, #52525b)"
            >
              No elements match your search.
            </Text>
          </Card>
        )}

        {selectedElement && (
          <Card padding={16} shadow="sm">
            <Stack direction="vertical" gap={12}>
              <Heading level={3}>{selectedElement.name}</Heading>
              <Stack direction="vertical" gap={8}>
                <Text variant="body">
                  <strong>Symbol:</strong> {selectedElement.symbol}
                </Text>
                <Text variant="body">
                  <strong>Atomic Number:</strong> {selectedElement.atomicNumber}
                </Text>
                <Text variant="body">
                  <strong>Atomic Weight:</strong>{' '}
                  {selectedElement.atomicWeight
                    ? selectedElement.atomicWeight.toFixed(2)
                    : 'N/A'}
                </Text>
                <Text variant="body">
                  <strong>Category:</strong> {selectedElement.category || 'N/A'}
                </Text>
              </Stack>
            </Stack>
          </Card>
        )}
      </Stack>
    </Container>
  );
}

import React, { useState, useRef, useEffect } from 'react';
import { Card, Stack, Heading, Text, Badge, Box, Input, Button, Icon } from '@ggui-ai/design/primitives';

interface Props {
  title: string;
  currentUser: string;
  participantCount?: number;
  messages: Array<{ sender?: string; text?: string; timestamp?: string }>;
  onSend?: (payload: { text: string; timestamp: string }) => void;
  onSendMessage?: (payload: { text: string; timestamp: string }) => void;
}

interface MessageGroup {
  sender: string | undefined;
  messages: Array<{ sender?: string; text?: string; timestamp?: string }>;
  isCurrentUser: boolean;
}

export default function ChatInterface({ title, currentUser, participantCount, messages = [], onSend, onSendMessage }: Props) {
  const [inputValue, setInputValue] = useState<string>('');
  const messagesEndRef = useRef<HTMLDivElement | null>(null);

  useEffect(() => {
    if (messagesEndRef.current) {
      messagesEndRef.current.scrollIntoView({ behavior: 'smooth' });
    }
  }, [messages]);

  const formatTimestamp = (isoString?: string): string => {
    if (!isoString) return '';
    try {
      const date = new Date(isoString);
      return date.toLocaleTimeString([], { hour: '2-digit', minute: '2-digit' });
    } catch {
      return isoString;
    }
  };

  const handleSend = () => {
    if (inputValue.trim().length === 0) return;
    const payload = { text: inputValue, timestamp: new Date().toISOString() };
    onSendMessage?.(payload);
    onSend?.(payload);
    setInputValue('');
  };

  const messageGroups: MessageGroup[] = [];
  let currentGroup: MessageGroup | null = null;

  for (const msg of messages) {
    const isCurrentUser = msg.sender === currentUser;
    const msgSender = msg.sender;
    if (currentGroup && currentGroup.sender !== msgSender) {
      messageGroups.push(currentGroup);
      currentGroup = null;
    }
    if (!currentGroup) {
      currentGroup = { sender: msgSender, messages: [msg], isCurrentUser };
    } else {
      currentGroup.messages.push(msg);
    }
  }
  if (currentGroup) {
    messageGroups.push(currentGroup);
  }

  const isSendDisabled = inputValue.trim().length === 0;

  return (
    <Card shadow="md" radius="lg" border={true} padding={0} style={{ display: 'flex', flexDirection: 'column', height: '100%', minHeight: '100vh', backgroundColor: 'var(--ggui-color-surface, #fafafa)' }}>
      <Box paddingX={16} paddingY={12} background="var(--ggui-color-surface, #fafafa)" borderRadius={0} style={{ borderBottom: '1px solid var(--ggui-color-outline, #d4d4d8)' }}>
        <Stack direction="horizontal" gap={16} align="center" justify="between">
          <Stack direction="vertical" gap={4}>
            <Heading level={3} color="var(--ggui-color-onSurface, #18181b)">{title}</Heading>
            {participantCount !== undefined && (
              <Text variant="caption" color="var(--ggui-color-onSurfaceVariant, #52525b)">
                {participantCount} participant{participantCount !== 1 ? 's' : ''}
              </Text>
            )}
          </Stack>
          {participantCount !== undefined && (
            <Badge variant="primary" size="sm" pill={true}>
              {participantCount}
            </Badge>
          )}
        </Stack>
      </Box>

      <Box style={{ flex: 1, overflowY: 'auto', overflowX: 'hidden', backgroundColor: 'var(--ggui-color-surface, #fafafa)', padding: 'var(--ggui-spacing-4, 16px)' }} borderRadius={0}>
        <Stack direction="vertical" gap={8} align="stretch">
          {messageGroups.length === 0 ? (
            <Text variant="body" color="var(--ggui-color-onSurfaceVariant, #52525b)" align="center">
              No messages yet. Start the conversation!
            </Text>
          ) : (
            messageGroups.map((group, groupIdx) => (
              <Stack key={groupIdx} direction="vertical" gap={2} align={group.isCurrentUser ? 'end' : 'start'}>
                <Text variant="label" color="var(--ggui-color-onSurfaceVariant, #52525b)" size="xs">
                  {group.sender || 'Unknown'}
                </Text>
                {group.messages.map((msg, msgIdx) => (
                  <Box
                    key={msgIdx}
                    padding={12}
                    background={group.isCurrentUser ? 'var(--ggui-color-primary-600, #0284c7)' : 'var(--ggui-color-surfaceVariant, #f4f4f5)'}
                    borderRadius={12}
                    style={{ maxWidth: '60%', wordWrap: 'break-word', boxShadow: 'var(--ggui-shape-shadow-sm, 0 1px 2px rgba(0,0,0,0.05))' }}
                  >
                    <Stack direction="vertical" gap={4}>
                      <Text variant="body" color={group.isCurrentUser ? 'var(--ggui-color-neutral-50, #f9fafb)' : 'var(--ggui-color-onSurface, #18181b)'}>
                        {msg.text || ''}
                      </Text>
                      <Text variant="caption" color={group.isCurrentUser ? 'var(--ggui-color-primary-100, #e0f2fe)' : 'var(--ggui-color-onSurfaceVariant, #52525b)'}>
                        {formatTimestamp(msg.timestamp)}
                      </Text>
                    </Stack>
                  </Box>
                ))}
              </Stack>
            ))
          )}
          <div ref={messagesEndRef} />
        </Stack>
      </Box>

      <Box paddingX={16} paddingY={12} background="var(--ggui-color-surface, #fafafa)" borderRadius={0} style={{ borderTop: '1px solid var(--ggui-color-outline, #d4d4d8)' }}>
        <Stack direction="horizontal" gap={8} align="center">
          <Input label="Message" placeholder="Type your message..." value={inputValue} onChange={setInputValue} type="text" size="md" />
          <Button variant="primary" size="md" disabled={isSendDisabled} onClick={handleSend} rightIcon={<Icon name="chevron-right" size={16} />}>
            Send
          </Button>
        </Stack>
      </Box>
    </Card>
  );
}

import React, { useState, useEffect } from 'react';
import {
  Container,
  Stack,
  Heading,
  Text,
  Card,
  Box,
  Spinner,
} from '@ggui-ai/design/primitives';

interface Stock {
  symbol?: string;
  name?: string;
  price?: number;
  change?: number;
  changePercent?: number;
}

interface Props {
  /** Array of stocks with symbol, name, price, change, changePercent */
  stocks: Stock[];
  /** ISO timestamp of last price update */
  lastUpdated?: string;
}

export default function StockTickerDashboard({ stocks = [], lastUpdated }: Props) {
  const [displayedStocks, setDisplayedStocks] = useState<Stock[]>(stocks);
  const [connectionStatus, setConnectionStatus] = useState<'connecting' | 'connected' | 'disconnected'>('connecting');
  const [formattedTime, setFormattedTime] = useState<string>('');

  // Format last updated timestamp
  useEffect(() => {
    if (lastUpdated) {
      try {
        const date = new Date(lastUpdated);
        const timeStr = date.toLocaleTimeString('en-US', {
          hour: '2-digit',
          minute: '2-digit',
          hour12: true,
        });
        setFormattedTime(`Last Updated: ${timeStr}`);
      } catch {
        setFormattedTime('Last Updated: N/A');
      }
    }
  }, [lastUpdated]);

  // Listen for live data updates via ggui:agent-data stream
  useEffect(() => {
    // Only set to connecting if we don't have any stocks yet
    if (stocks.length === 0) {
      setConnectionStatus('connecting');
    }

    const handleAgentData = (event: Event) => {
      const customEvent = event as CustomEvent & { detail?: { stocks?: Stock[] } };
      if (customEvent.detail?.stocks && Array.isArray(customEvent.detail.stocks)) {
        setDisplayedStocks(customEvent.detail.stocks);
        setConnectionStatus('connected');
      }
    };

    // Register listener with type safety
    try {
      const eventTarget = typeof globalThis !== 'undefined' ? globalThis : (self as any);
      if (eventTarget && typeof eventTarget.addEventListener === 'function') {
        eventTarget.addEventListener('ggui:agent-data', handleAgentData as EventListener);

        return () => {
          eventTarget.removeEventListener('ggui:agent-data', handleAgentData as EventListener);
        };
      }
    } catch {
      // Event listener setup failed, continue with default behavior
    }

    return undefined;
  }, [stocks.length]);

  // Update displayed stocks from props
  useEffect(() => {
    if (stocks.length > 0) {
      setDisplayedStocks(stocks);
      setConnectionStatus('connected');
    }
  }, [stocks]);

  // Format price to 2 decimals
  const formatPrice = (price?: number): string => {
    if (typeof price !== 'number') return '—';
    return `$${price.toFixed(2)}`;
  };

  // Determine color and arrow based on change
  const getChangeDisplay = (change?: number, changePercent?: number) => {
    const isPositive = change !== undefined && change >= 0;
    const color = isPositive
      ? 'var(--ggui-color-success-500, #22c55e)'
      : 'var(--ggui-color-error-500, #ef4444)';
    const arrow = isPositive ? '▲' : '▼';

    const changeStr =
      typeof change === 'number' ? `${isPositive ? '+' : ''}${change.toFixed(2)}` : '—';
    const percentStr =
      typeof changePercent === 'number'
        ? `${isPositive ? '+' : ''}${changePercent.toFixed(2)}%`
        : '—';

    return { color, arrow, changeStr, percentStr, isPositive };
  };

  // Get card border/background color based on change
  const getCardStyle = (change?: number) => {
    const isPositive = change !== undefined && change >= 0;
    if (isPositive) {
      return {
        borderColor: 'var(--ggui-color-success-200, #bbf7d0)',
        backgroundColor: 'var(--ggui-color-success-50, #f0fdf4)',
      };
    }
    if (change !== undefined && change < 0) {
      return {
        borderColor: 'var(--ggui-color-error-200, #fecaca)',
        backgroundColor: 'var(--ggui-color-error-50, #fef2f2)',
      };
    }
    return {
      borderColor: 'var(--ggui-color-outline, #d4d4d8)',
      backgroundColor: 'var(--ggui-color-surface, #fafafa)',
    };
  };

  const emptyState = displayedStocks.length === 0 && connectionStatus === 'connected';
  const isLoading = connectionStatus === 'connecting';

  return (
    <Container maxWidth="xl" padding={24}>
      <Stack gap={24} direction="vertical">
        {/* Header: Title + Last Updated */}
        <Stack direction="horizontal" justify="between" align="center">
          <Stack direction="horizontal" gap={12} align="center">
            <Heading level={1} color="var(--ggui-color-onSurface, #18181b)">
              Market Watch
            </Heading>
            {/* Connection Status Indicator */}
            <Box
              style={{
                display: 'inline-flex',
                alignItems: 'center',
                gap: 'var(--ggui-spacing-2, 8px)',
              }}
            >
              <span
                style={{
                  display: 'inline-block',
                  width: '8px',
                  height: '8px',
                  borderRadius: '50%',
                  backgroundColor:
                    connectionStatus === 'connected'
                      ? 'var(--ggui-color-success-500, #22c55e)'
                      : connectionStatus === 'connecting'
                        ? 'var(--ggui-color-warning-500, #f59e0b)'
                        : 'var(--ggui-color-error-500, #ef4444)',
                }}
              />
              <Text
                variant="caption"
                color="var(--ggui-color-onSurfaceVariant, #52525b)"
                as="span"
              >
                {connectionStatus === 'connected' ? 'Live' : 'Connecting...'}
              </Text>
            </Box>
          </Stack>

          {/* Timestamp on right */}
          {formattedTime && (
            <Text variant="caption" color="var(--ggui-color-onSurfaceVariant, #52525b)">
              {formattedTime}
            </Text>
          )}
        </Stack>

        {/* Loading State */}
        {isLoading && (
          <Box
            style={{
              display: 'flex',
              justifyContent: 'center',
              alignItems: 'center',
              minHeight: '300px',
            }}
          >
            <Stack gap={12} align="center">
              <Spinner size={32} color="var(--ggui-color-primary-600, #0284c7)" />
              <Text variant="body" color="var(--ggui-color-onSurfaceVariant, #52525b)">
                Connecting to live market data...
              </Text>
            </Stack>
          </Box>
        )}

        {/* Empty State */}
        {emptyState && (
          <Box
            style={{
              display: 'flex',
              justifyContent: 'center',
              alignItems: 'center',
              minHeight: '300px',
              backgroundColor: 'var(--ggui-color-surfaceVariant, #f4f4f5)',
              borderRadius: 'var(--ggui-shape-radius-lg, 12px)',
              padding: 'var(--ggui-spacing-6, 24px)',
            }}
          >
            <Text variant="body" color="var(--ggui-color-onSurfaceVariant, #52525b)">
              No stocks to display
            </Text>
          </Box>
        )}

        {/* Stock Grid */}
        {!isLoading && !emptyState && (
          <Box
            style={{
              display: 'grid',
              gridTemplateColumns: 'repeat(auto-fit, minmax(300px, 1fr))',
              gap: 'var(--ggui-spacing-4, 16px)',
            }}
          >
            {displayedStocks.map((stock, index) => {
              const { symbol = 'N/A', name = 'Unknown', price, change, changePercent } = stock;
              const { color, arrow, changeStr, percentStr, isPositive } = getChangeDisplay(
                change,
                changePercent
              );
              const cardStyle = getCardStyle(change);

              return (
                <article
                  key={symbol === 'N/A' ? `stock-${index}` : symbol}
                  aria-label={`${symbol} ${name} trading at ${formatPrice(price)}, change ${changeStr} (${percentStr})`}
                >
                  <Card
                    padding={20}
                    shadow="sm"
                    border={true}
                    radius="lg"
                    style={{
                      borderColor: cardStyle.borderColor,
                      backgroundColor: cardStyle.backgroundColor,
                      borderWidth: '2px',
                      transition: 'all 200ms ease-out',
                    }}
                  >
                    <Stack gap={16} direction="vertical">
                      {/* Symbol + Name */}
                      <Stack gap={4} direction="vertical">
                        <Text
                          as="span"
                          size="xl"
                          weight="bold"
                          color="var(--ggui-color-onSurface, #18181b)"
                        >
                          {symbol}
                        </Text>
                        <Text
                          variant="body"
                          color="var(--ggui-color-onSurfaceVariant, #52525b)"
                          truncate
                        >
                          {name}
                        </Text>
                      </Stack>

                      {/* Price */}
                      <Text
                        size="lg"
                        weight="semibold"
                        color="var(--ggui-color-onSurface, #18181b)"
                      >
                        {formatPrice(price)}
                      </Text>

                      {/* Change + Percentage with Arrow */}
                      <Stack gap={8} direction="horizontal" align="center">
                        <span
                          style={{
                            fontSize: 'var(--ggui-font-size-sm, 14px)',
                            color: color,
                            fontWeight: '600',
                            display: 'inline-block',
                          }}
                          aria-label={isPositive ? 'Price up' : 'Price down'}
                        >
                          {arrow}
                        </span>
                        <Text size="sm" weight="semibold" color={color} as="span">
                          {changeStr}
                        </Text>
                        <Text size="sm" weight="semibold" color={color} as="span">
                          ({percentStr})
                        </Text>
                      </Stack>
                    </Stack>
                  </Card>
                </article>
              );
            })}
          </Box>
        )}
      </Stack>
    </Container>
  );
}

import React, { useState, useMemo } from 'react';
import { Container, Card, Stack, Box, Heading, Text, Input, Select, Toggle, Button, Divider, Spacer } from '@ggui-ai/design/primitives';

interface Props {
  initialProfile?: { name?: string; email?: string; avatar?: string; role?: string; emailNotifications?: boolean; theme?: string };
  avatarOptions: string[];
  roleOptions: string[];
  onComplete?: (profileData: { name: string; email: string; avatar: string; role: string; emailNotifications: boolean; theme: string }) => void;
}

interface FormData {
  name: string;
  email: string;
  avatar: string;
  role: string;
  emailNotifications: boolean;
  theme: string;
}

interface Errors {
  name: string | null;
  email: string | null;
}

export default function OnboardingWizard(props: Props) {
  const { initialProfile = {}, avatarOptions, roleOptions, onComplete = () => {} } = props;
  const [currentStep, setCurrentStep] = useState(1);
  const [formData, setFormData] = useState<FormData>({
    name: initialProfile.name || '',
    email: initialProfile.email || '',
    avatar: initialProfile.avatar || avatarOptions[0] || '👤',
    role: initialProfile.role || '',
    emailNotifications: initialProfile.emailNotifications !== false,
    theme: initialProfile.theme || 'light',
  });
  const [errors, setErrors] = useState<Errors>({ name: null, email: null });

  const isValidEmail = (email: string): boolean => {
    return /^[^\s@]+@[^\s@]+\.[^\s@]+$/.test(email);
  };

  const validateStep1 = (): boolean => {
    const newErrors: Errors = { name: null, email: null };
    let isValid = true;
    if (!formData.name.trim()) {
      newErrors.name = 'Name is required';
      isValid = false;
    }
    if (!formData.email.trim()) {
      newErrors.email = 'Email is required';
      isValid = false;
    } else if (!isValidEmail(formData.email)) {
      newErrors.email = 'Please enter a valid email address';
      isValid = false;
    }
    setErrors(newErrors);
    return isValid;
  };

  const isStep1Valid = useMemo(() => {
    return formData.name.trim() !== '' && formData.email.trim() !== '' && isValidEmail(formData.email);
  }, [formData.name, formData.email]);

  const handleNext = () => {
    if (currentStep === 1 && !validateStep1()) return;
    if (currentStep < 3) {
      setCurrentStep(currentStep + 1);
      setErrors({ name: null, email: null });
    }
  };

  const handleBack = () => {
    if (currentStep > 1) {
      setCurrentStep(currentStep - 1);
      setErrors({ name: null, email: null });
    }
  };

  const handleComplete = () => {
    onComplete(formData);
  };

  const handleNameChange = (value: string) => {
    setFormData((prev) => ({ ...prev, name: value }));
    if (errors.name) setErrors((prev) => ({ ...prev, name: null }));
  };

  const handleEmailChange = (value: string) => {
    setFormData((prev) => ({ ...prev, email: value }));
    if (errors.email) setErrors((prev) => ({ ...prev, email: null }));
  };

  const handleAvatarSelect = (avatar: string) => {
    setFormData((prev) => ({ ...prev, avatar }));
  };

  const handleRoleChange = (value: string) => {
    setFormData((prev) => ({ ...prev, role: value }));
  };

  const handleNotificationsChange = (checked: boolean) => {
    setFormData((prev) => ({ ...prev, emailNotifications: checked }));
  };

  const handleThemeChange = (checked: boolean) => {
    setFormData((prev) => ({ ...prev, theme: checked ? 'dark' : 'light' }));
  };

  const progressPercent = (currentStep / 3) * 100;

  return (
    <Container maxWidth="md" padding={24} center={true}>
      <Box background="var(--ggui-color-primary-50, #f0f9ff)" padding={16} borderRadius={8}>
        <Stack direction="vertical" gap={12} align="center">
          <Heading level={3} align="center">Step {currentStep} of 3</Heading>
          <div style={{ width: '100%', height: '4px', backgroundColor: 'var(--ggui-color-neutral-200, #e5e7eb)', borderRadius: 'var(--ggui-shape-radius-sm, 4px)', overflow: 'hidden' }}>
            <div style={{ height: '100%', width: `${progressPercent}%`, backgroundColor: 'var(--ggui-color-primary-600, #0284c7)', transition: 'width 300ms ease-out' }} />
          </div>
        </Stack>
      </Box>

      <Spacer size={24} />

      <Card shadow="md" padding={32} radius="lg" border={true}>
        <Stack direction="vertical" gap={24}>
          {currentStep === 1 && (
            <>
              <Heading level={2}>Profile Setup</Heading>
              <Stack direction="vertical" gap={16}>
                <Input label="Name" value={formData.name} onChange={handleNameChange} placeholder="John Doe" required={true} error={errors.name || undefined} />
                <Input label="Email" type="email" value={formData.email} onChange={handleEmailChange} placeholder="john@example.com" required={true} error={errors.email || undefined} />
              </Stack>
              <Divider margin={16} />
              <Stack direction="vertical" gap={12}>
                <Text variant="label">Choose Avatar</Text>
                <div role="group" aria-label="Avatar selection" style={{ display: 'flex', flexDirection: 'row', gap: 'var(--ggui-spacing-2, 12px)', alignItems: 'center', justifyContent: 'center', flexWrap: 'wrap' }}>
                  {avatarOptions.map((avatar) => (
                    <button key={avatar} onClick={() => handleAvatarSelect(avatar)} style={{ background: 'none', border: 'none', padding: 0, cursor: 'pointer', fontSize: '32px', opacity: formData.avatar === avatar ? 1 : 0.6, transform: formData.avatar === avatar ? 'scale(1.2)' : 'scale(1)', transition: 'all 200ms ease-out' }} aria-pressed={formData.avatar === avatar} aria-label={`Select avatar ${avatar}`} type="button">
                      {avatar}
                    </button>
                  ))}
                </div>
              </Stack>
            </>
          )}

          {currentStep === 2 && (
            <>
              <Heading level={2}>Preferences</Heading>
              <Stack direction="vertical" gap={20}>
                <Select label="Role" value={formData.role} onChange={handleRoleChange} options={roleOptions.map((role) => ({ value: role, label: role }))} placeholder="Select your role" />
                <Divider margin={16} />
                <div>
                  <Toggle label="Email Notifications" checked={formData.emailNotifications} onChange={handleNotificationsChange} size="md" />
                  <Text variant="caption" color="var(--ggui-color-neutral-500, #6b7280)" style={{ display: 'block', marginTop: 'var(--ggui-spacing-2, 8px)' }}>
                    Receive email updates about your account
                  </Text>
                </div>
                <Divider margin={16} />
                <div>
                  <Toggle label="Dark Theme" checked={formData.theme === 'dark'} onChange={handleThemeChange} size="md" />
                  <Text variant="caption" color="var(--ggui-color-neutral-500, #6b7280)" style={{ display: 'block', marginTop: 'var(--ggui-spacing-2, 8px)' }}>
                    Use dark mode for the interface
                  </Text>
                </div>
              </Stack>
            </>
          )}

          {currentStep === 3 && (
            <>
              <Heading level={2}>Review Your Information</Heading>
              <Divider margin={16} />
              <Stack direction="vertical" gap={20}>
                <Stack direction="vertical" gap={12}>
                  <Heading level={4}>Profile</Heading>
                  <Stack direction="vertical" gap={8}>
                    <Stack direction="horizontal" gap={16} justify="between">
                      <Text variant="label" color="var(--ggui-color-neutral-500, #6b7280)">Name</Text>
                      <Text variant="body">{formData.name}</Text>
                    </Stack>
                    <Stack direction="horizontal" gap={16} justify="between">
                      <Text variant="label" color="var(--ggui-color-neutral-500, #6b7280)">Email</Text>
                      <Text variant="body">{formData.email}</Text>
                    </Stack>
                    <Stack direction="horizontal" gap={16} justify="between" align="center">
                      <Text variant="label" color="var(--ggui-color-neutral-500, #6b7280)">Avatar</Text>
                      <span style={{ fontSize: '24px', lineHeight: '1' }}>{formData.avatar}</span>
                    </Stack>
                  </Stack>
                </Stack>
                <Divider margin={16} />
                <Stack direction="vertical" gap={12}>
                  <Heading level={4}>Preferences</Heading>
                  <Stack direction="vertical" gap={8}>
                    <Stack direction="horizontal" gap={16} justify="between">
                      <Text variant="label" color="var(--ggui-color-neutral-500, #6b7280)">Role</Text>
                      <Text variant="body">{formData.role || 'Not specified'}</Text>
                    </Stack>
                    <Stack direction="horizontal" gap={16} justify="between">
                      <Text variant="label" color="var(--ggui-color-neutral-500, #6b7280)">Notifications</Text>
                      <Text variant="body">{formData.emailNotifications ? 'Enabled' : 'Disabled'}</Text>
                    </Stack>
                    <Stack direction="horizontal" gap={16} justify="between">
                      <Text variant="label" color="var(--ggui-color-neutral-500, #6b7280)">Theme</Text>
                      <Text variant="body">{formData.theme === 'dark' ? 'Dark' : 'Light'}</Text>
                    </Stack>
                  </Stack>
                </Stack>
              </Stack>
            </>
          )}

          <Divider margin={16} />

          <Stack direction="horizontal" gap={8} justify="between" align="center">
            <Button variant="ghost" onClick={handleBack} disabled={currentStep === 1}>
              Go Back
            </Button>
            <Stack direction="horizontal" gap={8}>
              {currentStep < 3 && (
                <Button variant={isStep1Valid ? 'primary' : 'secondary'} onClick={handleNext} disabled={currentStep === 1 && !isStep1Valid}>
                  Next Step
                </Button>
              )}
              {currentStep === 3 && (
                <Button variant="primary" onClick={handleComplete}>
                  Complete Setup
                </Button>
              )}
            </Stack>
          </Stack>
        </Stack>
      </Card>
    </Container>
  );
}

import React from 'react';
