                <Text
                  variant="caption"
                  color="var(--ggui-color-onSurfaceVariant, #52525b)"
                  align="center"
                >
                  {item.low !== undefined ? `${item.low}°` : '—'}
                </Text>
              </Stack>
            ))}
          </Stack>
        </Box>
      </Box>
    </Card>
  );
}

import React, { useState } from 'react';
import {
  Container, Card, Stack, Box, Text, Heading,
  Button, Input, TextArea, Checkbox, RadioGroup,
  Progress, Alert, Divider, Badge, MotionKeyframes,
} from '@ggui-ai/design/primitives';

interface Props {
  featureOptions: string[];
  satisfactionLabels: string[];
  onSubmit?: (answers: SurveyAnswers) => void;
}

interface SurveyAnswers {
  name: string;
  email: string;
  satisfaction: string;
  features: string[];
  comments: string;
}

const TOTAL_STEPS = 4;
const MAX_COMMENTS = 500;

function isValidEmail(email: string): boolean {
  return /^[^\s@]+@[^\s@]+\.[^\s@]+$/.test(email);
}

export default function GeneratedComponent(props: Props) {
  const {
    featureOptions = ['Dashboard Analytics','Team Collaboration','API Integrations','Mobile App','Custom Reports','Automated Workflows'],
    satisfactionLabels = ['Very Unsatisfied','Unsatisfied','Neutral','Satisfied','Very Satisfied'],
    onSubmit,
  } = props;

  const [currentStep, setCurrentStep] = useState(1);
  const [isSubmitting, setIsSubmitting] = useState(false);
  const [submitStatus, setSubmitStatus] = useState<'idle' | 'success' | 'error'>('idle');
  const [name, setName] = useState('');
  const [email, setEmail] = useState('');
  const [nameError, setNameError] = useState('');
  const [emailError, setEmailError] = useState('');
  const [nameBlurred, setNameBlurred] = useState(false);
  const [emailBlurred, setEmailBlurred] = useState(false);
  const [satisfaction, setSatisfaction] = useState('');
  const [selectedFeatures, setSelectedFeatures] = useState<string[]>([]);
  const [comments, setComments] = useState('');

  const satisfactionOptions = satisfactionLabels.map((lbl, i) => ({
    value: String(i + 1),
    label: `${i + 1} — ${lbl}`,
  }));

  const checkName = (v: string) => (!v.trim() ? 'Name is required.' : '');
  const checkEmail = (v: string) => {
    if (!v.trim()) return 'Email is required.';
    if (!isValidEmail(v)) return 'Please enter a valid email address.';
    return '';
  };

  const step1Valid = !checkName(name) && !checkEmail(email);
  const step2Valid = satisfaction !== '';
  const step4Valid = comments.length <= MAX_COMMENTS;

  const onNameChange = (v: string) => { setName(v); if (nameBlurred) setNameError(checkName(v)); };
  const onEmailChange = (v: string) => { setEmail(v); if (emailBlurred) setEmailError(checkEmail(v)); };
  const onNameBlur = () => { setNameBlurred(true); setNameError(checkName(name)); };
  const onEmailBlur = () => { setEmailBlurred(true); setEmailError(checkEmail(email)); };

  const toggleFeature = (feature: string, checked: boolean) =>
    setSelectedFeatures(prev => checked ? [...prev, feature] : prev.filter(f => f !== feature));

  const goNext = () => {
    if (currentStep === 1) {
      const ne = checkName(name); const ee = checkEmail(email);
      setNameError(ne); setEmailError(ee);
      setNameBlurred(true); setEmailBlurred(true);
      if (ne || ee) return;
    }
    setCurrentStep(s => Math.min(s + 1, TOTAL_STEPS + 1));
  };
  const goBack = () => setCurrentStep(s => Math.max(s - 1, 1));

  const handleSubmit = async () => {
    setIsSubmitting(true); setSubmitStatus('idle');
    const answers: SurveyAnswers = { name, email, satisfaction, features: selectedFeatures, comments };
    try { await onSubmit?.(answers); setSubmitStatus('success'); }
    catch { setSubmitStatus('error'); }
    finally { setIsSubmitting(false); }
  };

  const progressValue = Math.round(((currentStep - 1) / TOTAL_STEPS) * 100);
  const isReview = currentStep === TOTAL_STEPS + 1;

  const ratingLabel = () => {
    if (!satisfaction) return '—';
    const idx = parseInt(satisfaction, 10) - 1;
    return satisfactionLabels[idx] ? `${satisfaction} — ${satisfactionLabels[idx]}` : satisfaction;
  };

  const dotStyle = (step: number): React.CSSProperties => {
    const active = step === currentStep, done = step < currentStep;
    return {
      width: 32, height: 32, borderRadius: '50%',
      display: 'flex', alignItems: 'center', justifyContent: 'center',
      backgroundColor: done ? 'var(--ggui-color-success-500, #22c55e)'
        : active ? 'var(--ggui-color-primary-600, #0284c7)'
        : 'var(--ggui-color-neutral-200, #e5e7eb)',
      color: active || done ? '#ffffff' : 'var(--ggui-color-neutral-500, #6b7280)',
      fontSize: 'var(--ggui-font-size-xs, 12px)',
      fontWeight: 'var(--ggui-font-weight-semibold, 600)',
      transition: 'background-color 200ms ease-in-out',
      flexShrink: 0,
    };
  };

  const reviewBox = { paddingX: 16, paddingY: 12, background: 'var(--ggui-color-surfaceVariant, #f4f4f5)', borderRadius: 8 };

  return (
    <Container maxWidth="sm" padding={16}>
      <MotionKeyframes />
      <Stack gap={24}>

        {/* Header */}
        <Box paddingX={24} paddingY={20} background="var(--ggui-color-primary-50, #f0f9ff)" borderRadius={12}>
          <Stack gap={4}>
            <Heading level={2} color="var(--ggui-color-primary-900, #0c4a6e)" align="center">Survey</Heading>
            <Text variant="bodySmall" align="center" color="var(--ggui-color-primary-700, #0369a1)">
              {isReview ? 'Review your answers before submitting' : `Step ${currentStep} of ${TOTAL_STEPS}`}
            </Text>
          </Stack>
        </Box>

        {/* Progress */}
        {!isReview && (
          <Stack gap={8}>
            <Stack direction="horizontal" justify="between" align="center">
              <Text variant="label" color="var(--ggui-color-onSurfaceVariant, #52525b)">Progress</Text>
              <Text variant="caption" color="var(--ggui-color-primary-600, #0284c7)">{progressValue}%</Text>
            </Stack>
            <Progress value={progressValue} max={100} size="md" variant="default" />
          </Stack>
        )}

        {/* Step dots */}
        {!isReview && (
          <Stack direction="horizontal" justify="center" gap={8}>
            {Array.from({ length: TOTAL_STEPS }, (_, i) => {
              const s = i + 1, done = s < currentStep;
              return (
                <div key={s} style={dotStyle(s)}
                  aria-label={`Step ${s}${done ? ' completed' : s === currentStep ? ' current' : ''}`}
                  aria-current={s === currentStep ? 'step' : undefined}>
                  {done ? '✓' : s}
                </div>
              );
            })}
          </Stack>
        )}

        {/* Main card */}
        <Card shadow="md" padding={28} radius="lg">
          <Stack gap={24}>

            {/* Step 1: Personal info */}
            {currentStep === 1 && (
              <Stack gap={20}>
                <Stack gap={4}>
                  <Heading level={4} color="var(--ggui-color-onSurface, #18181b)">Tell us about yourself</Heading>
                  <Text variant="bodySmall" color="var(--ggui-color-onSurfaceVariant, #52525b)">We'll use this to personalise your experience.</Text>
                </Stack>
                <Divider margin={0} />
                <Input label="Full Name" placeholder="Jane Smith" value={name} onChange={onNameChange} error={nameError || undefined} required onBlur={onNameBlur} />
                <Input label="Email Address" type="email" placeholder="jane@example.com" value={email} onChange={onEmailChange} error={emailError || undefined} required onBlur={onEmailBlur} />
              </Stack>
            )}

            {/* Step 2: Satisfaction */}
            {currentStep === 2 && (
              <Stack gap={20}>
                <Stack gap={4}>
                  <Heading level={4} color="var(--ggui-color-onSurface, #18181b)">How satisfied are you?</Heading>
                  <Text variant="bodySmall" color="var(--ggui-color-onSurfaceVariant, #52525b)">Rate your overall satisfaction from 1 to {satisfactionLabels.length}.</Text>
                </Stack>
                <Divider margin={0} />
                <RadioGroup label="Satisfaction Rating" value={satisfaction} onChange={setSatisfaction} options={satisfactionOptions} direction="vertical" />
                {!satisfaction && (
                  <Text variant="caption" color="var(--ggui-color-onSurfaceVariant, #52525b)">Please select a rating to continue.</Text>
                )}
              </Stack>
            )}

            {/* Step 3: Features */}
            {currentStep === 3 && (
              <Stack gap={20}>
                <Stack gap={4}>
                  <Heading level={4} color="var(--ggui-color-onSurface, #18181b)">What features interest you?</Heading>
                  <Text variant="bodySmall" color="var(--ggui-color-onSurfaceVariant, #52525b)">Select all that apply. You may skip this step.</Text>
                </Stack>
                <Divider margin={0} />
                <div role="group" aria-label="Feature interests">
                  <Stack gap={12}>
                    {featureOptions.map(feature => (
                      <Checkbox key={feature} label={feature} checked={selectedFeatures.includes(feature)} onChange={checked => toggleFeature(feature, checked)} />
                    ))}
                  </Stack>
                </div>
                {selectedFeatures.length > 0 && (
                  <Box paddingX={12} paddingY={8} background="var(--ggui-color-primary-50, #f0f9ff)" borderRadius={8}>
                    <Text variant="caption" color="var(--ggui-color-primary-700, #0369a1)">
                      {selectedFeatures.length} feature{selectedFeatures.length !== 1 ? 's' : ''} selected
                    </Text>
                  </Box>
                )}
              </Stack>
            )}

            {/* Step 4: Comments */}
            {currentStep === 4 && (
              <Stack gap={20}>
                <Stack gap={4}>
                  <Heading level={4} color="var(--ggui-color-onSurface, #18181b)">Any additional comments?</Heading>
                  <Text variant="bodySmall" color="var(--ggui-color-onSurfaceVariant, #52525b)">This step is optional — share anything you'd like us to know.</Text>
                </Stack>
                <Divider margin={0} />
                <TextArea
                  label="Comments"
                  placeholder="Share your thoughts, suggestions, or feedback…"
                  value={comments}
                  onChange={setComments}
                  rows={5}
                  maxLength={MAX_COMMENTS}
                  showCount
                  helperText="Optional — maximum 500 characters."
                  error={comments.length > MAX_COMMENTS ? `Too long by ${comments.length - MAX_COMMENTS} character${comments.length - MAX_COMMENTS !== 1 ? 's' : ''}.` : undefined}
                />
              </Stack>
            )}

            {/* Review */}
            {isReview && (
              <Stack gap={20}>
                <Stack gap={4}>
                  <Heading level={4} color="var(--ggui-color-onSurface, #18181b)">Review your answers</Heading>
                  <Text variant="bodySmall" color="var(--ggui-color-onSurfaceVariant, #52525b)">Please confirm before submitting. Click Edit to make changes.</Text>
                </Stack>
                <Divider margin={0} />

                <Stack gap={8}>
                  <Stack direction="horizontal" justify="between" align="center">
                    <Text variant="overline" color="var(--ggui-color-primary-600, #0284c7)">Personal Info</Text>
                    <Button variant="ghost" size="xs" onClick={() => setCurrentStep(1)} aria-label="Edit personal info">Edit</Button>
                  </Stack>
                  <Box {...reviewBox}>
                    <Stack gap={8}>
                      <Stack direction="horizontal" gap={8}>
                        <Text variant="label" color="var(--ggui-color-onSurfaceVariant, #52525b)">Name:</Text>
                        <Text variant="body" color="var(--ggui-color-onSurface, #18181b)">{name}</Text>
                      </Stack>
                      <Stack direction="horizontal" gap={8}>
                        <Text variant="label" color="var(--ggui-color-onSurfaceVariant, #52525b)">Email:</Text>
                        <Text variant="body" color="var(--ggui-color-onSurface, #18181b)">{email}</Text>
                      </Stack>
                    </Stack>
                  </Box>
                </Stack>

                <Stack gap={8}>
                  <Stack direction="horizontal" justify="between" align="center">
                    <Text variant="overline" color="var(--ggui-color-primary-600, #0284c7)">Satisfaction</Text>
                    <Button variant="ghost" size="xs" onClick={() => setCurrentStep(2)} aria-label="Edit satisfaction rating">Edit</Button>
                  </Stack>
                  <Box {...reviewBox}>
                    <Text variant="body" color="var(--ggui-color-onSurface, #18181b)">{ratingLabel()}</Text>
                  </Box>
                </Stack>

                <Stack gap={8}>
                  <Stack direction="horizontal" justify="between" align="center">
                    <Text variant="overline" color="var(--ggui-color-primary-600, #0284c7)">Feature Interests</Text>
                    <Button variant="ghost" size="xs" onClick={() => setCurrentStep(3)} aria-label="Edit feature interests">Edit</Button>
                  </Stack>
                  <Box {...reviewBox}>
                    {selectedFeatures.length === 0
                      ? <Text variant="body" color="var(--ggui-color-onSurfaceVariant, #52525b)">None selected</Text>
                      : <Stack direction="horizontal" gap={8} wrap>
                          {selectedFeatures.map(f => <Badge key={f} variant="primary" size="md">{f}</Badge>)}
                        </Stack>
                    }
                  </Box>
                </Stack>

                <Stack gap={8}>
                  <Stack direction="horizontal" justify="between" align="center">
                    <Text variant="overline" color="var(--ggui-color-primary-600, #0284c7)">Comments</Text>
                    <Button variant="ghost" size="xs" onClick={() => setCurrentStep(4)} aria-label="Edit comments">Edit</Button>
                  </Stack>
                  <Box {...reviewBox}>
                    <Text variant="body" color={comments.trim() ? 'var(--ggui-color-onSurface, #18181b)' : 'var(--ggui-color-onSurfaceVariant, #52525b)'}>
                      {comments.trim() || 'No comments provided'}
                    </Text>
                  </Box>
                </Stack>

                {submitStatus === 'success' && (
                  <Alert variant="success" title="Survey submitted!">Thank you for your feedback. We appreciate your time.</Alert>
                )}
                {submitStatus === 'error' && (
                  <Alert variant="error" title="Submission failed">Something went wrong. Please try again.</Alert>
                )}
              </Stack>
            )}

          </Stack>
        </Card>

        {/* Navigation */}
        <Stack direction="horizontal" justify={currentStep > 1 ? 'between' : 'end'} gap={12}>
          {currentStep > 1 && (
            <Button variant="outline" size="md" onClick={goBack} disabled={isSubmitting} aria-label="Go back to previous step">← Back</Button>
          )}

          {!isReview && (
            <Button
              variant="primary" size="md" onClick={goNext}
              disabled={(currentStep === 1 && !step1Valid) || (currentStep === 2 && !step2Valid) || (currentStep === 4 && !step4Valid)}
              aria-label={currentStep < TOTAL_STEPS ? `Continue to step ${currentStep + 1}` : 'Review your answers'}
            >
              {currentStep === TOTAL_STEPS ? 'Review Answers →' : 'Next →'}
            </Button>
          )}

          {isReview && submitStatus !== 'success' && (
            <Button variant="primary" size="md" onClick={handleSubmit} loading={isSubmitting} disabled={isSubmitting} aria-label="Submit survey">
              Submit Survey
            </Button>
          )}

          {isReview && submitStatus === 'success' && (
            <Button variant="secondary" size="md" disabled aria-label="Survey submitted successfully">✓ Submitted</Button>
          )}
        </Stack>

        {!isReview && currentStep === 3 && (
          <Text variant="caption" align="center" color="var(--ggui-color-onSurfaceVariant, #52525b)">
            Step 3 is optional — you can proceed without selecting any features.
          </Text>
        )}

      </Stack>
    </Container>
  );
}

import React, { useState, useRef, useEffect, useCallback } from 'react';
import {
  Stack,
  Text,
  Heading,
  Button,
  Input,
  Badge,
  Avatar,
  Box,
  MotionKeyframes,
} from '@ggui-ai/design/primitives';

interface Message {
  sender?: string;
  text?: string;
  timestamp?: string;
}

interface Props {
  /** Chat window title */
  title: string;
  /** Current user name (for right-aligning own messages) */
  currentUser: string;
  /** Number of participants */
  participantCount?: number;
  /** Array of messages with sender name, text, and ISO timestamp */
  messages: Array<{ sender?: string; text?: string; timestamp?: string }>;
  /** Called when user sends a message. Payload: { text, timestamp } */
  onSendMessage?: (payload: { text: string; timestamp: string }) => void;
}

function formatTime(isoTimestamp?: string): string {
  if (!isoTimestamp) return '';
  try {
    return new Date(isoTimestamp).toLocaleTimeString([], { hour: '2-digit', minute: '2-digit' });
  } catch {
    return '';
  }
}

// Safe global event target for ggui:agent-data stream
const globalEventTarget: EventTarget | null =
  typeof globalThis !== 'undefined' && 'addEventListener' in globalThis
    ? (globalThis as unknown as EventTarget)
    : null;

export default function GeneratedComponent(props: Props) {
  const { title = 'Chat', currentUser = '', participantCount, messages = [], onSendMessage } = props;

  const [allMessages, setAllMessages] = useState<Message[]>(messages);
  const [inputValue, setInputValue] = useState<string>('');
  const messagesEndRef = useRef<HTMLDivElement>(null);

  useEffect(() => {
    messagesEndRef.current?.scrollIntoView({ behavior: 'smooth' });
  }, [allMessages]);

  // Stream Contract: listen for ggui:agent-data events
  useEffect(() => {
    if (!globalEventTarget) return;
    const handler = (event: Event) => {
      const e = event as CustomEvent;
      if (e.detail && typeof e.detail === 'object') {
        setAllMessages((prev) => [...prev, e.detail as Message]);
      }
    };
    globalEventTarget.addEventListener('ggui:agent-data', handler);
    return () => globalEventTarget.removeEventListener('ggui:agent-data', handler);
  }, []);

  useEffect(() => {
    setAllMessages(messages);
  }, [messages]);

  // Action Contract: sendMessage
  const handleSend = useCallback(() => {
    const trimmed = inputValue.trim();
    if (!trimmed) return;
    const timestamp = new Date().toISOString();
    setAllMessages((prev) => [...prev, { sender: currentUser, text: trimmed, timestamp }]);
    setInputValue('');
    onSendMessage?.({ text: trimmed, timestamp });
  }, [inputValue, currentUser, onSendMessage]);

  const handleInputKeyDown = useCallback(
    (e: React.KeyboardEvent<HTMLDivElement>) => {
      if (e.key === 'Enter' && !e.shiftKey) { e.preventDefault(); handleSend(); }
    },
    [handleSend]
  );

  const isSendDisabled = inputValue.trim().length === 0;

  return (
    <>
      <MotionKeyframes />
      <div
        style={{ display: 'flex', flexDirection: 'column', height: '100%', minHeight: '400px', maxHeight: '700px', backgroundColor: 'var(--ggui-color-surface, #fafafa)', border: '1px solid var(--ggui-color-outline, #d4d4d8)', borderRadius: 'var(--ggui-shape-radius-lg, 12px)', overflow: 'hidden', boxShadow: 'var(--ggui-shape-shadow-md, 0 4px 6px -1px rgba(0,0,0,0.1))' }}
        aria-label={`Chat: ${title}`}
      >
        {/* Header */}
        <header style={{ display: 'flex', alignItems: 'center', justifyContent: 'space-between', padding: 'var(--ggui-spacing-4, 16px)', backgroundColor: 'var(--ggui-color-primary-600, #0284c7)', flexShrink: 0 }}>
          <Heading level={5} color="var(--ggui-color-primary-50, #f0f9ff)">{title}</Heading>
          {participantCount !== undefined && (
            <Badge variant="info" size="md" pill>
              {participantCount} {participantCount === 1 ? 'participant' : 'participants'}
            </Badge>
          )}
        </header>

        {/* Message list */}
        <div role="log" aria-live="polite" aria-label="Message list" style={{ flex: 1, overflowY: 'auto', padding: 'var(--ggui-spacing-2, 8px) 0', display: 'flex', flexDirection: 'column' }}>
          {allMessages.length === 0 ? (
            <div style={{ flex: 1, display: 'flex', alignItems: 'center', justifyContent: 'center', padding: 'var(--ggui-spacing-8, 32px)' }}>
              <Text variant="bodySmall" color="var(--ggui-color-onSurfaceVariant, #52525b)" align="center">No messages yet. Start the conversation!</Text>
            </div>
          ) : (
            allMessages.map((msg, index) => {
              const isOwn = msg.sender === currentUser;
              const prevMsg = allMessages[index - 1];
              const showSender = !prevMsg || prevMsg.sender !== msg.sender;
              return (
                <Box key={`msg-${index}`} paddingX={16} paddingY={4} style={{ display: 'flex', flexDirection: 'column', alignItems: isOwn ? 'flex-end' : 'flex-start' }}>
                  {showSender && !isOwn && (
                    <Text variant="caption" color="var(--ggui-color-onSurfaceVariant, #52525b)" as="span" style={{ marginBottom: 'var(--ggui-spacing-1, 4px)', marginLeft: 'var(--ggui-spacing-8, 32px)' }}>
                      {msg.sender || 'Unknown'}
                    </Text>
                  )}
                  <Stack direction="horizontal" align="end" gap={6}>
                    {!isOwn && showSender ? (
                      <Avatar name={msg.sender || 'Unknown'} size="xs" shape="circle" />
                    ) : (
                      !isOwn && <Box style={{ width: 'var(--ggui-spacing-6, 24px)', flexShrink: 0 }} />
                    )}
                    <Box style={{ maxWidth: '70%' }}>
                      <div style={{ backgroundColor: isOwn ? 'var(--ggui-color-primary-600, #0284c7)' : 'var(--ggui-color-surfaceVariant, #f4f4f5)', color: isOwn ? 'var(--ggui-color-primary-50, #f0f9ff)' : 'var(--ggui-color-onSurface, #18181b)', padding: 'var(--ggui-spacing-2, 8px) var(--ggui-spacing-4, 16px)', borderRadius: isOwn ? 'var(--ggui-shape-radius-lg, 12px) var(--ggui-shape-radius-sm, 4px) var(--ggui-shape-radius-lg, 12px) var(--ggui-shape-radius-lg, 12px)' : 'var(--ggui-shape-radius-sm, 4px) var(--ggui-shape-radius-lg, 12px) var(--ggui-shape-radius-lg, 12px) var(--ggui-shape-radius-lg, 12px)', fontSize: 'var(--ggui-font-size-sm, 14px)', lineHeight: '1.5', wordBreak: 'break-word', boxShadow: 'var(--ggui-shape-shadow-sm, 0 1px 2px rgba(0,0,0,0.05))', transition: 'opacity 200ms ease-in-out' }}>
                        {msg.text || ''}
                      </div>
                      <Text variant="caption" color="var(--ggui-color-onSurfaceVariant, #52525b)" align={isOwn ? 'right' : 'left'} as="span" style={{ display: 'block', marginTop: 'var(--ggui-spacing-1, 4px)', paddingLeft: isOwn ? 0 : 'var(--ggui-spacing-1, 4px)', paddingRight: isOwn ? 'var(--ggui-spacing-1, 4px)' : 0 }}>
                        {formatTime(msg.timestamp)}
                      </Text>
                    </Box>
                  </Stack>
                </Box>
              );
            })
          )}
          <div ref={messagesEndRef} aria-hidden="true" />
        </div>

        {/* Compose area */}
        <div style={{ padding: 'var(--ggui-spacing-4, 16px)', borderTop: '1px solid var(--ggui-color-outline, #d4d4d8)', backgroundColor: 'var(--ggui-color-surface, #fafafa)', flexShrink: 0 }}>
          <Stack direction="horizontal" gap={8} align="end">
            <div style={{ flex: 1 }} onKeyDown={handleInputKeyDown} role="none">
              <Input label="Compose message" placeholder="Type a message… (Enter to send)" value={inputValue} onChange={setInputValue} />
            </div>
            <Button variant="primary" size="md" onClick={handleSend} disabled={isSendDisabled} aria-label="Send message">Send</Button>
          </Stack>
        </div>
      </div>
    </>
  );
}

import React, { useState } from 'react';
import {
  Card, Stack, Text, Heading, Button, Input, Select,
  Toggle, Box, Divider, Progress, MotionKeyframes
} from '@ggui-ai/design/primitives';

interface InitialProfile {
  name?: string;
  email?: string;
  avatar?: string;
  role?: string;
  emailNotifications?: boolean;
  theme?: string;
}

interface ProfileData {
  name: string;
  email: string;
  avatar: string;
  role: string;
  emailNotifications: boolean;
  theme: string;
}

interface Props {
  initialProfile?: InitialProfile;
  avatarOptions: string[];
  roleOptions: string[];
  onComplete?: (data: ProfileData) => void;
}

function isValidEmail(email: string): boolean {
  return /^[^\s@]+@[^\s@]+\.[^\s@]+$/.test(email);
}

function AvatarButton({
  emoji,
  selected,
  onSelect,
}: {
  emoji: string;
  selected: boolean;
  onSelect: () => void;
}) {
  return (
    <button
      type="button"
      onClick={onSelect}
      aria-label={`Select avatar ${emoji}`}
      aria-pressed={selected}
      style={{
        width: 56,
        height: 56,
        borderRadius: 'var(--ggui-shape-radius-lg, 12px)',
        border: selected
          ? '2px solid var(--ggui-color-primary-600, #0284c7)'
          : '2px solid var(--ggui-color-outline, #d4d4d8)',
        background: selected
          ? 'var(--ggui-color-primary-50, #f0f9ff)'
          : 'var(--ggui-color-surface, #fafafa)',
        fontSize: 28,
        cursor: 'pointer',
        display: 'flex',
        alignItems: 'center',
        justifyContent: 'center',
        transition: 'border-color 150ms ease, background 150ms ease, transform 150ms ease, box-shadow 150ms ease',
        outline: 'none',
        boxShadow: selected ? '0 0 0 3px var(--ggui-color-primary-200, #bae6fd)' : 'none',
        transform: selected ? 'scale(1.08)' : 'scale(1)',
      }}
      onFocus={(e) => {
        e.currentTarget.style.outline = '2px solid var(--ggui-color-primary-600, #0284c7)';
        e.currentTarget.style.outlineOffset = '2px';
      }}
      onBlur={(e) => {
        e.currentTarget.style.outline = 'none';
      }}
    >
      {emoji}
    </button>
  );
}

function ThemeButton({
  value,
  selected,
  onSelect,
}: {
  value: 'light' | 'dark';
  selected: boolean;
  onSelect: () => void;
}) {
  return (
    <button
      type="button"
      onClick={onSelect}
      aria-pressed={selected}
      aria-label={value === 'light' ? 'Light theme' : 'Dark theme'}
      style={{
        flex: 1,
        padding: 'var(--ggui-spacing-4, 16px)',
        borderRadius: 'var(--ggui-shape-radius-md, 8px)',
        border: selected
          ? '2px solid var(--ggui-color-primary-600, #0284c7)'
          : '2px solid var(--ggui-color-outline, #d4d4d8)',
        background: selected
          ? 'var(--ggui-color-primary-50, #f0f9ff)'
          : 'var(--ggui-color-surface, #fafafa)',
        cursor: 'pointer',
        transition: 'border-color 150ms ease, background 150ms ease, box-shadow 150ms ease',
        outline: 'none',
        display: 'flex',
        alignItems: 'center',
        justifyContent: 'center',
        gap: 'var(--ggui-spacing-2, 8px)',
      }}
      onFocus={(e) => {
        e.currentTarget.style.boxShadow = '0 0 0 3px var(--ggui-color-primary-200, #bae6fd)';
      }}
      onBlur={(e) => {
        e.currentTarget.style.boxShadow = 'none';
      }}
    >
      <span style={{ fontSize: 20 }} aria-hidden="true">
        {value === 'light' ? '☀️' : '🌙'}
      </span>
      <Text
        variant="label"
        color={selected ? 'var(--ggui-color-primary-700, #0369a1)' : 'var(--ggui-color-onSurface, #18181b)'}
        as="span"
      >
        {value === 'light' ? 'Light' : 'Dark'}
      </Text>
    </button>
  );
}

export default function GeneratedComponent(props: Props) {
  const { initialProfile = {}, avatarOptions, roleOptions, onComplete } = props;

  const [step, setStep] = useState<number>(1);
  const [animKey, setAnimKey] = useState<number>(0);

  const [name, setName] = useState<string>(initialProfile.name ?? '');
  const [email, setEmail] = useState<string>(initialProfile.email ?? '');
  const [avatar, setAvatar] = useState<string>(
    initialProfile.avatar ?? (avatarOptions[0] ?? '')
  );
  const [nameError, setNameError] = useState<string>('');
  const [emailError, setEmailError] = useState<string>('');

  const [role, setRole] = useState<string>(initialProfile.role ?? '');
  const [emailNotifications, setEmailNotifications] = useState<boolean>(
    initialProfile.emailNotifications ?? true
  );
  const [theme, setTheme] = useState<string>(initialProfile.theme ?? 'light');

  const TOTAL = 3;
  const LABELS = ['Profile Setup', 'Preferences', 'Review & Confirm'];
  const progressValue = step === 1 ? 33 : step === 2 ? 66 : 100;

  function step1Valid(): boolean {
    return name.trim().length > 0 && isValidEmail(email);
  }

  function step2Valid(): boolean {
    return role.trim().length > 0;
  }

  function validateStep1(): boolean {
    let ok = true;
    if (!name.trim()) { setNameError('Name is required'); ok = false; }
    else { setNameError(''); }
    if (!email.trim()) { setEmailError('Email is required'); ok = false; }
    else if (!isValidEmail(email)) { setEmailError('Please enter a valid email address'); ok = false; }
    else { setEmailError(''); }
    return ok;
  }

  function goNext() {
    if (step === 1 && !validateStep1()) return;
    setAnimKey(k => k + 1);
    setStep(s => s + 1);
  }

  function goBack() {
    setAnimKey(k => k + 1);
    setStep(s => s - 1);
  }

  function handleComplete() {
    if (onComplete) {
      onComplete({ name, email, avatar, role, emailNotifications, theme });
    }
  }

  const roleSelectOptions = roleOptions.map(r => ({ value: r, label: r }));

  const reviewRows = [
    { label: 'Avatar', value: avatar },
    { label: 'Role', value: role },
    { label: 'Email Notifications', value: emailNotifications ? 'Enabled' : 'Disabled' },
    { label: 'Theme', value: theme === 'dark' ? 'Dark' : 'Light' },
  ];

  return (
    <Box padding={24} background="var(--ggui-color-surface, #fafafa)">
      <MotionKeyframes />
      <div style={{ maxWidth: 560, margin: '0 auto' }}>

        {/* Header */}
        <Stack gap={8} align="center">
          <Heading level={2} align="center" color="var(--ggui-color-onSurface, #18181b)">
            Account Setup
          </Heading>
          <Text variant="body" align="center" color="var(--ggui-color-onSurfaceVariant, #52525b)">
            Step {step} of {TOTAL} — {LABELS[step - 1]}
          </Text>
        </Stack>

        {/* Step indicator */}
        <Box paddingY={24}>
          <Stack gap={12}>
            <Progress value={progressValue} max={100} size="sm" />
            <Stack direction="horizontal" justify="between" align="center">
              {LABELS.map((label, idx) => {
                const num = idx + 1;
                const active = num === step;
                const done = num < step;
                return (
                  <Stack key={num} direction="vertical" gap={4} align="center">
                    <div
                      role="img"
                      aria-label={`Step ${num}: ${label}${done ? ' (completed)' : active ? ' (current)' : ''}`}
                      style={{
                        width: 32,
                        height: 32,
                        borderRadius: 'var(--ggui-shape-radius-full, 9999px)',
                        background: done
                          ? 'var(--ggui-color-success-500, #22c55e)'
                          : active
                          ? 'var(--ggui-color-primary-600, #0284c7)'
                          : 'var(--ggui-color-outline, #d4d4d8)',
                        display: 'flex',
                        alignItems: 'center',
                        justifyContent: 'center',
                        transition: 'background 200ms ease-in-out',
                      }}
                    >
                      {done ? (
                        <svg width="14" height="14" viewBox="0 0 14 14" fill="none" aria-hidden="true">
                          <path d="M2.5 7l3 3L11.5 4" stroke="white" strokeWidth="2" strokeLinecap="round" strokeLinejoin="round" />
                        </svg>
                      ) : (
                        <Text variant="caption" weight="semibold" color="white" as="span">
                          {num}
                        </Text>
                      )}
                    </div>
                    <Text
                      variant="caption"
                      weight={active ? 'medium' : 'normal'}
                      color={active ? 'var(--ggui-color-primary-600, #0284c7)' : 'var(--ggui-color-onSurfaceVariant, #52525b)'}
                    >
                      {label}
                    </Text>
                  </Stack>
                );
              })}
            </Stack>
          </Stack>
        </Box>

        {/* Animated step panel */}
        <div key={animKey} style={{ animation: 'ggui-fadeIn 200ms ease-out both' }}>
          <Card shadow="md" padding={32} radius="lg">

            {/* ─── Step 1 ─── */}
            {step === 1 && (
              <Stack gap={24}>
                <Stack gap={4}>
                  <Heading level={4} color="var(--ggui-color-onSurface, #18181b)">
                    Profile Setup
                  </Heading>
                  <Text variant="bodySmall" color="var(--ggui-color-onSurfaceVariant, #52525b)">
                    Tell us a bit about yourself to get started.
                  </Text>
                </Stack>

                <Stack gap={4}>
                  <Input label="Full Name" placeholder="Enter your full name" value={name} onChange={(v) => { setName(v); if (v.trim()) setNameError(''); }} required error={nameError || undefined} />
                </Stack>

                <Stack gap={4}>
                  <Input label="Email Address" type="email" placeholder="you@example.com" value={email} onChange={(v) => { setEmail(v); if (!v.trim() || isValidEmail(v)) setEmailError(''); }} required error={emailError || undefined} />
                </Stack>

                <Stack gap={8}>
                  <Text variant="label" color="var(--ggui-color-neutral-700, #374151)">
                    Choose Your Avatar
                  </Text>
                  <Stack direction="horizontal" gap={12} wrap>
                    {avatarOptions.map((emoji) => (
                      <AvatarButton
                        key={emoji}
                        emoji={emoji}
                        selected={avatar === emoji}
                        onSelect={() => setAvatar(emoji)}
                      />
                    ))}
                  </Stack>
                </Stack>
              </Stack>
            )}

            {/* ─── Step 2 ─── */}
            {step === 2 && (
              <Stack gap={24}>
                <Stack gap={4}>
                  <Heading level={4} color="var(--ggui-color-onSurface, #18181b)">
                    Preferences
                  </Heading>
                  <Text variant="bodySmall" color="var(--ggui-color-onSurfaceVariant, #52525b)">
                    Customize your experience.
                  </Text>
                </Stack>

                <Select
                  label="Your Role"
                  value={role}
                  onChange={setRole}
                  options={roleSelectOptions}
                  placeholder="Select your role"
                  required
                />

                <Divider margin={0} />

                <Stack gap={8}>
                  <Toggle
                    label="Email Notifications"
                    checked={emailNotifications}
                    onChange={setEmailNotifications}
                  />
                  <Text variant="caption" color="var(--ggui-color-onSurfaceVariant, #52525b)">
                    Receive product updates and news via email.
                  </Text>
                </Stack>

                <Divider margin={0} />

                <Stack gap={12}>
                  <Text variant="label" color="var(--ggui-color-neutral-700, #374151)">
                    Theme Preference
                  </Text>
                  <Stack direction="horizontal" gap={12}>
                    <ThemeButton value="light" selected={theme === 'light'} onSelect={() => setTheme('light')} />
                    <ThemeButton value="dark" selected={theme === 'dark'} onSelect={() => setTheme('dark')} />
                  </Stack>
                </Stack>
              </Stack>
            )}

            {/* ─── Step 3 ─── */}
            {step === 3 && (
              <Stack gap={24}>
                <Stack gap={4}>
                  <Heading level={4} color="var(--ggui-color-onSurface, #18181b)">
                    Review & Confirm
                  </Heading>
                  <Text variant="bodySmall" color="var(--ggui-color-onSurfaceVariant, #52525b)">
                    Check your selections before completing setup.
                  </Text>
                </Stack>

                <Box
                  background="var(--ggui-color-primary-50, #f0f9ff)"
                  borderRadius={12}
                  paddingX={20}
                  paddingY={20}
                >
                  <Stack direction="horizontal" gap={16} align="center">
                    <div
                      aria-label={`Selected avatar: ${avatar}`}
                      style={{
                        width: 64,
                        height: 64,
                        borderRadius: 'var(--ggui-shape-radius-full, 9999px)',
                        background: 'var(--ggui-color-primary-100, #e0f2fe)',
                        border: '2px solid var(--ggui-color-primary-200, #bae6fd)',
                        display: 'flex',
                        alignItems: 'center',
                        justifyContent: 'center',
                        fontSize: 36,
                        flexShrink: 0,
                      }}
                    >
                      {avatar}
                    </div>
                    <Stack gap={4}>
                      <Text variant="bodyLarge" weight="semibold" color="var(--ggui-color-onSurface, #18181b)">
                        {name}
                      </Text>
                      <Text variant="bodySmall" color="var(--ggui-color-onSurfaceVariant, #52525b)">
                        {email}
                      </Text>
                    </Stack>
                  </Stack>
                </Box>

                <Divider margin={0} />

                <Stack gap={0}>
                  {reviewRows.map((row, idx) => (
                    <div
                      key={row.label}
                      style={{
                        display: 'flex',
                        alignItems: 'center',
                        justifyContent: 'space-between',
                        padding: 'var(--ggui-spacing-4, 16px) 0',
                        borderBottom: idx < reviewRows.length - 1
                          ? '1px solid var(--ggui-color-outlineVariant, #e4e4e7)'
                          : 'none',
                      }}
                    >
                      <Text variant="label" color="var(--ggui-color-onSurfaceVariant, #52525b)">
                        {row.label}
                      </Text>
                      <Text variant="body" weight="medium" color="var(--ggui-color-onSurface, #18181b)">
                        {row.value}
                      </Text>
                    </div>
                  ))}
                </Stack>
              </Stack>
            )}

          </Card>
        </div>

        {/* Navigation */}
        <Box paddingY={20}>
          <Stack direction="horizontal" justify="between" align="center">
            <Button
              variant="ghost"
              onClick={goBack}
              disabled={step === 1}
              aria-label="Go back to previous step"
            >
              ← Back
            </Button>
            <Stack direction="horizontal" gap={8}>
              {step < TOTAL ? (
                <Button
                  variant="primary"
                  onClick={goNext}
                  disabled={step === 1 ? !step1Valid() : !step2Valid()}
                  aria-label={`Continue to step ${step + 1}: ${LABELS[step]}`}
                >
                  Next →
                </Button>
              ) : (
                <>
                  <Button variant="outline" onClick={goBack} aria-label="Go back to edit preferences">
                    Go Back
                  </Button>
                  <Button variant="primary" onClick={handleComplete} aria-label="Complete onboarding setup">
                    Complete Setup ✓
                  </Button>
                </>
              )}
            </Stack>
          </Stack>
        </Box>

      </div>
    </Box>
  );
}
